# Research-mode disciplines: the v8.22.0 anti-hallucination output-format
# rules (REFUSAL / PRECISION / CITATION). Injected into the system prompt
# by `_build_system_prompt` when the active project has `research_mode=True`
# — research-mode chats need refuse-on-empty + verbatim citations on every
# claim. Non-research project chats (codegen, drafting, anything that USES
# indexed content as input rather than reproducing it) do NOT receive this
# block; they only see the soft "memory is available" variant — those chats
# are allowed to combine retrieved facts with general knowledge.
#
# Topic A (retrieval discipline — query shape, search-first) lives in the
# `mempalace_query` per-tool description (admin → Tools settings) and fires
# for EVERY chat that has the tool, regardless of research_mode. This
# constant only carries Topic B (audit-grade output posture).
#
# These rules are NOT user-editable — they are Brain behavior toggled by
# the project's `research_mode` flag. The per-project `instructions` field
# is a purely additive layer for owner-supplied guidance and is appended
# AFTER this block when both are active. Editing `instructions` does not
# replace or shadow these disciplines.
# Research-mode disciplines, split into three admin-editable sections.
# These are the SEED values — copied into config.json on first boot so
# admins can edit them via General Settings → Tools. Runtime reads from
# engine._research_mode_disciplines (populated from server_config at
# startup, refreshed on POST /v1/research-mode/disciplines). The seeds
# stay as factory defaults for the UI's reset-per-section button.

# TOOL-AGNOSTIC by design: these disciplines are injected on EVERY grounding
# turn (memory, web, documents, context) — including a pure-web turn. They must
# NOT name a specific tool or its mechanics (mempalace/read_document/drawer/…),
# or the prose becomes a dangling anchor on a turn that doesn't use that tool —
# the root cause of the 2026-06 "model digs only in memory then gives up, never
# escalates to web" bug (memory note project_websearch_skip_root_cause). The
# refusal forbids FABRICATION, it does NOT tell the model to give up after empty
# retrieval. Keep these byte-identical to config.json → research_mode_disciplines;
# tests/test_websearch_escalation_gating.py guards the tool-agnostic property.
_RESEARCH_MODE_DISCIPLINE_REFUSAL_DEFAULT = (
    "**REFUSAL DISCIPLINE — never assert unproven facts**:\n"
    "State a fact only when it is backed by evidence you actually retrieved this "
    "turn (a source you read, a result you got back). Do NOT fill gaps with "
    "training-data knowledge, plausible guesses, or assumptions — for compliance, "
    "policy, factual or audit questions an unsupported claim is a fabrication "
    "hazard. If, after a genuine attempt to retrieve it, the information is not "
    "available, say so plainly — name what is missing and, where useful, suggest "
    "how the user could provide or locate it. A clear 'this could not be found' is "
    "always better than an invented answer."
)

_RESEARCH_MODE_DISCIPLINE_PRECISION_DEFAULT = (
    "**PRECISION DISCIPLINE — no plausible-sounding filler**:\n"
    "When the retrieved source does not give a concrete value (interval, "
    "frequency, threshold, count, deadline, length, duration), write `nicht "
    "spezifiziert` — never substitute a plausible default like 'regelmäßig', "
    "'häufig', 'sofort', 'kürzer', 'mindestens X Zeichen', 'alle 12 Monate', "
    "'mindestens jährlich'. If you use any qualifying adverb or comparative "
    "('regelmäßig', 'häufiger', 'kürzer', 'sofort', 'zeitnah', 'angemessen'), "
    "the very next characters must be a wörtliches Zitat (`> \"...\"`) from the "
    "retrieved text proving the source actually says that. No quote → drop the "
    "qualifier. Typical phrasing remembered from training data is NOT a source."
)

_RESEARCH_MODE_DISCIPLINE_CITATION_DEFAULT = (
    "**CITATION DISCIPLINE — per-claim, not per-block**:\n"
    "EVERY factual sentence and EVERY bullet point that came from a retrieved "
    "source must carry its OWN reference right after the claim, in the form "
    "[Quelle: <kurzer Quellenname> — \"<wörtliches Zitat 10-25 Wörter>\"]. One "
    "citation at the end of a 5-bullet list is INSUFFICIENT — the reader cannot "
    "tell which bullet came from which source, and uncited bullets are where "
    "paraphrase drift and fabrication slip in. Treat each bullet as an "
    "independent claim that must stand on its own with its own quote. A bullet "
    "with only a citation and no claim, or a claim with no citation, is not "
    "correct.\n"
    "If you cannot find a verbatim quote in the retrieved source that supports a "
    "specific claim — DELETE that claim. Do not write claims you cannot cite. A "
    "shorter, fully-cited answer is always preferable to a longer answer with "
    "uncited statements.\n"
    "The verbatim quote (10-25 words, copied EXACTLY from the retrieved text) is "
    "mandatory — it lets the user find and verify the statement in the original. "
    "Without a quote the citation is unverifiable.\n"
    "Source naming: use a short, recognisable source name — a document's "
    "filename (without any path or extracted-companion suffix) or, for a web "
    "source, its title or domain. Add a locator only when it is genuinely "
    "present in the retrieved text (e.g. `Page N`, `Slide N`, `Sheet \"Name\"`, "
    "or a section number the source itself prints). NEVER invent paragraph or "
    "section numbers — a locator you did not see in the text is a fabrication. "
    "If no clean locator exists, the verbatim quote alone is sufficient.\n"
    "Multiple sources for one claim → repeat the bracket: "
    "[Quelle: A — \"...\"] [Quelle: B — \"...\"]."
)

# Section keys + their factory defaults. Iteration order is the
# concatenation order in the prompt — refusal → precision → citation,
# matching the original DEFAULT_PROJECT_INSTRUCTIONS.
RESEARCH_MODE_DISCIPLINE_SECTIONS = ("refusal", "precision", "citation")
RESEARCH_MODE_DISCIPLINE_DEFAULTS = {
    "refusal":   _RESEARCH_MODE_DISCIPLINE_REFUSAL_DEFAULT,
    "precision": _RESEARCH_MODE_DISCIPLINE_PRECISION_DEFAULT,
    "citation":  _RESEARCH_MODE_DISCIPLINE_CITATION_DEFAULT,
}

# Runtime state populated by server.py at startup from
# config.json["research_mode_disciplines"]. Same {refusal, precision,
# citation} shape; empty strings mean "section omitted from prompt".
_research_mode_disciplines: dict[str, str] = {}


def get_research_mode_disciplines() -> dict[str, str]:
    """Effective research-mode disciplines, merged with seed defaults.
    Any section missing or empty in the runtime config falls back to the
    seed default. Returns a fresh dict every call so callers can mutate
    locally without touching state."""
    out: dict[str, str] = {}
    cfg = _research_mode_disciplines or {}
    for k in RESEARCH_MODE_DISCIPLINE_SECTIONS:
        v = cfg.get(k)
        if isinstance(v, str) and v.strip():
            out[k] = v
        else:
            out[k] = RESEARCH_MODE_DISCIPLINE_DEFAULTS[k]
    return out


def active_research_discipline_sections() -> list[str]:
    """The section KEYS (subset of refusal/precision/citation, in order) that
    render_research_mode_disciplines() would actually emit right now, honouring
    the per-section admin opt-out (a section explicitly saved as "" is skipped).
    Single source of truth shared with the renderer so the per-turn
    classification inspector can report exactly which disciplines were injected,
    not the static default set."""
    cfg = _research_mode_disciplines or {}
    out: list[str] = []
    for k in RESEARCH_MODE_DISCIPLINE_SECTIONS:
        if k in cfg:
            v = cfg[k]
            if not (isinstance(v, str) and v.strip()):
                continue  # admin opt-out
            out.append(k)
        else:
            out.append(k)  # missing → default text
    return out


def render_research_mode_disciplines() -> str:
    """Concatenate the three sections (refusal → precision → citation)
    into the prompt block that fires when research_mode is on. Sections
    with explicit empty-string in the config (admin cleared it) are
    skipped — admin opt-out per section, not just whole-block opt-out.
    """
    cfg = _research_mode_disciplines or {}
    parts: list[str] = []
    for k in RESEARCH_MODE_DISCIPLINE_SECTIONS:
        # An admin who explicitly saved "" wants that section gone.
        # Missing key → fall back to default.
        if k in cfg:
            v = cfg[k]
            if not (isinstance(v, str) and v.strip()):
                continue
            parts.append(v.strip())
        else:
            parts.append(RESEARCH_MODE_DISCIPLINE_DEFAULTS[k].strip())
    if not parts:
        return ""
    return "\n\n".join(parts)


# Back-compat alias — callers that still read DEFAULT_PROJECT_INSTRUCTIONS
# get the merged-with-defaults concatenation, same string they got before.
# Will be removed once external references (memory notes, comments) are
# updated.
def _default_project_instructions_compat() -> str:
    return render_research_mode_disciplines()
