def _review_anon_override(text: str, source: str) -> str | None:
    """Return a user-reviewed, pre-anonymised version of `text` if one exists.

    INVARIANT-CRITICAL (see handlers/data_review): this only ever returns a
    stored `anon_text` when ALL hold — a saved review exists for the current
    user, its status is 'anonymised', and its content hash matches `text`. In
    every other case it returns None and the caller falls back to today's
    behaviour exactly. It NEVER introduces anonymisation where the caller wasn't
    already going to anonymise; callers guard their own "should I anonymise at
    all" decision and only consult this for WHICH anonymised text to use.

    Matching is by content hash so a renamed/copied file still reuses its
    review. Best-effort; never raises.
    """
    if not text:
        return None
    try:
        uid = get_request_context().current_user_id or ""
    except Exception:
        uid = ""
    if not uid:
        return None
    try:
        from engine import doc_review
        from server_lib.db import DataReviewDB
        chash = doc_review.content_hash(text)
        row = DataReviewDB.get_by_hash(chash, uid, admin=False)
        if (row and row.get("status") == "anonymised"
                and row.get("anon_text")
                and row.get("content_hash") == chash):
            return row["anon_text"]
    except Exception as e:
        print(f"[data_review] anon override lookup failed: {e}", flush=True)
    return None


def _gdpr_anon_tool_text(text: str, source: str) -> str:
    """Pseudonymise text returned from a read-style tool, if the active
    session has a transparent-anonymisation mapping.

    Reads `get_request_context()._gdpr_mapping_id` (set by `tool_mcp._apply_context`
    on every sidecar tool-dispatch from the per-turn `tool_context.gdpr_mapping_id`).
    No-op when no mapping is active — returns text unchanged.

    Scans for PII findings, adds them to the mapping, returns pseudonymised
    text. The same mapping is also used by `StreamingDeanonymizer` on the
    assistant reply, so any token minted here is reversed before the user
    sees it.

    When findings are added, emits an `anonymise_read` synthetic tool-call
    pair on the session's live stream so the chat history shows what
    actually got pseudonymised mid-turn. Persisted with `synthetic=True`,
    so reload picks them up.

    Also runs the classification gate first — if content is classified
    above the per-level threshold AND the active model is non-local, the
    tool read is refused with ClassificationBlockedError before PII
    pseudonymisation runs.
    """
    if not text:
        return text
    # Classification gate — runs BEFORE pseudonymisation. Raises
    # ClassificationBlockedError when policy says block; tool dispatcher
    # turns the raise into a JSON tool-error the LLM sees verbatim.
    _classification_gate_tool_text(text, source)
    try:
        mapping_id = get_request_context()._gdpr_mapping_id or ""
    except Exception:
        mapping_id = ""
    if not mapping_id:
        return text
    try:
        import pseudonymizer as _ps
        mapping = _ps.get_mapping(mapping_id)
        if mapping is None:
            return text
        # Reviewed-anonymisation reuse: if the user has already reviewed +
        # anonymised THIS exact content (matched by hash), ship their approved
        # `anon_text` verbatim instead of a fresh scan. We merge the review's
        # saved de-anon entries into the active per-turn mapping so the reply
        # de-anonymiser can still reverse the tokens. Guarded so a non-reviewed
        # file behaves exactly as before (override returns None → fall through).
        _override = _review_anon_override(text, source)
        if _override is not None and _override != text:
            try:
                _row = None
                from server_lib.db import DataReviewDB as _DRB
                from engine import doc_review as _dr
                _uid = get_request_context().current_user_id or ""
                _row = _DRB.get_by_hash(_dr.content_hash(text), _uid, admin=False)
                _rmid = (_row or {}).get("anon_mapping_id") or ""
                if _rmid:
                    _rm = _ps.load_mapping(_rmid)
                    if _rm:
                        for _orig, _fake in _rm.forward.items():
                            if _fake not in mapping.reverse:
                                mapping.forward.setdefault(_orig, _fake)
                                mapping.reverse[_fake] = _orig
                                mapping.categories.setdefault(
                                    _orig, _rm.categories.get(_orig, "unknown"))
            except Exception as _e:
                print(f"[data_review] reuse merge failed: {_e}", flush=True)
            return _override
        cfg = _get_gdpr_scanner_config()
        findings = _pii_scan_text(text, cfg=cfg)
        if not findings:
            return text
        _tokens_before = len(mapping.forward)
        out = _ps.pseudonymize_text(text, findings, mapping=mapping,
                                    source=source or "tool_output")
        _tokens_added = len(mapping.forward) - _tokens_before
        # Per-rule_id breakdown for the chat-history row.
        _cats: dict[str, int] = {}
        for f in findings:
            rid = f.get("rule_id") or "unknown"
            _cats[rid] = _cats.get(rid, 0) + 1
        # Surface a synthetic anonymise_read row so the UI shows what
        # happened. Best-effort — never block the tool return.
        try:
            sid = get_request_context().current_session_id or ""
            if sid:
                from handlers.chat import emit_gdpr_tool_event_for_session
                _tuid = f"anon_read_{mapping_id[:8]}_{int(time.time()*1000) % 1_000_000}"
                emit_gdpr_tool_event_for_session(
                    sid,
                    kind="anonymise_read",
                    tool_use_id=_tuid,
                    args={"source": source or "tool_output"},
                    result={
                        "findings": len(findings),
                        "tokens_minted": _tokens_added,
                        "categories": _cats,
                        "source": source or "tool_output",
                        "mapping_id": mapping_id,
                    },
                    status="ok",
                    duration_ms=0,
                )
        except Exception:
            pass
        return out
    except Exception:
        # Fail-safe: never leak PII because of a scanner crash. On error,
        # caller surfaces an error; here we conservatively return the
        # original text (the only alternative — return nothing — would
        # silently hide content). The recovery-modal path in the worker
        # already covered the "fail-closed" stance for the user message.
        return text


def _route_to_node(tool_name: str, args: dict) -> str | None:
    """If args contain 'node', route to remote node via server API. Returns result string or None for local."""
    node = args.pop("node", None)
    if not node:
        return None
    try:
        import urllib.request
        body = json.dumps({"node": node, "tool": tool_name, "params": args}).encode("utf-8")
        req = urllib.request.Request(
            "http://127.0.0.1:8420/v1/nodes/execute",
            data=body,
            headers={"Content-Type": "application/json"},
            method="POST",
        )
        with urllib.request.urlopen(req, timeout=300) as resp:
            result = json.loads(resp.read().decode("utf-8"))
        if "error" in result:
            return _err(f"Node '{node}': {result['error']}")
        return _ok(result)
    except Exception as e:
        return _err(f"Node routing error: {e}")


