# --- Warmup Registry ---
#
# Per-model warmup state tracker. A background keeper daemon (in server.py)
# fires minimal prefill requests against local model endpoints so the first
# real user turn hits a warm KV cache and time-to-first-token is minimised.
# Each model's warmup is opt-in via models_config[id].warmup + warmup_ttl_seconds.
#
# State values: "idle" (never warmed), "warming", "warm", "failed", "skipped_cloud"

_warmup_state: dict[str, dict] = {}
_warmup_state_lock = threading.Lock()


# --- Provider Concurrency Queue ---
#
# Local LLM gateways (oMLX, cliproxyapi) typically cannot process multiple
# /chat/completions in parallel even when multiple models are loaded. We
# serialize per-provider via a semaphore + strict-FIFO waitlist so concurrent
# chats/delegates/warmups line up instead of fighting for the same GPU.
#
# Config (config.json → providers.<name>.max_concurrent):
#   0         (default)  unlimited — no queue
#   >=1                  cap at N simultaneous calls
#
# Tickets carry (provider, label, session_id, agent_id, user_id, model,
# enqueued_at). While a ticket waits, the queue emits queue_wait events via
# event_callback so the UI can show "waiting in queue, position 3 of 5".

_PROVIDER_QUEUE_TIMEOUT_DEFAULT = 300  # seconds


class _ProviderTicket:
    __slots__ = ("id", "provider", "label", "session_id", "agent_id",
                 "user_id", "model", "enqueued_at", "acquired_at",
                 "released_at", "event_callback", "cancel_token",
                 "_released", "_position", "_admin_cancelled",
                 "_admin_cancel_reason")

    def __init__(self, provider, label, session_id, agent_id, user_id, model,
                 event_callback=None, cancel_token=None):
        self.id = uuid.uuid4().hex[:12]
        self.provider = provider
        self.label = label
        self.session_id = session_id
        self.agent_id = agent_id
        self.user_id = user_id
        self.model = model
        self.enqueued_at = time.time()
        self.acquired_at = 0.0
        self.released_at = 0.0
        self.event_callback = event_callback
        self.cancel_token = cancel_token
        self._released = False
        self._position = 0  # last-emitted position (1-based); 0 = none yet
        self._admin_cancelled = False
        self._admin_cancel_reason = ""


class _ProviderQueueSlot:
    """Per-provider serialization primitive + FIFO waitlist."""

    def __init__(self, provider: str, max_concurrent: int):
        self.provider = provider
        self.max_concurrent = max(1, int(max_concurrent))
        self._sem = threading.Semaphore(self.max_concurrent)
        self._lock = threading.Lock()
        self._waiters: list[_ProviderTicket] = []  # FIFO
        self._active: list[_ProviderTicket] = []
        # Wall-clock of the last non-warmup ticket release. Read by the
        # warmup keeper to back off when real user load just finished —
        # prevents the keeper from snapping into the gap between two
        # close-together user turns (e.g. mid-eval-run).
        self.last_release_ts: float = 0.0

    def snapshot(self) -> dict:
        with self._lock:
            now = time.time()
            return {
                "provider": self.provider,
                "max_concurrent": self.max_concurrent,
                "active_count": len(self._active),
                "waiting_count": len(self._waiters),
                "active": [
                    {
                        "id": t.id,
                        "label": t.label,
                        "session_id": t.session_id,
                        "agent_id": t.agent_id,
                        "user_id": t.user_id,
                        "model": t.model,
                        "age_ms": int((now - (t.acquired_at or t.enqueued_at)) * 1000),
                    }
                    for t in self._active
                ],
                "waiting": [
                    {
                        "id": t.id,
                        "label": t.label,
                        "session_id": t.session_id,
                        "agent_id": t.agent_id,
                        "user_id": t.user_id,
                        "model": t.model,
                        "age_ms": int((now - t.enqueued_at) * 1000),
                        "position": i + 1,
                    }
                    for i, t in enumerate(self._waiters)
                ],
            }


class LocalProviderQueue:
    """Per-provider concurrency gate + FIFO waitlist.

    Providers opt in via `max_concurrent` in their config.json entry:
      - 0 / missing:  no queue (unlimited), acquire_if is a no-op
      - >= 1:          semaphore cap; extras wait FIFO

    Default is 0 — cloud providers stay unlimited unless explicitly capped.
    Thread-safe; supports cancel_token for clean cancellation while waiting.
    """

    def __init__(self):
        self._slots: dict[str, _ProviderQueueSlot] = {}
        self._lock = threading.Lock()

    def _resolve_max_concurrent(self, provider_name: str) -> int:
        if not provider_name or provider_name == "default":
            return 0
        try:
            cfg_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), "config.json")
            with open(cfg_path) as f:
                prov = json.load(f).get("providers", {}).get(provider_name, {})
            return max(0, int(prov.get("max_concurrent", 0) or 0))
        except Exception:
            return 0

    def _get_or_create_slot(self, provider_name: str) -> _ProviderQueueSlot | None:
        max_c = self._resolve_max_concurrent(provider_name)
        if max_c <= 0:
            return None
        with self._lock:
            slot = self._slots.get(provider_name)
            if slot is None or slot.max_concurrent != max_c:
                slot = _ProviderQueueSlot(provider_name, max_c)
                self._slots[provider_name] = slot
            return slot

    def snapshot_all(self) -> dict:
        with self._lock:
            slots = list(self._slots.values())
        # snapshot each slot without holding the outer lock
        return {
            "providers": {s.provider: s.snapshot() for s in slots},
        }

    def provider_busy(self, provider_name: str, grace_seconds: float = 15.0) -> bool:
        """True if the warmup keeper should defer firing on this provider.

        Busy means any of:
          - a non-warmup ticket is currently holding a slot,
          - any ticket is waiting in the FIFO,
          - a non-warmup ticket released within the last `grace_seconds`.

        The grace window keeps the keeper from snapping into the brief gap
        between two close-together user turns (eval runs, multi-turn chats).
        Providers without a queue slot (cloud, max_concurrent=0) return False.
        """
        if not provider_name or provider_name == "default":
            return False
        with self._lock:
            slot = self._slots.get(provider_name)
        if slot is None:
            return False
        with slot._lock:
            non_warmup_active = any(t.label != "warmup" for t in slot._active)
            waiting = len(slot._waiters) > 0
            last_release = slot.last_release_ts
        if non_warmup_active or waiting:
            return True
        if grace_seconds > 0 and last_release > 0 \
                and (time.time() - last_release) < grace_seconds:
            return True
        return False

    def cancel_ticket(self, ticket_id: str, reason: str = "") -> dict:
        """Admin action: cancel a queued or running ticket.

        Waiting: marks the ticket cancelled so the waiting thread raises
          TaskCancelled on its next 200ms loop tick, ~instant.
        Running: fires the ticket's cancel_token (same as pressing the chat's
          stop button). The sidecar proxy's `_watch_cancel` thread polls the
          token and POSTs `/cancel/<turn_id>` to the sidecar, which terminates
          the in-flight Anthropic SDK call.

        Returns a result dict describing what was cancelled.
        """
        with self._lock:
            slots = list(self._slots.values())
        for slot in slots:
            with slot._lock:
                for t in slot._waiters:
                    if t.id == ticket_id:
                        t._admin_cancelled = True
                        t._admin_cancel_reason = reason or "admin cancel"
                        return {
                            "ok": True, "state": "waiting",
                            "ticket_id": ticket_id, "provider": slot.provider,
                            "label": t.label, "session_id": t.session_id,
                        }
                for t in slot._active:
                    if t.id == ticket_id:
                        t._admin_cancelled = True
                        t._admin_cancel_reason = reason or "admin cancel"
                        # Fire the ticket's cancel_token if present — this is
                        # the same signal the per-chat Stop button uses.
                        ct = t.cancel_token
                        fired = False
                        if ct is not None:
                            try:
                                # CancelToken exposes cancel()
                                if hasattr(ct, "cancel"):
                                    ct.cancel()
                                    fired = True
                                else:
                                    # Some watchers just expose .cancelled = True
                                    try:
                                        ct.cancelled = True
                                        fired = True
                                    except Exception:
                                        pass
                            except Exception:
                                pass
                        return {
                            "ok": True, "state": "running",
                            "ticket_id": ticket_id, "provider": slot.provider,
                            "label": t.label, "session_id": t.session_id,
                            "cancel_token_fired": fired,
                        }
        return {"ok": False, "error": "ticket not found", "ticket_id": ticket_id}

    def reset_config(self):
        """Drop all slots; next acquire rebuilds from fresh config."""
        with self._lock:
            # Never destroy a slot while it holds active tickets; just clear
            # so a future acquire rebuilds. Active tickets retain their ref.
            self._slots.clear()

    @contextlib.contextmanager
    def acquire_if(self, provider_name: str, *, label: str,
                   session_id: str | None = None,
                   agent_id: str | None = None,
                   user_id: str | None = None,
                   model: str | None = None,
                   event_callback=None,
                   cancel_token=None,
                   timeout: float | None = None):
        """Block until the provider's semaphore has a free slot.

        No-op if the provider isn't queued (max_concurrent <= 0).

        Scope: wrap *only* the HTTP call to /chat/completions. Release as soon
        as the LLM response completes — don't hold across tool execution or
        nested calls. The gateway's actual bottleneck is one HTTP call at a
        time; tool work happens locally and doesn't consume gateway capacity.
        This also avoids a deadlock where a worker subagent's nested
        send_message (e.g. summariser) would block on the outer chat's slot.

        Emits queue_wait / queue_acquired / queue_released events via
        event_callback. Raises TimeoutError on timeout, TaskCancelled on cancel.
        """
        slot = self._get_or_create_slot(provider_name)
        if slot is None:
            yield None
            return

        ticket = _ProviderTicket(
            provider=provider_name, label=label, session_id=session_id,
            agent_id=agent_id, user_id=user_id, model=model,
            event_callback=event_callback, cancel_token=cancel_token,
        )
        to = float(timeout) if timeout is not None else _PROVIDER_QUEUE_TIMEOUT_DEFAULT

        # Enqueue + emit initial position
        with slot._lock:
            slot._waiters.append(ticket)
            ticket._position = len(slot._waiters)
            waiting_count = len(slot._waiters)
            active_count = len(slot._active)
        self._emit(ticket, "queue_wait", slot, ticket._position,
                   waiting_count, active_count)

        deadline = time.time() + to
        acquired = False
        try:
            # Wait for our turn: we must be the head of the waiter list AND
            # the semaphore must have a free slot.
            while True:
                if cancel_token and getattr(cancel_token, "cancelled", False):
                    raise TaskCancelled()
                if ticket._admin_cancelled:
                    raise TaskCancelled(
                        f"Queue cancel by admin: {ticket._admin_cancel_reason or 'no reason given'}"
                    )
                remaining = deadline - time.time()
                if remaining <= 0:
                    raise TimeoutError(
                        f"Provider '{provider_name}' queue timeout after {to}s "
                        f"(label={label}, position={ticket._position})"
                    )
                # Only the FIFO head is allowed to try acquiring the semaphore;
                # others wait for the head to be popped. Poll every 200ms so we
                # can respond to cancels and re-emit position when it changes.
                with slot._lock:
                    is_head = slot._waiters and slot._waiters[0].id == ticket.id
                    cur_position = 0
                    for i, t in enumerate(slot._waiters):
                        if t.id == ticket.id:
                            cur_position = i + 1
                            break
                if cur_position != ticket._position:
                    ticket._position = cur_position
                    self._emit(ticket, "queue_wait", slot, cur_position,
                               len(slot._waiters), len(slot._active))
                if is_head:
                    got = slot._sem.acquire(timeout=min(0.2, remaining))
                    if got:
                        acquired = True
                        with slot._lock:
                            try:
                                slot._waiters.remove(ticket)
                            except ValueError:
                                pass
                            ticket.acquired_at = time.time()
                            slot._active.append(ticket)
                        self._emit(ticket, "queue_acquired", slot, 0,
                                   len(slot._waiters), len(slot._active))
                        break
                else:
                    # Not the head — sleep briefly and re-check.
                    time.sleep(min(0.2, max(0.05, remaining)))
            yield ticket
        except BaseException:
            # On cancel/timeout/exception before acquisition, remove from waiters.
            if not acquired:
                with slot._lock:
                    try:
                        slot._waiters.remove(ticket)
                    except ValueError:
                        pass
            raise
        finally:
            if acquired and not ticket._released:
                ticket._released = True
                ticket.released_at = time.time()
                with slot._lock:
                    try:
                        slot._active.remove(ticket)
                    except ValueError:
                        pass
                    waiting_count = len(slot._waiters)
                    active_count = len(slot._active)
                    # Track when real user load (not the warmup keeper itself)
                    # last finished on this provider, so the keeper can back
                    # off for a short grace window afterwards.
                    if ticket.label != "warmup":
                        slot.last_release_ts = ticket.released_at
                slot._sem.release()
                self._emit(ticket, "queue_released", slot, 0,
                           waiting_count, active_count)

    def _emit(self, ticket: _ProviderTicket, event_type: str, slot,
              position: int, waiting_count: int, active_count: int):
        cb = ticket.event_callback
        if not cb:
            return
        try:
            cb(event_type, {
                "provider": ticket.provider,
                "label": ticket.label,
                "model": ticket.model,
                "session_id": ticket.session_id,
                "agent_id": ticket.agent_id,
                "position": position,
                "waiting": waiting_count,
                "active": active_count,
                "max_concurrent": slot.max_concurrent,
                "ticket_id": ticket.id,
                "wait_ms": int((time.time() - ticket.enqueued_at) * 1000),
            })
        except Exception:
            pass


_provider_queue = LocalProviderQueue()


def get_provider_queue() -> LocalProviderQueue:
    return _provider_queue


def get_warmup_state(model: str) -> dict:
    """Get a copy of the current warmup state for a model."""
    with _warmup_state_lock:
        return dict(_warmup_state.get(model, {
            "state": "idle",
            "last_warmup_ts": 0,
            "last_used_ts": 0,
            "last_error": "",
            "next_due_ts": 0,
        }))


def set_warmup_state(model: str, **fields):
    """Update warmup state fields for a model."""
    with _warmup_state_lock:
        cur = _warmup_state.setdefault(model, {
            "state": "idle",
            "last_warmup_ts": 0,
            "last_used_ts": 0,
            "last_error": "",
            "next_due_ts": 0,
        })
        cur.update(fields)


def mark_model_used(model: str):
    """Call when a real request hits a model.

    A real turn keeps the model loaded in GPU memory and leaves a valid KV
    prefix cached — effectively, using the model is itself the best warmup.
    So we bump both last_used_ts and (if currently cold/idle) flip the state
    to warm so the UI reflects reality without triggering a redundant prime.
    """
    now = time.time()
    with _warmup_state_lock:
        cur = _warmup_state.setdefault(model, {
            "state": "idle",
            "last_warmup_ts": 0,
            "last_used_ts": 0,
            "last_error": "",
            "next_due_ts": 0,
        })
        cur["last_used_ts"] = now
        if cur.get("state") in ("idle", "cold", "failed"):
            cur["state"] = "warm"
            cur["last_warmup_ts"] = now
            cur["last_error"] = ""


def all_warmup_states() -> dict:
    """Return snapshot of all tracked warmup states."""
    with _warmup_state_lock:
        return {k: dict(v) for k, v in _warmup_state.items()}


# Inflight tracker for thinking-mode re-primes — prevents stacking concurrent
# warmups against the same model when a chat toggles thinking rapidly.
_reprime_inflight: set = set()
_reprime_inflight_lock = threading.Lock()


def maybe_reprime_for_thinking(model: str, thinking: bool, agent_id: str = "main") -> bool:
    """Trigger a background re-prime if the requested thinking mode differs
    from what's currently primed. No-op when:
      - the model has no warmup configured
      - the model has thinking_format=none (toggle is a no-op anyway)
      - a re-prime for this model is already in flight
      - the cached state already matches the requested mode

    Returns True if a re-prime thread was kicked off.
    """
    cfg = _models_config.get(model, {}) or {}
    if not cfg.get("warmup"):
        return False
    if cfg.get("thinking_format", "none") == "none":
        return False
    state = get_warmup_state(model)
    # If we've never primed yet, the first real turn does the work — skip.
    if state.get("state") not in ("warm", "warming"):
        return False
    if bool(state.get("thinking_primed")) == bool(thinking):
        return False
    with _reprime_inflight_lock:
        if model in _reprime_inflight:
            return False
        _reprime_inflight.add(model)

    def _bg():
        try:
            allow_cloud = bool(cfg.get("warmup_allow_cloud"))
            mode = (cfg.get("warmup_mode") or "full").lower()
            run_model_warmup(model, allow_cloud=allow_cloud,
                             agent_id=agent_id, mode=mode, thinking=thinking)
        finally:
            with _reprime_inflight_lock:
                _reprime_inflight.discard(model)

    threading.Thread(target=_bg, daemon=True,
                     name=f"reprime-{model[:20]}-think{int(thinking)}").start()
    return True


# --- Shared domain context + tool_context construction -----------------
#
# A scheduled task in a given domain (plain chat vs. project chat) runs the
# SAME domain logic as a chat in that domain — it has no parallel
# implementation. `apply_domain_context` is the single place that turns the
# domain inputs (agent, project, user) into request-context state:
#   - project scope (`project` = name; resolved from project_id for callers
#     that only have the id, like the scheduler)
#   - team_ids (from the user's auth record) → team-scoped MemPalace wings
#   - research_mode_override
#   - the `disable_web_search` project lockout (web tools removed from the
#     active set, additive to any caller-supplied exclude list)
# Both the chat worker and the scheduler fire-path call it, so the two never
# drift. `build_tool_context` then snapshots the request context into the dict
# `run_turn` consumes — again one definition for both callers.

def apply_domain_context(*, agent_id: str, project: str = "",
                         project_id: str = "", user_id: str = "",
                         research_mode_override=None,
                         base_exclude_tools: list | None = None) -> None:
    """Set the domain-determining fields on the ACTIVE request context.

    Must be called inside a `with request_context():` scope. Idempotent-ish:
    overwrites project / team_ids / research_mode_override / exclude_tools.

    project / project_id: pass whichever you have. project_id wins if given
    (resolved to the project NAME — the value every downstream consumer reads).
    base_exclude_tools: names to exclude regardless (e.g. the chat's Websuche
    basket lockout); the project web lockout is unioned on top.
    """
    ctx = get_request_context()
    # 1. Resolve project name. The scheduler stores project_id; the chat passes
    #    the name directly. Either way the request context holds the NAME.
    proj_name = (project or "").strip()
    if project_id and not proj_name:
        try:
            for _p in ProjectManager.list_projects(agent_id):
                if _p.get("id") == project_id:
                    proj_name = _p.get("name") or ""
                    break
        except Exception:
            proj_name = ""
    ctx.project = proj_name

    # 2. Team IDs (team-scoped MemPalace wing visibility). Empty for anon.
    try:
        from server_lib.auth import AuthDB as _AuthDB
        ctx.current_team_ids = [
            t["id"] for t in _AuthDB.get_user_teams(user_id)
        ] if user_id else []
    except Exception:
        ctx.current_team_ids = []

    # 3. Research-mode override (sticky per session; None = project default).
    ctx.research_mode_override = research_mode_override

    # 4. Web-search lockout. Start from any caller-supplied exclusions (the
    #    chat's Websuche-basket lockout), then add the 3 web tools when the
    #    project has `disable_web_search` set. Model-independent enforcement.
    _excl = set(base_exclude_tools or [])
    if proj_name:
        try:
            _pcfg = ProjectManager.get_project(agent_id, proj_name)
        except Exception:
            _pcfg = None
        if _pcfg and _pcfg.get("disable_web_search"):
            _excl |= {"web_fetch", "exa_search", "searxng_search"}
    ctx.exclude_tools = list(_excl) if _excl else None


def build_tool_context(*, session_id: str, agent_id: str, user_id: str = "",
                       gdpr_mapping_id: str = "") -> dict:
    """Snapshot the active request context into the tool_context dict that
    `run_turn` passes to the sidecar. Single definition for chat + scheduler so
    the per-tool-call context rebuild is identical in both. Reads project,
    team_ids, note_context, workflow_run_id, plan_mode, research_mode_override,
    execution_overrides, attachment_image_model, caveman_* off the context —
    so whatever `apply_domain_context` (and the caller) set is reflected."""
    ctx = get_request_context()
    return {
        "session_id": session_id,
        "agent_id": agent_id,
        "user_id": user_id or "",
        "team_ids": list(ctx.current_team_ids or []),
        "project": ctx.project or "",
        "note_context": ctx.note_context,
        "workflow_run_id": ctx.workflow_run_id or "",
        "plan_mode": bool(ctx.plan_mode),
        "research_mode_override": ctx.research_mode_override,
        "execution_overrides": ctx.execution_overrides or {},
        "attachment_image_model": ctx.attachment_image_model or "",
        "caveman_chat": int(ctx.caveman_chat or 0),
        "caveman_system": int(ctx.caveman_system or 0),
        "gdpr_mapping_id": gdpr_mapping_id or "",
    }


def build_first_turn_prefix(model: str, agent_id: str, *,
                            mcp_manager=None,
                            discovered_tools: set | None = None,
                            is_openai_shape: bool = False,
                            purpose: str = "interactive",
                            system_prompt_override: str | None = None,
                            breakdown: dict | None = None):
    """SINGLE source of truth for the first-turn KV prefix (system prompt +
    active tools). Both the warm-pool prime (`run_model_warmup`) and the live
    chat worker call this so their prefixes are byte-identical — the entire
    point of warmup. Any input that one caller sets and the other doesn't is a
    silent cache-miss; centralising the recipe here makes that impossible.

    Binds `get_request_context()._current_model = model` so `_get_token_config`
    resolves the SAME model-profile overlay (deferred_tool_groups, etc.) in
    both paths. Caller is responsible for the thread-context (`current_agent`,
    mcp_manager) being set, and for restoring/clearing `_current_model`.

    `is_openai_shape` affects only the tool serialization shape, NOT the tool
    names or the system-prompt text — so it's safe for the two callers to
    differ there (warmup hits oMLX's OpenAI endpoint; the turn goes through the
    Anthropic-shape sidecar). The KV-prefix-relevant outputs (system_prompt +
    active_tool_names) are shape-independent.

    Returns (system_prompt, active_tools, active_tool_names).
    """
    get_request_context()._current_model = model
    active_tools = resolve_active_tools(
        purpose=purpose,
        agent_id=agent_id,
        discovered_tools=discovered_tools if discovered_tools is not None else set(),
        mcp_manager=mcp_manager,
        is_openai_shape=is_openai_shape,
        breakdown=breakdown,
    )
    active_tool_names = {
        (t.get("function", {}) or {}).get("name", "") or t.get("name", "")
        for t in active_tools
    }
    # Brainy (purpose="helpdesk") ships a FIXED system prompt from config, not
    # the agent's _build_system_prompt — so its warmup prime must mirror that
    # exact text, else the KV prefix misses on the first Brainy turn.
    if system_prompt_override is not None:
        system_prompt = system_prompt_override
    else:
        system_prompt = _build_system_prompt(
            include_memory_summary=True,
            purpose=purpose,
            active_tool_names=active_tool_names,
        )
    return system_prompt, active_tools, active_tool_names


def run_model_warmup(model: str, allow_cloud: bool = False,
                     agent_id: str = "main", timeout: int = 30,
                     mode: str = "full", thinking: bool = False,
                     purpose: str = "interactive",
                     track_state: bool = True) -> dict:
    """Fire a single prefill request against a model's provider.

    Returns a result dict: {ok, state, duration_ms, error, mode}. Updates
    _warmup_state.

    `mode` controls the payload shape:
      - "full":    system prompt + tools + "." user. Primes the KV cache so
                   the user's first real turn reuses the prefix. Best when
                   exactly one warmup model is active (its KV stays resident).
      - "minimal": 1-token user ("."), no system, no tools. Only loads the
                   model's weights into GPU memory — no KV prefix primed.
                   Used when multiple warmup models are active, because they'd
                   evict each other's KV cache anyway, so paying the prefill
                   cost is wasted work.

    `thinking` (oMLX thinking-capable models only): when True, the warmup
    payload sets chat_template_kwargs.enable_thinking=true so the primed KV
    prefix matches a chat that has thinking enabled. Without this match, the
    first thinking-on turn cache-misses and pays full prefill cost.
    """
    t0 = time.time()
    # The helpdesk (Brainy) side-prime warms a SECOND, different prefix for the
    # same model. It must NOT clobber the model's reported warmup state (the
    # keeper keys state by model and would think the model needs re-priming).
    # track_state=False routes every state write through this no-op.
    def _set_state(*a, **k):
        if track_state:
            set_warmup_state(*a, **k)
    prov = resolve_provider_for_model(model)
    base_url = prov.get("base_url", "")
    api_key = prov.get("api_key", "")

    if not base_url:
        err = "no base_url"
        _set_state(model, state="failed", last_error=err)
        return {"ok": False, "state": "failed", "error": err, "duration_ms": 0, "mode": mode}

    # `prov` (resolve_provider_for_model) returns only {api_key, base_url,
    # provider_name} — it has NO is_local key, so prov.get("is_local") was
    # always False and every model was treated as cloud (warmup skipped unless
    # warmup_allow_cloud was set). Same bug class as the v8.8.0 is_model_local
    # fix. Use the authoritative resolver, which reads the provider's is_local
    # flag from config by name.
    if not allow_cloud and not is_model_local(model):
        _set_state(model, state="skipped_cloud",
                   last_error="cloud provider (warmup.allow_cloud=false)")
        return {"ok": False, "state": "skipped_cloud",
                "error": "cloud skipped", "duration_ms": 0, "mode": mode}

    _set_state(model, state="warming", last_error="", mode=mode,
               thinking_primed=bool(thinking))

    try:
        agent_config = AgentConfig(agent_id)
        # Reuse the process-global MCP manager so warmup's tool list matches
        # the real chat payload. Without this, the KV prefix differs (MCP
        # tools are in the real request but not the warmup) and oMLX's
        # prompt cache misses on the first turn — defeating warmup entirely.
        mcp_mgr = _mcp_manager if mode == "full" else None
        _warmup_ctx = ExecutionContext(
            mode="chat",
            agent_id=agent_id,
            mcp_manager=mcp_mgr,
        )
        with request_context():
            init_thread_context(_warmup_ctx, agent_config=agent_config)
            # Caveman no longer touches the system prompt (v9.121.0 — it's a
            # trailing wire-only suffix on the user message), so warmup needs NO
            # caveman handling: the primed system-prompt prefix is byte-identical
            # to every turn regardless of caveman level.

            if mode == "full":
                # Build the prefix through the SHARED helper so it is byte-identical
                # to the live chat worker's first-turn prefix (the chat worker calls
                # the same build_first_turn_prefix). discovered_tools=set() matches
                # turn 0 (nothing discovered yet); mcp_manager + model binding are
                # handled inside the helper. Tool wire-shape (openai) differs from
                # the sidecar's anthropic shape but does NOT affect the KV-relevant
                # system_prompt / tool-name set.
                #
                # purpose="helpdesk": prime BRAINY's prefix instead — its fixed
                # read-only tool set + the helpdesk system prompt from config (NOT
                # the agent's _build_system_prompt). Mirrors handlers/helpdesk.py
                # so the first Brainy turn on a local model hits the warm prefix.
                _sp_override = None
                if purpose == "helpdesk":
                    try:
                        from handlers.helpdesk import _load_helpdesk_config
                        _sp_override = _load_helpdesk_config()["system_prompt"]
                    except Exception:
                        _sp_override = None
                system_prompt, all_tools, _ = build_first_turn_prefix(
                    model, agent_id,
                    mcp_manager=mcp_mgr,
                    discovered_tools=set(),
                    is_openai_shape=True,
                    purpose=purpose,
                    system_prompt_override=_sp_override,
                )
                messages = [
                    {"role": "system", "content": system_prompt},
                    {"role": "user", "content": "."},
                ]
            else:  # "minimal"
                # Weights-only prime: no system prompt, no tools. all_tools must
                # still be bound (the shared payload-build below reads it) — empty
                # so no `tools` key is added.
                messages = [{"role": "user", "content": "."}]
                all_tools = []

            endpoint = f"{base_url}/chat/completions"
            # Match send_message: stream=True + stream_options so the tokenised
            # request shape is identical to what the real first turn sends.
            # max_tokens=8 is fine — the KV prefix covers system+tools+user and
            # doesn't depend on the output-length budget.
            payload = {
                "model": get_api_model_id(model),
                "max_tokens": 8,
                "messages": messages,
                "stream": True,
                "stream_options": {"include_usage": True},
            }
            if all_tools:
                payload["tools"] = all_tools
            model_cfg = resolve_model_settings(model)
            if all_tools and model_cfg.get("parallel_tool_calls", True):
                payload["parallel_tool_calls"] = True
            # KV-prefix stability: real chat requests now go through
            # _apply_inference_to_payload, which forces enable_thinking on/off for
            # oMLX thinking-capable models. The warmup payload must mirror that
            # exactly or the prefix won't match and prompt cache will miss.
            # When `thinking=True` we inject the same legacy flag the chat path
            # uses so the helper renders enable_thinking=true into the payload.
            provider_name = prov.get("provider_name", "")
            _inf = get_inference_params(model)
            if thinking:
                _inf = dict(_inf)
                _inf["thinking"] = True
                _inf["thinking_level"] = "high"
            _apply_inference_to_payload(payload, _inf, provider_name, scoped_model=model)
            headers = make_headers(api_key)
            data = json.dumps(payload).encode("utf-8")
            req = urllib.request.Request(endpoint, data=data, headers=headers, method="POST")
            _provider_name = prov.get("provider_name", "") or "default"
            with _provider_queue.acquire_if(
                _provider_name, label="warmup",
                session_id=None, agent_id=agent_id, user_id=None,
                model=model, event_callback=None, cancel_token=None,
                timeout=max(timeout * 2, 60),
            ):
                with urllib.request.urlopen(req, timeout=timeout) as resp:
                    resp.read()
            dur_ms = int((time.time() - t0) * 1000)
            now = time.time()
            _set_state(model, state="warm", last_warmup_ts=now,
                       last_error="", mode=mode,
                       thinking_primed=bool(thinking))
            return {"ok": True, "state": "warm", "duration_ms": dur_ms,
                    "error": "", "mode": mode, "thinking": bool(thinking)}
    except urllib.error.HTTPError as e:
        try:
            body = e.read().decode("utf-8", errors="replace")[:500]
        except Exception:
            body = ""
        err = f"HTTP {e.code}: {body or e.reason}"
        _set_state(model, state="failed", last_error=err,
                   last_warmup_ts=time.time(), mode=mode)
        return {"ok": False, "state": "failed", "error": err,
                "duration_ms": int((time.time() - t0) * 1000), "mode": mode}
    except Exception as e:
        err = f"{type(e).__name__}: {e}"
        _set_state(model, state="failed", last_error=err,
                   last_warmup_ts=time.time(), mode=mode)
        return {"ok": False, "state": "failed", "error": err,
                "duration_ms": int((time.time() - t0) * 1000), "mode": mode}


# --- Background Task Runner ---

import uuid as _uuid


class TaskRunner:
    """Manages background agent tasks with status tracking and cancellation."""

    def __init__(self):
        self._tasks: dict[str, dict] = {}  # task_id -> task_info
        self._threads: dict[str, threading.Thread] = {}
        self._cancel_flags: dict[str, threading.Event] = {}
        self._lock = threading.Lock()

    def submit(self, agent_id: str, task: str, model: str | None = None) -> str:
        """Submit a task to run in a background thread. Returns task_id."""
        task_id = _uuid.uuid4().hex[:8]
        cancel_flag = threading.Event()
        # Capture caller's user_id and team ids for MemPalace wing scoping in the child thread
        caller_user_id = get_request_context().current_user_id or ""
        caller_team_ids = list(get_request_context().current_team_ids or [])

        with self._lock:
            self._tasks[task_id] = {
                "id": task_id,
                "agent": agent_id,
                "task": task,
                "model": model,
                "status": "running",
                "result": None,
                "error": None,
                "submitted_at": datetime.datetime.now().isoformat(),
                "finished_at": None,
            }
            self._cancel_flags[task_id] = cancel_flag

        thread = threading.Thread(
            target=self._run_task,
            args=(task_id, agent_id, task, model, cancel_flag, caller_user_id, caller_team_ids),
            daemon=True)
        self._threads[task_id] = thread
        thread.start()
        return task_id

    def get_status(self, task_id: str) -> dict | None:
        with self._lock:
            return self._tasks.get(task_id, {}).copy() if task_id in self._tasks else None

    def list_tasks(self) -> list[dict]:
        with self._lock:
            return [t.copy() for t in self._tasks.values()]

    def cancel(self, task_id: str) -> bool:
        with self._lock:
            if task_id not in self._tasks:
                return False
            if self._tasks[task_id]["status"] != "running":
                return False
            self._cancel_flags[task_id].set()
            self._tasks[task_id]["status"] = "cancelled"
            self._tasks[task_id]["finished_at"] = datetime.datetime.now().isoformat()
            return True

    def get_result(self, task_id: str) -> dict | None:
        """Get result, blocking until complete if still running. Timeout 0.1s poll."""
        if task_id not in self._threads:
            return self.get_status(task_id)
        # Wait for thread to finish (with timeout so we don't block forever)
        self._threads[task_id].join(timeout=300)
        return self.get_status(task_id)

    def _run_task(self, task_id: str, agent_id: str, task: str,
                  model: str | None, cancel_flag: threading.Event,
                  caller_user_id: str = "",
                  caller_team_ids: list | None = None):
        caller_team_ids = caller_team_ids or []
        """Execute a task in a background thread."""
        target = AgentConfig(agent_id)

        if not model:
            model = target.preferred_model or _delegate_fallback_model or "claude-opus-4-5-20251101"

        import platform
        cwd = os.getcwd()
        os_name = platform.system()
        soul = target.soul

        from datetime import datetime as _dt
        system_prompt = (
            f"{soul}\n\n"
            f"You are agent '{agent_id}' running a background task.\n"
            f"Current date and time: {_dt.now().strftime('%Y-%m-%d %H:%M %Z').strip()}\n"
            f"Current working directory: {cwd}\n"
            f"Operating system: {os_name}\n\n"
            "Complete the task and provide a concise result summary.\n"
        )
        # Inject team context
        team_info = _get_agent_team_info(agent_id)
        if team_info:
            if team_info["is_head"]:
                peers = [m for m in team_info["members"] if m != agent_id]
                system_prompt += (
                    f"\nTEAM: You are the head of team '{team_info['name']}'. "
                    f"Your team members: {', '.join(peers)}\n"
                    "Delegate sub-tasks to your team members when appropriate.\n"
                    "Use wiki_write(scope='team') for team-level shared knowledge.\n"
                )
            else:
                peers = [m for m in team_info["members"] if m != agent_id and m != team_info["head"]]
                system_prompt += (
                    f"\nTEAM: You are a member of team '{team_info['name']}'.\n"
                    f"Team head: {team_info['head']}\n"
                )
                if peers:
                    system_prompt += f"Team peers: {', '.join(peers)}\n"
                system_prompt += "Use wiki_write(scope='team') for team-level shared knowledge.\n"

        # Per-tool prompt prose for the delegate's resolved tool set.
        _delegate_tool_names = _get_agent_tool_names(agent_id)
        if _delegate_tool_names:
            _rules = _render_tool_descriptions(_delegate_tool_names)
            if _rules:
                system_prompt += f"\n--- TOOL USAGE GUIDE ---\n{_rules}"

        # Build team-aware agent registry for this delegate
        agent_registry = build_agent_registry(for_agent_id=agent_id)
        if agent_registry:
            system_prompt += f"\n\n{agent_registry}\n"

        messages = [{"role": "user", "content": task}]

        result_text = ""
        status = "completed"
        try:
            _task_ctx = ExecutionContext(
                mode="delegate",
                agent_id=agent_id,
                user_id=caller_user_id,
                team_ids=caller_team_ids,
            )
            with request_context():
                init_thread_context(_task_ctx, agent_config=target)
                if cancel_flag.is_set():
                    status = "cancelled"
                else:
                    delegate_inf = get_inference_params(model, target.config.get("model_purpose"))
                    # GDPR policy gate: the calling agent's context (system
                    # prompt + the task payload itself) may carry PII, and the
                    # delegate target can be a different cloud provider than
                    # the parent. Scan both, swap model and/or pseudonymise
                    # per admin policy, deanon the reply before returning it
                    # up to the caller.
                    _del_deanon = _identity_deanon
                    _wire_system = system_prompt
                    _wire_messages = messages
                    try:
                        _msg_blobs = []
                        _msg_idx = []
                        for _i, _m in enumerate(messages):
                            _c = _m.get("content")
                            if isinstance(_c, str):
                                _msg_blobs.append(_c)
                                _msg_idx.append(_i)
                        _scan_inputs = [system_prompt] + _msg_blobs
                        model, _new_blobs, _del_deanon = gdpr_pick_model_for_background(
                            model, _scan_inputs, purpose="delegate_task")
                        if _new_blobs is not _scan_inputs:
                            _wire_system = _new_blobs[0]
                            _wire_messages = list(messages)
                            for _i, _nb in zip(_msg_idx, _new_blobs[1:]):
                                _wire_messages[_i] = {**messages[_i], "content": _nb}
                    except GDPRBlockedError as e:
                        status = "error"
                        result_text = f"Delegate error: GDPR block — {e}"
                    if status != "error":
                        from handlers import sidecar_proxy as _sidecar_proxy
                        _res = _sidecar_proxy.background_call(
                            messages=_wire_messages, model=model, system_prompt=_wire_system,
                            agent_id=agent_id, cost_purpose="delegate_task",
                            max_tokens=int(delegate_inf.get("max_tokens") or 0) or None,
                        )
                        result_text = _del_deanon(_res.get("reply") or "")
                        if cancel_flag.is_set():
                            status = "cancelled"
                        elif _res.get("error"):
                            result_text = f"Delegate error: {_res['error']}"
                            status = "error"
        except Exception as e:
            result_text = str(e)
            status = "error"

        with self._lock:
            self._tasks[task_id]["status"] = status
            self._tasks[task_id]["result"] = result_text
            self._tasks[task_id]["finished_at"] = datetime.datetime.now().isoformat()
            if status == "error":
                self._tasks[task_id]["error"] = result_text
            # Clean up thread reference
            self._threads.pop(task_id, None)
            self._cancel_flags.pop(task_id, None)


# Global task runner
_task_runner: TaskRunner | None = None


# --- Workflow Engine ---

try:
    import yaml as _yaml
except ImportError:
    _yaml = None  # Graceful fallback — suggest pip3 install pyyaml


# =================================================================
# Workflow Language (.flow) — small scripted DSL.
#
# A workflow is a plain-text file storing keywords + tool calls. The
# language stays deliberately tiny (Excel-formula-tier) so non-programmer
# users can read and edit them; every action is a CALL to a Brain tool
# from TOOL_DISPATCH so the language never lags behind the tool surface.
#
# Grammar (informal):
#
#   workflow      := (line)*
#   line          := comment | header | statement
#   comment       := '#' .*
#   header        := 'WORKFLOW' STRING
#                  | 'DESCRIPTION' STRING
#                  | 'TRIGGER' STRING
#   statement     := assign | call_stmt | if_stmt | for_stmt | return_stmt
#   assign        := 'SET' IDENT '=' expr
#   call_stmt     := 'CALL' IDENT (NAME '=' expr)*
#                  | 'CALL?' IDENT (NAME '=' expr)*
#   if_stmt       := 'IF' expr ':' BLOCK ('ELSE' ':' BLOCK)?
#   for_stmt      := 'FOR' 'EACH' IDENT 'IN' expr ':' BLOCK
#   return_stmt   := 'RETURN' expr
#   BLOCK         := indented child lines
#   expr          := literal | ident | indexing | call_expr | binop | str_interp
#
# Errors halt by default. `CALL?` makes a call non-fatal — on tool error
# the variable is set to null and `last_error` holds the message.
# =================================================================


# ----------------------------- Workflow scripting engine -----------------------------
# Lexer / AST / parser / interpreter extracted to engine/workflow.py (governing
# principle #3). Re-exported here so in-file callers (WorkflowEngine /
# WorkflowExecution) and external `brain.X` references still resolve.
from engine.workflow import (
    WorkflowError,
    _WF_KEYWORDS, _WF_TT, _WF_OP_MULTICHAR,
    _wf_tokenize, _wf_tok_line,
    _WFNode, _WFLiteral, _WFVar, _WFGetAttr, _WFGetItem, _WFBinOp, _WFUnary,
    _WFFnCall, _WFList, _WFDict, _WFInterpStr, _WFAssign, _WFCall, _WFIf,
    _WFFor, _WFReturn, _WFProgram, _WFParser,
    _wf_parse,
    _WFReturnValue, _WorkflowInterpreter,
)


# ----------------------------- Public API -----------------------------


class WorkflowEngine:
    """Workflow definitions stored as plain text under agents/<id>/workflows/*.flow."""

    EXTENSION = ".flow"

    @staticmethod
    def _workflows_dir(agent_id: str) -> str:
        return os.path.join(AGENTS_DIR, agent_id, "workflows")

    @staticmethod
    def list_workflows(agent_id: str) -> list[dict]:
        wdir = WorkflowEngine._workflows_dir(agent_id)
        if not os.path.isdir(wdir):
            return []
        results = []
        for fname in sorted(os.listdir(wdir)):
            if not fname.endswith(WorkflowEngine.EXTENSION):
                continue
            name = fname[:-len(WorkflowEngine.EXTENSION)]
            src = WorkflowEngine.get_workflow_source(agent_id, name)
            display_name = name
            description = ""
            trigger = "manual"
            if src is not None:
                try:
                    prog = _wf_parse(src)
                    if prog.name:
                        display_name = prog.name
                    description = prog.description
                    trigger = prog.trigger
                except WorkflowError:
                    pass
            results.append({
                "file": fname,
                "name": name,
                "display_name": display_name,
                "description": description,
                "trigger": trigger,
            })
        return results

    @staticmethod
    def get_workflow_source(agent_id: str, name: str) -> str | None:
        wdir = WorkflowEngine._workflows_dir(agent_id)
        fpath = os.path.join(wdir, name + WorkflowEngine.EXTENSION)
        if not os.path.exists(fpath):
            return None
        try:
            with open(fpath, "r") as f:
                return f.read()
        except Exception:
            return None

    @staticmethod
    def save_workflow(agent_id: str, name: str, source: str) -> str:
        # Validate by attempting to parse
        try:
            _wf_parse(source)
        except WorkflowError as e:
            raise RuntimeError(f"Workflow parse error on line {e.line}: {e}")
        wdir = WorkflowEngine._workflows_dir(agent_id)
        os.makedirs(wdir, exist_ok=True)
        fpath = os.path.join(wdir, name + WorkflowEngine.EXTENSION)
        with open(fpath, "w") as f:
            f.write(source)
        return fpath

    @staticmethod
    def delete_workflow(agent_id: str, name: str) -> bool:
        wdir = WorkflowEngine._workflows_dir(agent_id)
        fpath = os.path.join(wdir, name + WorkflowEngine.EXTENSION)
        ok = False
        if os.path.exists(fpath):
            os.remove(fpath)
            ok = True
        meta_path = fpath + ".meta.json"
        if os.path.exists(meta_path):
            try:
                os.remove(meta_path)
            except OSError:
                pass
        return ok

    # ── sharing metadata sidecar (<name>.flow.meta.json) ────────────
    @staticmethod
    def _workflow_meta_path(agent_id: str, name: str) -> str:
        return os.path.join(WorkflowEngine._workflows_dir(agent_id),
                            name + WorkflowEngine.EXTENSION + ".meta.json")

    @staticmethod
    def get_workflow_meta(agent_id: str, name: str) -> dict | None:
        """Return the workflow's sharing-metadata dict. None if the workflow
        doesn't exist; an empty-ish dict (owner='') for a legacy workflow with
        no sidecar yet."""
        wf_path = os.path.join(WorkflowEngine._workflows_dir(agent_id),
                               name + WorkflowEngine.EXTENSION)
        if not os.path.exists(wf_path):
            return None
        mp = WorkflowEngine._workflow_meta_path(agent_id, name)
        meta = {"owner_user_id": "", "visibility": "private", "owner_team_id": "",
                "extra_member_user_ids": [], "excluded_user_ids": [], "created_at": ""}
        if os.path.exists(mp):
            try:
                with open(mp, "r") as f:
                    stored = json.load(f)
                if isinstance(stored, dict):
                    meta.update({k: stored[k] for k in stored if k in meta})
            except (OSError, json.JSONDecodeError):
                pass
        return meta

    @staticmethod
    def update_workflow_meta(agent_id: str, name: str, updates: dict) -> dict:
        meta = WorkflowEngine.get_workflow_meta(agent_id, name)
        if meta is None:
            return {"error": "workflow not found"}
        for k in ("owner_user_id", "visibility", "owner_team_id",
                  "extra_member_user_ids", "excluded_user_ids", "created_at"):
            if k in updates:
                meta[k] = updates[k]
        if not meta.get("created_at"):
            meta["created_at"] = datetime.datetime.now(datetime.timezone.utc).isoformat()
        mp = WorkflowEngine._workflow_meta_path(agent_id, name)
        try:
            os.makedirs(os.path.dirname(mp), exist_ok=True)
            with open(mp, "w") as f:
                json.dump(meta, f, indent=2)
        except OSError as e:
            return {"error": str(e)}
        return {"status": "updated"}

    @staticmethod
    def workflow_block(meta: dict) -> dict:
        return {
            "owner_user_id": (meta or {}).get("owner_user_id", "") or "",
            "visibility": (meta or {}).get("visibility", "private") or "private",
            "owner_team_id": (meta or {}).get("owner_team_id", "") or "",
            "extra_member_user_ids": (meta or {}).get("extra_member_user_ids", []) or [],
            "excluded_user_ids": (meta or {}).get("excluded_user_ids", []) or [],
        }


class WorkflowExecution:
    """Runs a parsed scripted workflow in a background thread.

    Backwards-compatible interface with the old YAML system: the same
    public attributes (`status`, `current_stage_idx`, `current_stage_name`,
    `started_at`, `finished_at`, `error`, `to_dict`) are preserved so the
    HTTP handlers don't need rewriting.
    """

    def __init__(self, source: str, variables: dict, agent_id: str,
                 model: str | None = None, execution_id: str | None = None,
                 workflow_name: str = "",
                 user_id: str = "", user_display: str = "",
                 trigger_kind: str = "manual", trigger_ref: str = ""):
        self.source = source
        self.variables = variables or {}
        self.agent_id = agent_id
        self.model = model
        self.execution_id = execution_id or _uuid.uuid4().hex[:10]
        self.workflow_name = workflow_name
        self.user_id = user_id or ""
        self.user_display = user_display or ""
        self.trigger_kind = trigger_kind or "manual"
        self.trigger_ref = trigger_ref or ""
        self.status = "pending"
        self.current_stage_idx = -1
        self.current_stage_name = ""
        self.steps: list[dict] = []   # ordered execution log
        self.started_at: str | None = None
        self.finished_at: str | None = None
        self.error: str | None = None
        self._cancel = threading.Event()
        self._thread: threading.Thread | None = None
        self._return_value = None
        self._program: _WFProgram | None = None
        # Parse upfront to surface parse errors before run()
        try:
            self._program = _wf_parse(source)
        except WorkflowError as e:
            self.status = "failed"
            self.error = f"Parse error on line {e.line}: {e}"
            self.finished_at = datetime.datetime.now().isoformat()
            return
        # Inherit AGENT/MODEL from program headers when not overridden by caller
        if self._program:
            if not self.agent_id and self._program.agent_id:
                self.agent_id = self._program.agent_id
            if not self.model and self._program.model:
                self.model = self._program.model
        # Persist initial history row immediately so even running/zombied executions are visible
        try:
            wf_file = (self.workflow_name or "") + WorkflowEngine.EXTENSION
            now_iso = datetime.datetime.now().isoformat()
            self.started_at = now_iso  # provisional — overwritten on run()
            _workflow_history_insert(
                self.execution_id, self.workflow_name, wf_file, source,
                self.agent_id or "main", self.user_id, self.user_display,
                self.trigger_kind, self.trigger_ref, self.model or "",
                now_iso, json.dumps(self.variables, default=str),
            )
        except Exception as e:
            logging.warning(f"workflow init history: {e}")

    def run(self) -> None:
        if self.status == "failed":
            # Parse-error case: history row was never inserted; persist a final
            # row so the run still appears in history with the parse error.
            try:
                wf_file = (self.workflow_name or "") + WorkflowEngine.EXTENSION
                now_iso = self.finished_at or datetime.datetime.now().isoformat()
                _workflow_history_insert(
                    self.execution_id, self.workflow_name, wf_file, self.source,
                    self.agent_id or "main", self.user_id, self.user_display,
                    self.trigger_kind, self.trigger_ref, self.model or "",
                    now_iso, json.dumps(self.variables, default=str),
                )
                _workflow_history_finalize(
                    self.execution_id, "failed", now_iso, 0, self.error, "",
                    json.dumps(self.steps, default=str),
                )
            except Exception:
                pass
            return
        self.status = "running"
        self.started_at = datetime.datetime.now().isoformat()
        self._thread = threading.Thread(
            target=self._execute, daemon=True,
            name=f"workflow-{self.execution_id}")
        self._thread.start()

    def _execute(self) -> None:
        # Set thread-locals so:
        #  - ask_user_for_file finds the execution id
        #  - cost-logging keys all LLM calls under "wf-<execution_id>"
        #  - ask_llm sees workflow defaults (model, agent)
        with request_context():
            get_request_context().workflow_execution_id = self.execution_id
            get_request_context().current_session_id = f"wf-{self.execution_id}"
            get_request_context().current_user_id = self.user_id or ""
            get_request_context().workflow_default_model = self.model or ""
            get_request_context().workflow_agent_id = self.agent_id or ""
            # Resolve and pin a current_agent so cost logging records the right agent
            try:
                get_request_context().current_agent = AgentConfig(self.agent_id or "main")
            except Exception:
                get_request_context().current_agent = None
            try:
                interp = _WorkflowInterpreter(self._program, self)  # type: ignore
                interp.run()
                if self._cancel.is_set():
                    self.status = "cancelled"
                else:
                    self.status = "completed"
            except WorkflowError as e:
                self.status = "failed"
                self.error = f"Line {e.line}: {e}"
            except Exception as e:
                self.status = "failed"
                self.error = str(e)
            finally:
                self.finished_at = datetime.datetime.now().isoformat()
                # Compute duration
                try:
                    start_dt = datetime.datetime.fromisoformat(self.started_at) if self.started_at else None
                    end_dt = datetime.datetime.fromisoformat(self.finished_at)
                    duration_ms = int((end_dt - start_dt).total_seconds() * 1000) if start_dt else 0
                except Exception:
                    duration_ms = 0
                # Persist terminal state
                try:
                    rv = self._return_value
                    rv_str = json.dumps(rv, default=str) if rv is not None else ""
                    _workflow_history_finalize(
                        self.execution_id, self.status, self.finished_at,
                        duration_ms, self.error, rv_str,
                        json.dumps(self.steps, default=str),
                    )
                except Exception as e:
                    logging.warning(f"workflow finalize: {e}")

    def _record_step(self, line: int, kind: str, detail: str) -> None:
        self.steps.append({
            "line": line,
            "kind": kind,
            "detail": detail,
            "at": datetime.datetime.now().isoformat(),
        })
        self.current_stage_idx = len(self.steps) - 1
        self.current_stage_name = f"line {line}"

    def cancel(self) -> None:
        self._cancel.set()
        # Also unblock any pending file-upload wait
        try:
            deliver_workflow_file_answer(self.execution_id, None)
        except Exception:
            pass

    # No-op approval methods — kept so HTTP handlers can call them harmlessly.
    def approve(self) -> None: pass
    def reject(self) -> None: self.cancel()

    def to_dict(self) -> dict:
        # For UI, expose the recorded steps as "stages"
        stages = [
            {
                "name": f"L{step['line']}",
                "type": step["kind"],
                "status": "completed",
                "output": step["detail"],
                "elapsed": 0,
            }
            for step in self.steps
        ]
        # Pull final variable map from interpreter env if available
        return {
            "execution_id": self.execution_id,
            "workflow_name": self.workflow_name,
            "agent": self.agent_id,
            "model": self.model,
            "status": self.status,
            "current_stage": self.current_stage_name,
            "current_stage_idx": self.current_stage_idx,
            "total_stages": len(self.steps),
            "stages": stages,
            "steps": self.steps,
            "variables": self.variables,
            "return_value": self._return_value,
            "started_at": self.started_at,
            "finished_at": self.finished_at,
            "error": self.error,
        }


# Global workflow execution registry
_workflow_executions: dict[str, "WorkflowExecution"] = {}
_workflow_lock = threading.Lock()


def workflow_start(agent_id: str, workflow_name: str, variables: dict,
                   model: str | None = None,
                   user_id: str = "", user_display: str = "",
                   trigger_kind: str = "manual",
                   trigger_ref: str = "") -> WorkflowExecution:
    src = WorkflowEngine.get_workflow_source(agent_id, workflow_name)
    if src is None:
        raise ValueError(f"Workflow '{workflow_name}' not found for agent '{agent_id}'")
    execution = WorkflowExecution(
        src, variables, agent_id, model,
        workflow_name=workflow_name,
        user_id=user_id, user_display=user_display,
        trigger_kind=trigger_kind, trigger_ref=trigger_ref,
    )
    with _workflow_lock:
        _workflow_executions[execution.execution_id] = execution
    execution.run()
    return execution


def workflow_get_execution(execution_id: str) -> WorkflowExecution | None:
    with _workflow_lock:
        return _workflow_executions.get(execution_id)


def workflow_list_executions() -> list[dict]:
    with _workflow_lock:
        return [ex.to_dict() for ex in _workflow_executions.values()]


def workflow_cleanup_old(max_age_hours: int = 24) -> None:
    cutoff = datetime.datetime.now() - datetime.timedelta(hours=max_age_hours)
    with _workflow_lock:
        to_remove = []
        for eid, ex in _workflow_executions.items():
            if ex.status in ("completed", "failed", "cancelled") and ex.finished_at:
                try:
                    finished = datetime.datetime.fromisoformat(ex.finished_at)
                    if finished < cutoff:
                        to_remove.append(eid)
                except (ValueError, TypeError):
                    pass
        for eid in to_remove:
            del _workflow_executions[eid]


# tool_delegate_task / tool_task_status / tool_task_cancel moved to
