# --- Scheduler ---

import sqlite3

# The scheduler subsystem (DB pool, Scheduler class,
# _validate_thinking_level_for_model, tool_schedule_*) was extracted to
# engine/scheduler.py (refactor B2). Re-exported here so every existing
# caller still resolves via `brain.X` / `engine.X`:
#   - the schedule DB pool (`SCHEDULER_DB`, `_sched_db_pool`, `_sched_conn`)
#     is reached by the schedule-sharing helpers and the workflow-history
#     subsystem (both still defined below) AND by _gather_recent_schedule_history;
#   - `Scheduler` is annotated on the `_scheduler` global below and
#     instantiated by server.py as `engine._scheduler = engine.Scheduler()`;
#   - the tool functions are wired into TOOL_DISPATCH unchanged;
#   - the characterization tests target brain.Scheduler / brain._calc_next_run
#     / brain._calc_next_from_last / brain._validate_thinking_level_for_model.
from engine.scheduler import (  # noqa: E402
    SCHEDULER_DB,
    _sched_db_pool,
    _sched_conn,
    _validate_thinking_level_for_model,
    Scheduler,
    tool_schedule_list,
    tool_schedule_history,
)


# --- Schedule sharing helpers (generic visibility model) ---

def _schedule_get_row(name: str) -> dict | None:
    """Return a schedule row as a dict, or None. Used by handlers/share.py."""
    try:
        with _sched_conn() as conn:
            conn.row_factory = sqlite3.Row
            r = conn.execute("SELECT * FROM schedules WHERE name = ?", (name,)).fetchone()
            return dict(r) if r else None
    except Exception:
        return None


def _schedule_share_block(row: dict) -> dict:
    """Map a schedule row to the generic five-field sharing block. The
    schedule's `user_id` is its owner."""
    def _list(v):
        if isinstance(v, list):
            return v
        if not v:
            return []
        try:
            d = json.loads(v); return d if isinstance(d, list) else []
        except Exception:
            return []
    return {
        "owner_user_id": row.get("user_id") or "",
        "visibility": row.get("visibility") or "private",
        "owner_team_id": row.get("owner_team_id") or "",
        "extra_member_user_ids": _list(row.get("extra_member_user_ids")),
        "excluded_user_ids": _list(row.get("excluded_user_ids")),
    }


def _schedule_update_share(name: str, *, visibility=None, owner_team_id=None,
                           extra_member_user_ids=None, excluded_user_ids=None,
                           owner_user_id=None):
    sets, params = [], []
    if visibility is not None:
        sets.append("visibility = ?"); params.append(visibility)
    if owner_team_id is not None:
        sets.append("owner_team_id = ?"); params.append(owner_team_id)
    if extra_member_user_ids is not None:
        sets.append("extra_member_user_ids = ?"); params.append(json.dumps(list(extra_member_user_ids)))
    if excluded_user_ids is not None:
        sets.append("excluded_user_ids = ?"); params.append(json.dumps(list(excluded_user_ids)))
    if owner_user_id is not None:
        sets.append("user_id = ?"); params.append(owner_user_id)
    if not sets:
        return
    params.append(name)
    with _sched_conn() as conn:
        conn.execute(f"UPDATE schedules SET {', '.join(sets)} WHERE name = ?", params)
        conn.commit()


# --- Workflow run history (piggybacks on scheduler.db) ---

_WF_HIST_INIT_DONE = False


def _workflow_history_init() -> None:
    """Idempotent: create workflow_history table on first use."""
    global _WF_HIST_INIT_DONE
    if _WF_HIST_INIT_DONE:
        return
    try:
        conn = _sched_conn()
        conn.execute("""
            CREATE TABLE IF NOT EXISTS workflow_history (
                execution_id     TEXT PRIMARY KEY,
                workflow_name    TEXT NOT NULL,
                workflow_file    TEXT,
                workflow_source  TEXT,
                agent_id         TEXT NOT NULL DEFAULT 'main',
                user_id          TEXT NOT NULL DEFAULT '',
                user_display     TEXT NOT NULL DEFAULT '',
                trigger_kind     TEXT NOT NULL DEFAULT 'manual',
                trigger_ref      TEXT NOT NULL DEFAULT '',
                model            TEXT NOT NULL DEFAULT '',
                status           TEXT NOT NULL DEFAULT 'running',
                started_at       TEXT NOT NULL,
                finished_at      TEXT,
                duration_ms      INTEGER NOT NULL DEFAULT 0,
                error            TEXT,
                return_value     TEXT,
                variables_json   TEXT,
                steps_json       TEXT,
                tool_calls       INTEGER NOT NULL DEFAULT 0,
                llm_calls        INTEGER NOT NULL DEFAULT 0,
                tokens_in        INTEGER NOT NULL DEFAULT 0,
                tokens_out       INTEGER NOT NULL DEFAULT 0,
                cost_usd         REAL    NOT NULL DEFAULT 0.0
            )
        """)
        conn.execute("CREATE INDEX IF NOT EXISTS idx_wfh_workflow ON workflow_history(workflow_name, started_at DESC)")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_wfh_user     ON workflow_history(user_id, started_at DESC)")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_wfh_status   ON workflow_history(status, started_at DESC)")
        # Zombie sweep: any row marked running/pending/waiting_approval at init
        # time has lost its in-memory WorkflowExecution (we just started up).
        # Mark them cancelled so the running set reflects reality. Idempotent.
        try:
            now_iso = datetime.datetime.now().isoformat()
            cur = conn.execute("""
                UPDATE workflow_history
                SET status = 'cancelled',
                    finished_at = COALESCE(finished_at, ?),
                    error = COALESCE(NULLIF(error, ''),
                                     'Cancelled at server startup (in-memory execution lost)')
                WHERE status IN ('running', 'pending', 'waiting_approval')
            """, (now_iso,))
            swept = cur.rowcount or 0
            if swept:
                logging.info(f"workflow_history: swept {swept} zombie running rows at startup")
        except Exception as e:
            logging.warning(f"workflow_history zombie sweep: {e}")
        conn.commit()
        _WF_HIST_INIT_DONE = True
    except Exception as e:
        logging.warning(f"workflow_history init: {e}")


def _workflow_history_insert(execution_id: str, workflow_name: str, workflow_file: str,
                             workflow_source: str, agent_id: str, user_id: str,
                             user_display: str, trigger_kind: str, trigger_ref: str,
                             model: str, started_at: str, variables_json: str) -> None:
    _workflow_history_init()
    try:
        conn = _sched_conn()
        conn.execute("""
            INSERT OR REPLACE INTO workflow_history
            (execution_id, workflow_name, workflow_file, workflow_source, agent_id,
             user_id, user_display, trigger_kind, trigger_ref, model, status,
             started_at, variables_json)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'running', ?, ?)
        """, (execution_id, workflow_name, workflow_file, workflow_source, agent_id,
              user_id or "", user_display or "", trigger_kind or "manual",
              trigger_ref or "", model or "", started_at, variables_json or "{}"))
        conn.commit()
    except Exception as e:
        logging.warning(f"workflow_history insert: {e}")


def _workflow_history_finalize(execution_id: str, status: str, finished_at: str,
                               duration_ms: int, error: str | None,
                               return_value: str, steps_json: str) -> None:
    """Update terminal-state row + roll up costs from cost_log keyed by 'wf-<execution_id>'."""
    _workflow_history_init()
    # Roll up costs from cost_log
    sid = f"wf-{execution_id}"
    tool_calls = 0
    llm_calls = 0
    tokens_in = 0
    tokens_out = 0
    cost_usd = 0.0
    try:
        with _cost_conn() as cconn:
            row = cconn.execute("""
                SELECT COUNT(*) AS llm_calls,
                       COALESCE(SUM(tokens_in), 0) AS tokens_in,
                       COALESCE(SUM(tokens_out), 0) AS tokens_out,
                       COALESCE(SUM(cost_usd), 0.0) AS cost_usd
                FROM cost_log WHERE session_id = ?
            """, (sid,)).fetchone()
            if row:
                llm_calls = int(row[0] or 0)
                tokens_in = int(row[1] or 0)
                tokens_out = int(row[2] or 0)
                cost_usd = float(row[3] or 0.0)
    except Exception as e:
        logging.warning(f"workflow_history cost rollup: {e}")
    # Count tool_calls from steps_json
    try:
        steps = json.loads(steps_json) if steps_json else []
        tool_calls = sum(1 for s in steps if s.get("kind") == "call")
    except Exception:
        pass
    try:
        conn = _sched_conn()
        conn.execute("""
            UPDATE workflow_history
            SET status = ?, finished_at = ?, duration_ms = ?, error = ?,
                return_value = ?, steps_json = ?,
                tool_calls = ?, llm_calls = ?,
                tokens_in = ?, tokens_out = ?, cost_usd = ?
            WHERE execution_id = ?
        """, (status, finished_at, duration_ms, error or "", return_value or "",
              steps_json or "[]", tool_calls, llm_calls, tokens_in, tokens_out,
              cost_usd, execution_id))
        conn.commit()
    except Exception as e:
        logging.warning(f"workflow_history finalize: {e}")


def _workflow_history_list(workflow_name: str | None = None, user_id: str | None = None,
                           status: str | None = None, limit: int = 50, offset: int = 0) -> list[dict]:
    _workflow_history_init()
    try:
        conn = _sched_conn()
        conn.row_factory = sqlite3.Row
        where_parts = []
        params: list = []
        if workflow_name:
            where_parts.append("workflow_name = ?")
            params.append(workflow_name)
        if user_id:
            where_parts.append("user_id = ?")
            params.append(user_id)
        if status:
            where_parts.append("status = ?")
            params.append(status)
        where = ("WHERE " + " AND ".join(where_parts)) if where_parts else ""
        params.extend([int(limit), int(offset)])
        rows = conn.execute(f"""
            SELECT execution_id, workflow_name, workflow_file, agent_id, user_id, user_display,
                   trigger_kind, trigger_ref, model, status, started_at, finished_at,
                   duration_ms, error, return_value, tool_calls, llm_calls,
                   tokens_in, tokens_out, cost_usd
            FROM workflow_history {where}
            ORDER BY started_at DESC
            LIMIT ? OFFSET ?
        """, params).fetchall()
        return [dict(r) for r in rows]
    except Exception as e:
        logging.warning(f"workflow_history list: {e}")
        return []


def _workflow_history_get(execution_id: str) -> dict | None:
    _workflow_history_init()
    try:
        conn = _sched_conn()
        conn.row_factory = sqlite3.Row
        row = conn.execute("""
            SELECT * FROM workflow_history WHERE execution_id = ?
        """, (execution_id,)).fetchone()
        return dict(row) if row else None
    except Exception as e:
        logging.warning(f"workflow_history get: {e}")
        return None


_WF_LIVE_STATUSES = ("running", "pending", "waiting_approval")


def _workflow_history_delete_run(execution_id: str) -> dict:
    """Delete a single workflow_history row. Refuses in-flight runs — caller
    must cancel first (the cancel endpoint finalises the row). Returns a
    summary dict; idempotent (returns deleted=0 if the row is already gone).
    """
    _workflow_history_init()
    row = _workflow_history_get(execution_id)
    if not row:
        return {"status": "ok", "deleted": 0}
    if row.get("status") in _WF_LIVE_STATUSES:
        return {"error": f"Cannot delete a {row.get('status')} run; cancel it first"}
    try:
        conn = _sched_conn()
        cur = conn.execute("DELETE FROM workflow_history WHERE execution_id = ?", (execution_id,))
        conn.commit()
        return {"status": "ok", "deleted": int(cur.rowcount or 0), "execution_id": execution_id}
    except Exception as e:
        logging.warning(f"workflow_history delete_run: {e}")
        return {"error": str(e)}


def _workflow_history_delete_for_workflow(workflow_name: str,
                                          user_id: str | None = None) -> dict:
    """Purge every terminal run for a given workflow. In-flight runs are left
    intact. When `user_id` is provided, only that user's runs are deleted —
    the HTTP layer uses this for non-admin RBAC."""
    _workflow_history_init()
    try:
        conn = _sched_conn()
        params: list = [workflow_name]
        scope_clause = ""
        if user_id:
            scope_clause = " AND user_id = ?"
            params.append(user_id)
        # Build a NOT IN clause over the live statuses to avoid deleting
        # in-flight rows.
        live_placeholders = ",".join("?" * len(_WF_LIVE_STATUSES))
        params.extend(_WF_LIVE_STATUSES)
        cur = conn.execute(
            f"DELETE FROM workflow_history "
            f"WHERE workflow_name = ?{scope_clause} "
            f"AND status NOT IN ({live_placeholders})",
            params,
        )
        conn.commit()
        return {"status": "ok", "runs_removed": int(cur.rowcount or 0)}
    except Exception as e:
        logging.warning(f"workflow_history delete_for_workflow: {e}")
        return {"error": str(e)}


def _workflow_history_delete_all(user_id: str | None = None) -> dict:
    """Purge every terminal workflow run. Live runs are left intact. When
    `user_id` is provided, only that user's runs are deleted (non-admin path)."""
    _workflow_history_init()
    try:
        conn = _sched_conn()
        params: list = []
        scope_clause = ""
        if user_id:
            scope_clause = "user_id = ? AND "
            params.append(user_id)
        live_placeholders = ",".join("?" * len(_WF_LIVE_STATUSES))
        params.extend(_WF_LIVE_STATUSES)
        cur = conn.execute(
            f"DELETE FROM workflow_history "
            f"WHERE {scope_clause}status NOT IN ({live_placeholders})",
            params,
        )
        conn.commit()
        return {"status": "ok", "runs_removed": int(cur.rowcount or 0)}
    except Exception as e:
        logging.warning(f"workflow_history delete_all: {e}")
        return {"error": str(e)}



