# Regex-based detection of personal data in outgoing LLM payloads. The regex
# scanner + rule catalogue + category maps were relocated to engine/pii_ner.py
# (B3) so the regex half and the spaCy-NER half live in one module. Re-exported
# here for back-compat — every caller still resolves brain._pii_scan_text etc.
# (server.py does `import brain as engine`, so engine._pii_scan_text resolves
# through these aliases too). DELICATE rule-ordering invariants live in pii_ner.
from engine.pii_ner import (  # noqa: E402
    _pii_rules,
    _pii_scan_bare_identifiers,
    _pii_scan_text,
    PII_RULE_CATEGORIES,
    PII_DEFAULT_CATEGORY_ACTIONS,
    PII_DEFAULT_MIN_OCCURRENCES,
)


def _pii_scan_messages(messages: list[dict], max_findings: int = 100,
                       cfg: dict | None = None) -> list[dict]:
    """Scan outgoing LLM messages for PII. Only looks at user + system content
    (assistant content + tool results come from the model and aren't 'leaks'
    from the user's perspective — but we could extend if needed)."""
    if cfg is None:
        cfg = _get_gdpr_scanner_config()
    findings: list[dict] = []
    for idx, msg in enumerate(messages or []):
        role = msg.get("role")
        if role not in ("user", "system"):
            continue
        content = msg.get("content", "")
        if isinstance(content, str):
            for f in _pii_scan_text(content, max_findings=max_findings - len(findings), cfg=cfg):
                f["msg_index"] = idx
                findings.append(f)
        elif isinstance(content, list):
            for block in content:
                if isinstance(block, dict) and block.get("type") == "text":
                    for f in _pii_scan_text(block.get("text", ""), max_findings=max_findings - len(findings), cfg=cfg):
                        f["msg_index"] = idx
                        findings.append(f)
        if len(findings) >= max_findings:
            break
    return findings


def _pii_summarize(findings: list[dict]) -> dict[str, int]:
    counts: dict[str, int] = {}
    for f in findings:
        counts[f["label"]] = counts.get(f["label"], 0) + 1
    return counts


def _pii_worst_action(findings: list[dict]) -> str:
    """Return the most-severe action present in findings: block > warn > ignore.
    Assumes findings carry an 'action' field (populated by _pii_scan_text).
    """
    worst = "ignore"
    for f in findings:
        a = f.get("action") or "warn"
        if a == "block":
            return "block"
        if a == "warn" and worst != "block":
            worst = "warn"
    return worst


