# --- Context Window Management ---

DEFAULT_MAX_CONTEXT_TOKENS = 131072
COMPACT_THRESHOLD = 0.75  # compact at 75% full
KEEP_RECENT_MESSAGES = 6  # always keep the last N messages untouched (legacy fallback)
CHARS_PER_TOKEN = 4       # conservative estimate

# --- Lossless Context Manager ---

CONTEXT_DB = os.path.join(AGENTS_DIR, "main", "context.db")

_CONTEXT_CONFIG_DEFAULTS = {
    "enabled": True,
    "fresh_tail_count": 3,  # number of recent TURNS kept verbatim (not messages)
    "compact_threshold": 0.60,
    "summary_target_tokens": 1000,
    "condense_threshold": 4,
    "max_depth": 5,
    "summary_model": "",
    "summary_model_fallback": "",
    "messages_per_summary": 10,
}

_context_db_pool = threading.local()


def _context_conn():
    """Thread-local SQLite connection for the context DB."""
    conn = getattr(_context_db_pool, "conn", None)
    if conn is None:
        os.makedirs(os.path.dirname(CONTEXT_DB), exist_ok=True)
        conn = sqlite3.connect(CONTEXT_DB, timeout=10, check_same_thread=False)
        conn.execute("PRAGMA busy_timeout = 5000")
        conn.execute("PRAGMA journal_mode = WAL")
        _context_db_pool.conn = conn
    return conn


def _context_init_db():
    conn = _context_conn()
    conn.executescript("""
        CREATE TABLE IF NOT EXISTS summaries (
            id TEXT PRIMARY KEY,
            session_id TEXT NOT NULL,
            depth INTEGER NOT NULL DEFAULT 0,
            token_count INTEGER NOT NULL,
            content TEXT NOT NULL,
            parent_ids TEXT DEFAULT '[]',
            message_range_start INTEGER NOT NULL,
            message_range_end INTEGER NOT NULL,
            created_at REAL DEFAULT (strftime('%s','now'))
        );
        CREATE INDEX IF NOT EXISTS idx_summary_session ON summaries(session_id);
        CREATE INDEX IF NOT EXISTS idx_summary_depth ON summaries(session_id, depth);
        CREATE TABLE IF NOT EXISTS context_config (
            key TEXT PRIMARY KEY,
            value TEXT NOT NULL
        );
    """)
    conn.commit()


# Sentinels for the synthetic summary block assemble_context() prepends.
# Kept in sync with the literals written in ContextManager.assemble_context.
_SYNTH_SUMMARY_USER_PREFIX = "[Conversation Context]"
_SYNTH_SUMMARY_ASSISTANT_PREFIX = "I have the context from our earlier conversation."


def _count_synthetic_summary_prefix(messages: list[dict]) -> int:
    """Number of leading messages that form synthetic summary pairs from a prior
    compaction. Matches (user '[Conversation Context]…' + assistant ack) pairs at
    the head of the list; stops at the first real message. Returns an even count."""
    n = 0
    while n + 1 < len(messages):
        u, a = messages[n], messages[n + 1]
        u_txt = u.get("content") if isinstance(u.get("content"), str) else ""
        a_txt = a.get("content") if isinstance(a.get("content"), str) else ""
        if (u.get("role") == "user" and u_txt.startswith(_SYNTH_SUMMARY_USER_PREFIX)
                and a.get("role") == "assistant"
                and a_txt.startswith(_SYNTH_SUMMARY_ASSISTANT_PREFIX)):
            n += 2
        else:
            break
    return n


class ContextManager:
    """Lossless context management with DAG-based hierarchical summarization."""

    def __init__(self):
        _context_init_db()

    def get_config(self) -> dict:
        cfg = dict(_CONTEXT_CONFIG_DEFAULTS)
        try:
            conn = _context_conn()
            rows = conn.execute("SELECT key, value FROM context_config").fetchall()
            for k, v in rows:
                if k in cfg:
                    # Coerce types
                    default = _CONTEXT_CONFIG_DEFAULTS[k]
                    if isinstance(default, bool):
                        cfg[k] = v.lower() in ("true", "1", "yes")
                    elif isinstance(default, int):
                        cfg[k] = int(v)
                    elif isinstance(default, float):
                        cfg[k] = float(v)
                    else:
                        cfg[k] = v
        except Exception:
            pass
        return cfg

    def save_config(self, updates: dict):
        conn = _context_conn()
        for k, v in updates.items():
            if k in _CONTEXT_CONFIG_DEFAULTS:
                conn.execute(
                    "INSERT OR REPLACE INTO context_config (key, value) VALUES (?, ?)",
                    (k, str(v))
                )
        conn.commit()

    def _resolve_summary_model(self) -> tuple[str | None, str | None]:
        """Return (primary_model, fallback_model) for context summarization."""
        cfg = self.get_config()
        primary = cfg.get("summary_model") or ""
        fallback = cfg.get("summary_model_fallback") or ""
        p, f = _resolve_model_with_fallback(primary, fallback)
        return p, f

    def _extract_message_text(self, msg: dict) -> str:
        """Extract plain text from a message (handles string and block content)."""
        role = msg.get("role", "unknown")
        content = msg.get("content", "")
        if isinstance(content, str):
            return f"{role}: {content}"
        elif isinstance(content, list):
            parts = []
            for block in content:
                if isinstance(block, dict):
                    if block.get("type") == "text":
                        parts.append(block.get("text", ""))
                    elif block.get("type") == "tool_use":
                        parts.append(f"[Tool: {block.get('name', '')}]")
                    elif block.get("type") == "tool_result":
                        c = block.get("content", "")
                        parts.append(f"[Result: {str(c)[:300]}]")
            return f"{role}: {' '.join(parts)}"
        return f"{role}: {str(content)[:500]}"

    def summarize_chunk(self, messages: list[dict], session_id: str,
                        range_start: int, range_end: int,
                        model: str, api_key: str, base_url: str,
                        fallback_model: str | None = None) -> str | None:
        """Summarize a chunk of messages into a leaf summary (depth 0). Returns summary ID."""
        text_parts = [self._extract_message_text(m) for m in messages]
        source_text = "\n".join(text_parts)

        summary_text = None
        try:
            # GDPR policy gate. The summarised chunk is verbatim chat
            # history — real names / emails / IBANs land here. Pseudonymise
            # before sending to the cloud, deanon the summary before it
            # gets persisted into the context DAG.
            _sum_deanon = _identity_deanon
            _wire_source = source_text
            try:
                model, (_pii_source,), _sum_deanon = gdpr_pick_model_for_background(
                    model, [source_text], purpose="lcm_summarize")
                _wire_source = _pii_source
            except GDPRBlockedError:
                # Cannot summarise this chunk under admin policy; fall
                # through to the truncation fallback below.
                _wire_source = None
            if _wire_source is not None:
                from handlers import sidecar_proxy as _sidecar_proxy
                _msg = [{"role": "user", "content": (
                    "Summarize this conversation segment concisely. Preserve: key facts, decisions, "
                    "file paths, commands run, errors encountered, and task context. "
                    "Be factual and specific, not vague. ~200-300 words.\n\n" + _wire_source
                )}]
                _sys = "You are a precise conversation summarizer. Output only the summary."
                _res = _sidecar_proxy.background_call(
                    messages=_msg, model=model, system_prompt=_sys,
                    session_id=session_id, cost_purpose="lcm_summarize", max_tokens=2000,
                )
                if _res.get("error") and fallback_model and fallback_model != model:
                    # Re-gate so the fallback model picks up its own swap
                    # decision (it may already be local, in which case the
                    # gate is a no-op).
                    _fb_model = fallback_model
                    _fb_deanon = _sum_deanon
                    _fb_wire = _wire_source
                    try:
                        _fb_model, (_fb_pii,), _fb_deanon = gdpr_pick_model_for_background(
                            fallback_model, [source_text], purpose="lcm_summarize_fb")
                        _fb_wire = _fb_pii
                    except GDPRBlockedError:
                        _fb_wire = None
                    if _fb_wire is not None:
                        _msg = [{"role": "user", "content": (
                            "Summarize this conversation segment concisely. Preserve: key facts, decisions, "
                            "file paths, commands run, errors encountered, and task context. "
                            "Be factual and specific, not vague. ~200-300 words.\n\n" + _fb_wire
                        )}]
                        _res = _sidecar_proxy.background_call(
                            messages=_msg, model=_fb_model, system_prompt=_sys,
                            session_id=session_id, cost_purpose="lcm_summarize", max_tokens=2000,
                        )
                        _sum_deanon = _fb_deanon
                result = _sum_deanon(_res.get("reply") or "")
                if result and not _res.get("error"):
                    summary_text = result.strip()
        except Exception:
            pass

        if not summary_text:
            # Fallback: truncation
            summary_text = source_text[:3000]
            if len(source_text) > 3000:
                summary_text += "\n...(truncated)"

        sid = hashlib.sha256(f"{session_id}:{range_start}:{range_end}:{time.time()}".encode()).hexdigest()[:16]
        token_count = len(summary_text) // CHARS_PER_TOKEN

        conn = _context_conn()
        conn.execute(
            "INSERT OR REPLACE INTO summaries (id, session_id, depth, token_count, content, parent_ids, message_range_start, message_range_end) "
            "VALUES (?, ?, 0, ?, ?, '[]', ?, ?)",
            (sid, session_id, token_count, summary_text, range_start, range_end)
        )
        conn.commit()
        return sid

    def condense(self, session_id: str) -> bool:
        """Merge same-depth summaries into higher-depth summaries. Returns True if any merged."""
        cfg = self.get_config()
        threshold = cfg.get("condense_threshold", 4)
        max_depth = cfg.get("max_depth", 5)
        conn = _context_conn()
        merged_any = False

        for depth in range(max_depth):
            rows = conn.execute(
                "SELECT id, content, token_count, message_range_start, message_range_end "
                "FROM summaries WHERE session_id = ? AND depth = ? ORDER BY message_range_start",
                (session_id, depth)
            ).fetchall()
            if len(rows) < threshold:
                continue

            # Merge all same-depth summaries into one higher-depth summary
            combined_text = "\n\n---\n\n".join(r[1] for r in rows)
            parent_ids = [r[0] for r in rows]
            range_start = rows[0][3]
            range_end = rows[-1][4]

            # Summarize the combined text
            c_model, c_fallback = self._resolve_summary_model()
            condensed_text = None
            if c_model:
                try:
                    # GDPR policy gate: combined_text holds prior summaries
                    # already derived from chat history, so it still carries
                    # whatever PII survived the summarise step.
                    _cd_deanon = _identity_deanon
                    _wire_combined = combined_text
                    try:
                        c_model, (_pii_combined,), _cd_deanon = gdpr_pick_model_for_background(
                            c_model, [combined_text], purpose="lcm_condense")
                        _wire_combined = _pii_combined
                    except GDPRBlockedError:
                        _wire_combined = None
                    if _wire_combined is not None:
                        from handlers import sidecar_proxy as _sidecar_proxy
                        _msg = [{"role": "user", "content": (
                            f"Condense these {len(rows)} conversation summaries into one cohesive summary. "
                            "Preserve all key facts, decisions, and context. ~300-500 words.\n\n" + _wire_combined
                        )}]
                        _sys = "You are a precise summarizer. Output only the condensed summary."
                        _res = _sidecar_proxy.background_call(
                            messages=_msg, model=c_model, system_prompt=_sys,
                            session_id=session_id, cost_purpose="lcm_condense", max_tokens=3000,
                        )
                        if _res.get("error") and c_fallback and c_fallback != c_model:
                            _fb_model = c_fallback
                            _fb_deanon = _cd_deanon
                            _fb_wire = _wire_combined
                            try:
                                _fb_model, (_fb_pii,), _fb_deanon = gdpr_pick_model_for_background(
                                    c_fallback, [combined_text], purpose="lcm_condense_fb")
                                _fb_wire = _fb_pii
                            except GDPRBlockedError:
                                _fb_wire = None
                            if _fb_wire is not None:
                                _msg = [{"role": "user", "content": (
                                    f"Condense these {len(rows)} conversation summaries into one cohesive summary. "
                                    "Preserve all key facts, decisions, and context. ~300-500 words.\n\n" + _fb_wire
                                )}]
                                _res = _sidecar_proxy.background_call(
                                    messages=_msg, model=_fb_model, system_prompt=_sys,
                                    session_id=session_id, cost_purpose="lcm_condense", max_tokens=3000,
                                )
                                _cd_deanon = _fb_deanon
                        result = _cd_deanon(_res.get("reply") or "")
                        if result and not _res.get("error"):
                            condensed_text = result.strip()
                except Exception:
                    pass

            if not condensed_text:
                condensed_text = combined_text[:4000]

            new_id = hashlib.sha256(f"condense:{session_id}:{depth+1}:{time.time()}".encode()).hexdigest()[:16]
            token_count = len(condensed_text) // CHARS_PER_TOKEN

            conn.execute(
                "INSERT OR REPLACE INTO summaries (id, session_id, depth, token_count, content, parent_ids, message_range_start, message_range_end) "
                "VALUES (?, ?, ?, ?, ?, ?, ?, ?)",
                (new_id, session_id, depth + 1, token_count, condensed_text,
                 json.dumps(parent_ids), range_start, range_end)
            )
            # Remove merged lower-depth summaries
            conn.executemany("DELETE FROM summaries WHERE id = ?", [(pid,) for pid in parent_ids])
            conn.commit()
            merged_any = True

        return merged_any

    def assemble_context(self, session_id: str, messages: list[dict],
                         system_prompt: str = "", max_tokens: int = DEFAULT_MAX_CONTEXT_TOKENS,
                         fresh_tail_count: int = None) -> list[dict]:
        """Assemble context: summaries + fresh tail within token budget."""
        cfg = self.get_config()
        if fresh_tail_count is None:
            # Config is in TURNS; assembly works in messages (≈2 per turn).
            fresh_tail_count = cfg.get("fresh_tail_count", 3) * 2

        # Ensure we don't exceed available messages
        fresh_tail_count = min(fresh_tail_count, len(messages))
        fresh_tail = messages[-fresh_tail_count:] if fresh_tail_count > 0 else []

        # Calculate token budget
        system_tokens = len(system_prompt) // CHARS_PER_TOKEN if system_prompt else 0
        fresh_tokens = sum(_estimate_tokens_message(m) for m in fresh_tail)
        response_reserve = 4000  # reserve tokens for response
        budget = max_tokens - system_tokens - fresh_tokens - response_reserve

        if budget <= 0:
            return fresh_tail

        # Load summaries, highest depth first
        conn = _context_conn()
        rows = conn.execute(
            "SELECT id, depth, token_count, content, message_range_start, message_range_end "
            "FROM summaries WHERE session_id = ? ORDER BY depth DESC, message_range_start ASC",
            (session_id,)
        ).fetchall()

        if not rows:
            return fresh_tail

        # Fill budget with summaries
        summary_parts = []
        used_tokens = 0
        for row in rows:
            sid, depth, tc, content, rs, re_ = row
            if used_tokens + tc > budget:
                continue
            summary_parts.append({
                "id": sid, "depth": depth, "tokens": tc,
                "content": content, "range": f"messages {rs}-{re_}"
            })
            used_tokens += tc

        if not summary_parts:
            return fresh_tail

        # Sort by message range for chronological order
        summary_parts.sort(key=lambda s: s["range"])

        # Build summary message
        summary_text = "## Compacted Conversation History\n\n"
        summary_text += "The following summaries cover earlier parts of this conversation. "
        summary_text += "Use context_search, context_detail, or context_recall tools to access original details.\n\n"
        for s in summary_parts:
            summary_text += f"### Summary (depth {s['depth']}, {s['range']})\n{s['content']}\n\n"

        assembled = [
            {"role": "user", "content": f"[Conversation Context]\n{summary_text}"},
            {"role": "assistant", "content": "I have the context from our earlier conversation. I can use context_search, context_detail, or context_recall to access specific details if needed."},
        ]
        assembled.extend(fresh_tail)
        return assembled

    def check_and_compact(self, messages: list[dict], session_id: str,
                          model: str, api_key: str, base_url: str,
                          system_prompt: str = "",
                          max_tokens: int = DEFAULT_MAX_CONTEXT_TOKENS,
                          force: bool = False) -> tuple[list[dict], bool]:
        """Check if compaction needed and perform hierarchical summarization."""
        cfg = self.get_config()
        if not cfg.get("enabled", True) and not force:
            return messages, False

        estimated = _estimate_conversation_tokens(messages, system_prompt)
        if not force:
            threshold_pct = cfg.get("compact_threshold", 0.75)
            threshold = int(max_tokens * threshold_pct)
            if estimated < threshold:
                return messages, False

        if not messages:
            return messages, False

        # On re-compaction, session.messages begins with the synthetic summary
        # block from the previous run (a "[Conversation Context]" user message +
        # its assistant ack). Those are a *render* of context.db summary rows,
        # not real turns — strip them so they're neither re-summarized nor counted
        # as turns. assemble_context rebuilds the rendered block from the DB rows
        # (old + new), so keeping the old summaries is automatic ("append new,
        # keep old" → stacked summary blocks).
        prefix = _count_synthetic_summary_prefix(messages)
        real_msgs = messages[prefix:]

        # Whole-turn boundaries. A turn starts at each user message; compressing
        # always cuts at a turn boundary so a user+assistant pair is never split
        # across the summary/verbatim line (splitting it strands the answer from
        # its question — the bug behind the "useless summary" on 1-turn chats).
        turn_starts = [i for i, m in enumerate(real_msgs) if m.get("role") == "user"]
        n_turns = len(turn_starts)
        if len(real_msgs) <= 1 or n_turns <= 1:
            # Single (or partial) turn: nothing older to keep verbatim, and the
            # pair must not be split — compress the whole thing into one summary.
            fresh_tail_count = 0
            to_compress = real_msgs
        else:
            # fresh_tail_count is a TURN count.
            fresh_tail_turns = cfg.get("fresh_tail_count", 16)
            if n_turns > fresh_tail_turns:
                # Long chat: keep the last `fresh_tail_turns` turns verbatim,
                # compress everything older.
                compress_turns = n_turns - fresh_tail_turns
            else:
                # Short chat (turns ≤ fresh_tail): 50% rule. Compress
                # floor(turns / 2); on an odd turn count the half falls to
                # the kept side — 3 turns → compress 1, keep 2.
                compress_turns = max(1, n_turns // 2)
            boundary = turn_starts[compress_turns]  # first kept message
            fresh_tail_count = len(real_msgs) - boundary
            to_compress = real_msgs[:boundary]

        if not to_compress:
            # Nothing new to compress (e.g. all real turns fit in the fresh tail).
            # Re-render existing summaries + the current tail.
            return self.assemble_context(session_id, messages, system_prompt, max_tokens,
                                         fresh_tail_count=fresh_tail_count), True

        # New summary rows are numbered AFTER any existing rows so assemble_context
        # (sorted by message_range_start) renders them in chronological order:
        # SUMMARY(turns 1-7) then SUMMARY(turns 8-17). The range numbers only drive
        # sort order + get_detail's best-effort lookup; they need not align with
        # live message indices (the live list was replaced by the prior compaction).
        conn = _context_conn()
        existing = conn.execute(
            "SELECT MAX(message_range_end) FROM summaries WHERE session_id = ?",
            (session_id,)
        ).fetchone()
        range_base = existing[0] if existing and existing[0] else 0

        msgs_per_summary = min(cfg.get("messages_per_summary", 10), len(to_compress))

        # Use summary model (Gemini Flash default, Haiku fallback)
        summary_model, summary_model_fallback = self._resolve_summary_model()
        summary_model = summary_model or model
        summary_model_fallback = summary_model_fallback or model

        pct = int(estimated / max_tokens * 100)
        logging.info(f"Context {pct}% full (~{estimated:,} tokens), creating hierarchical summaries...")

        # Create leaf summaries in chunks
        for i in range(0, len(to_compress), msgs_per_summary):
            chunk = to_compress[i:i + msgs_per_summary]
            range_start = range_base + i
            range_end = range_base + i + len(chunk)
            self.summarize_chunk(chunk, session_id, range_start, range_end,
                                 summary_model, api_key, base_url,
                                 fallback_model=summary_model_fallback)

        # No condensation: each compaction's summary block stays a separate,
        # chronologically-ordered block (SUMMARY 1-7, then SUMMARY 8-17, …) so
        # the rendered history reads as distinct eras rather than collapsing into
        # one merged summary. (condense() is retained but no longer invoked.)

        # Assemble final context. Keep the recent turns verbatim (fresh tail) and
        # only replace older turns with summaries — even when force=True. The manual
        # ✂️ trigger reclaims budget; it shouldn't obliterate the live conversation.
        assembled = self.assemble_context(session_id, messages, system_prompt, max_tokens,
                                          fresh_tail_count=fresh_tail_count)
        new_estimated = _estimate_conversation_tokens(assembled, system_prompt)

        # Fallback: if keeping the fresh tail still leaves us above threshold, drop
        # the tail entirely and assemble summaries-only (the old force behavior).
        threshold = int(max_tokens * cfg.get("compact_threshold", 0.75))
        if new_estimated >= threshold and fresh_tail_count > 0:
            logging.info(f"Still {int(new_estimated / max_tokens * 100)}% after tail-preserving "
                         f"compaction; dropping fresh tail.")
            assembled = self.assemble_context(session_id, messages, system_prompt, max_tokens,
                                              fresh_tail_count=0)
            new_estimated = _estimate_conversation_tokens(assembled, system_prompt)

        new_pct = int(new_estimated / max_tokens * 100)
        logging.info(f"Compacted: {pct}% → {new_pct}% (~{new_estimated:,} tokens)")

        return assembled, True

    def search(self, session_id: str, query: str, regex: bool = False, limit: int = 10) -> list[dict]:
        """Search original messages in ChatDB by keyword/regex."""
        results = []
        try:
            from server import _db_conn as chat_db_conn
            conn = chat_db_conn()
            conn.row_factory = sqlite3.Row
            if regex:
                # SQLite doesn't support regex natively, use LIKE as fallback
                rows = conn.execute(
                    "SELECT id, role, content, created_at FROM messages WHERE session_id = ? AND content LIKE ? ORDER BY id LIMIT ?",
                    (session_id, f"%{query}%", limit)
                ).fetchall()
            else:
                rows = conn.execute(
                    "SELECT id, role, content, created_at FROM messages WHERE session_id = ? AND content LIKE ? ORDER BY id LIMIT ?",
                    (session_id, f"%{query}%", limit)
                ).fetchall()
            for r in rows:
                content = r["content"]
                # Extract snippet around match
                idx = content.lower().find(query.lower())
                if idx >= 0:
                    start = max(0, idx - 80)
                    end = min(len(content), idx + len(query) + 120)
                    snippet = ("..." if start > 0 else "") + content[start:end] + ("..." if end < len(content) else "")
                else:
                    snippet = content[:200]
                results.append({
                    "message_id": r["id"],
                    "role": r["role"],
                    "snippet": snippet,
                    "timestamp": r["created_at"],
                })
        except Exception as e:
            results.append({"error": str(e)})
        return results

    def get_detail(self, summary_id: str) -> dict:
        """Get a summary and its original messages."""
        conn = _context_conn()
        row = conn.execute(
            "SELECT * FROM summaries WHERE id = ?", (summary_id,)
        ).fetchone()
        if not row:
            return {"error": f"Summary {summary_id} not found"}

        summary = {
            "id": row[0], "session_id": row[1], "depth": row[2],
            "token_count": row[3], "content": row[4],
            "parent_ids": json.loads(row[5] or "[]"),
            "message_range": f"{row[6]}-{row[7]}",
        }

        # Load original messages from ChatDB
        try:
            from server import _db_conn as chat_db_conn
            cconn = chat_db_conn()
            cconn.row_factory = sqlite3.Row
            msgs = cconn.execute(
                "SELECT id, role, content FROM messages WHERE session_id = ? AND id >= ? AND id <= ? ORDER BY id",
                (row[1], row[6], row[7])
            ).fetchall()
            summary["original_messages"] = [{"id": m["id"], "role": m["role"], "content": m["content"][:500]} for m in msgs]
        except Exception:
            summary["original_messages"] = []

        return summary

    def recall(self, session_id: str, query: str,
               model: str, api_key: str, base_url: str) -> str:
        """Deep recall: search summaries and original messages, then answer with a focused sub-query."""
        # Find relevant summaries
        conn = _context_conn()
        conn.row_factory = sqlite3.Row
        rows = conn.execute(
            "SELECT id, content, message_range_start, message_range_end FROM summaries WHERE session_id = ? ORDER BY depth DESC",
            (session_id,)
        ).fetchall()

        relevant_context = []
        for r in rows:
            if query.lower() in r["content"].lower():
                relevant_context.append(r["content"])

        # Also search original messages
        msg_results = self.search(session_id, query, limit=5)
        for mr in msg_results:
            if "snippet" in mr:
                relevant_context.append(f"[{mr['role']}]: {mr['snippet']}")

        if not relevant_context:
            return f"No relevant context found for: {query}"

        context_text = "\n\n---\n\n".join(relevant_context[:10])
        r_model, r_fallback = self._resolve_summary_model()
        r_model = r_model or model

        try:
            # GDPR policy gate: scan both the assembled context AND the
            # query. The query may name a person ("what did Alice say
            # about…"); the context certainly carries history-PII.
            _rc_deanon = _identity_deanon
            _wire_query = query
            _wire_ctx = context_text
            try:
                r_model, (_pii_query, _pii_ctx), _rc_deanon = gdpr_pick_model_for_background(
                    r_model, [query, context_text], purpose="lcm_recall")
                _wire_query = _pii_query
                _wire_ctx = _pii_ctx
            except GDPRBlockedError:
                return f"Recall blocked by GDPR policy for: {query}"
            from handlers import sidecar_proxy as _sidecar_proxy
            _msg = [{"role": "user", "content": (
                f"Based on this conversation history, answer the following query precisely:\n\n"
                f"**Query:** {_wire_query}\n\n**Context:**\n{_wire_ctx}"
            )}]
            _sys = "Answer based only on the provided context. Be specific and cite details."
            _res = _sidecar_proxy.background_call(
                messages=_msg, model=r_model, system_prompt=_sys,
                session_id=session_id, cost_purpose="lcm_recall", max_tokens=2000,
            )
            if _res.get("error") and r_fallback and r_fallback != r_model:
                _fb_model = r_fallback
                _fb_deanon = _rc_deanon
                _fb_q = _wire_query
                _fb_ctx = _wire_ctx
                try:
                    _fb_model, (_fb_pq, _fb_pc), _fb_deanon = gdpr_pick_model_for_background(
                        r_fallback, [query, context_text], purpose="lcm_recall_fb")
                    _fb_q = _fb_pq
                    _fb_ctx = _fb_pc
                except GDPRBlockedError:
                    return f"Recall blocked by GDPR policy for: {query}"
                _msg = [{"role": "user", "content": (
                    f"Based on this conversation history, answer the following query precisely:\n\n"
                    f"**Query:** {_fb_q}\n\n**Context:**\n{_fb_ctx}"
                )}]
                _res = _sidecar_proxy.background_call(
                    messages=_msg, model=_fb_model, system_prompt=_sys,
                    session_id=session_id, cost_purpose="lcm_recall", max_tokens=2000,
                )
                _rc_deanon = _fb_deanon
            result = _rc_deanon(_res.get("reply") or "")
            if result and not _res.get("error"):
                return result.strip()
        except Exception as e:
            return f"Recall failed: {e}"

        return f"Could not generate answer for: {query}"

    def get_stats(self, session_id: str) -> dict:
        """Get context stats for a session."""
        conn = _context_conn()
        rows = conn.execute(
            "SELECT depth, COUNT(*), SUM(token_count) FROM summaries WHERE session_id = ? GROUP BY depth",
            (session_id,)
        ).fetchall()
        depth_stats = {r[0]: {"count": r[1], "tokens": r[2]} for r in rows}
        total_summaries = sum(s["count"] for s in depth_stats.values())
        total_tokens = sum(s["tokens"] for s in depth_stats.values())
        return {
            "session_id": session_id,
            "total_summaries": total_summaries,
            "total_summary_tokens": total_tokens,
            "depth_distribution": depth_stats,
            "config": self.get_config(),
        }


_context_manager: ContextManager | None = None


def _estimate_tokens_str(text: str) -> int:
    """Estimate token count for a string."""
    return max(1, len(text) // CHARS_PER_TOKEN)


def _estimate_tokens_message(msg: dict) -> int:
    """Estimate token count for a single message (any format)."""
    content = msg.get("content", "")
    if isinstance(content, str):
        return _estimate_tokens_str(content) + 4  # role overhead
    elif isinstance(content, list):
        # Anthropic-style content blocks (text, tool_use, tool_result, etc.)
        total = 4
        for block in content:
            if isinstance(block, dict):
                if block.get("type") == "text":
                    total += _estimate_tokens_str(block.get("text", ""))
                elif block.get("type") == "tool_use":
                    total += _estimate_tokens_str(json.dumps(block.get("input", {}))) + 20
                elif block.get("type") == "tool_result":
                    total += _estimate_tokens_str(str(block.get("content", "")))
                else:
                    total += _estimate_tokens_str(json.dumps(block))
            elif isinstance(block, str):
                total += _estimate_tokens_str(block)
        return total
    return 10


def _estimate_conversation_tokens(messages: list[dict], system_prompt: str = "") -> int:
    """Estimate total token count for the full conversation."""
    total = _estimate_tokens_str(system_prompt) if system_prompt else 0
    for msg in messages:
        total += _estimate_tokens_message(msg)
    return total


# --- Task cancellation ---

class TaskCancelled(Exception):
    """Raised when the user presses Escape to cancel the current task."""
    pass


class CancelToken:
    """Simple cancellation token — start/stop are no-ops; cancel() flips an Event."""

    def __init__(self):
        self._cancelled = threading.Event()

    @property
    def cancelled(self) -> bool:
        return self._cancelled.is_set()

    def cancel(self):
        self._cancelled.set()

    def start(self):
        pass  # No-op — no background thread needed

    def stop(self):
        pass  # No-op

_gdpr_scanner_cache: dict | None = None
_gdpr_scanner_cache_time: float = 0.0


# PII_RULE_CATEGORIES + PII_DEFAULT_CATEGORY_ACTIONS moved to engine/pii_ner.py
# (B3). Re-exported at the top of the GDPR section above; referenced here as
# module globals via that import. Mirrored in web/index.html PIIScanner.


def _get_gdpr_scanner_config() -> dict:
    """Read gdpr_scanner config block from config.json. 30s cache.

    Shape:
      {"enabled": bool,                  # master on/off (default True)
       "server_log": bool,               # audit.db entries on findings (default True)
       "server_block": bool,             # master switch for "block" actions (default False)
                                         #   false → block actions downgrade to warn (back-compat)
                                         #   true  → block actions refuse unless model is local
       "default_local_fallback_model": str,
       "background_pii_action": str,     # anonymise | swap_to_local | abort  (default anonymise)
                                         # Policy for non-interactive LLM calls when PII is found.
       "background_anonymise_fail_action": str,  # swap_to_local | abort  (default swap_to_local)
                                         # What to do when pseudonymisation itself fails.
       "categories": {<cat>: {"action": "ignore|warn|block"}},
       "rule_overrides": {<rule_id>: "ignore|warn|block"},
       "email_allowlist": [str, ...]}    # full addresses or "@domain" patterns
    """
    global _gdpr_scanner_cache, _gdpr_scanner_cache_time
    now = time.time()
    if _gdpr_scanner_cache is not None and (now - _gdpr_scanner_cache_time) < 30:
        return _gdpr_scanner_cache
    cfg = {
        "enabled": True, "server_log": True, "server_block": False,
        "default_local_fallback_model": "",
        "background_pii_action": "anonymise",
        "background_anonymise_fail_action": "swap_to_local",
        "categories": {cat: {"action": act} for cat, act in PII_DEFAULT_CATEGORY_ACTIONS.items()},
        "rule_overrides": {},
        # Per-rule minimum DISTINCT occurrences before a rule fires (see
        # PII_DEFAULT_MIN_OCCURRENCES). Seeded from defaults; admin overrides
        # merge over them. Default 1 for any rule not present.
        "min_occurrences": dict(PII_DEFAULT_MIN_OCCURRENCES),
        "email_allowlist": [],
    }
    cfg_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), "config.json")
    try:
        with open(cfg_path) as f:
            loaded = json.load(f).get("gdpr_scanner") or {}
        for k in ("enabled", "server_log", "server_block"):
            if k in loaded:
                cfg[k] = bool(loaded[k])
        if "default_local_fallback_model" in loaded:
            cfg["default_local_fallback_model"] = str(loaded["default_local_fallback_model"] or "")
        if loaded.get("background_pii_action") in ("anonymise", "swap_to_local", "abort"):
            cfg["background_pii_action"] = loaded["background_pii_action"]
        if loaded.get("background_anonymise_fail_action") in ("swap_to_local", "abort"):
            cfg["background_anonymise_fail_action"] = loaded["background_anonymise_fail_action"]
        cats_in = loaded.get("categories") or {}
        if isinstance(cats_in, dict):
            for cat, entry in cats_in.items():
                if cat not in cfg["categories"]:
                    continue
                if isinstance(entry, dict) and entry.get("action") in ("ignore", "warn", "block"):
                    cfg["categories"][cat]["action"] = entry["action"]
                elif isinstance(entry, str) and entry in ("ignore", "warn", "block"):
                    cfg["categories"][cat]["action"] = entry
        ovr_in = loaded.get("rule_overrides") or {}
        if isinstance(ovr_in, dict):
            for rid, act in ovr_in.items():
                if act in ("ignore", "warn", "block") and rid in PII_RULE_CATEGORIES:
                    cfg["rule_overrides"][rid] = act
        mo_in = loaded.get("min_occurrences") or {}
        if isinstance(mo_in, dict):
            for rid, n in mo_in.items():
                if rid in PII_RULE_CATEGORIES:
                    try:
                        cfg["min_occurrences"][rid] = max(1, int(n))
                    except (TypeError, ValueError):
                        pass
        al_in = loaded.get("email_allowlist") or []
        if isinstance(al_in, list):
            cfg["email_allowlist"] = [str(e).strip().lower() for e in al_in
                                      if isinstance(e, str) and e.strip()]
    except (OSError, json.JSONDecodeError):
        pass
    _gdpr_scanner_cache = cfg
    _gdpr_scanner_cache_time = now
    return cfg


def _pii_effective_action(rule_id: str, cfg: dict | None = None) -> str:
    """Return effective action for a rule_id — 'ignore', 'warn', or 'block'.

    Precedence: rule_overrides[rule_id] > categories[cat].action > default.
    When `server_block` is false, any 'block' is downgraded to 'warn' so the
    master switch stays meaningful.
    """
    if cfg is None:
        cfg = _get_gdpr_scanner_config()
    ovr = (cfg.get("rule_overrides") or {}).get(rule_id)
    if ovr in ("ignore", "warn", "block"):
        action = ovr
    else:
        cat = PII_RULE_CATEGORIES.get(rule_id, "personal")
        cat_cfg = (cfg.get("categories") or {}).get(cat) or {}
        action = cat_cfg.get("action") or PII_DEFAULT_CATEGORY_ACTIONS.get(cat, "warn")
    if action == "block" and not cfg.get("server_block", False):
        action = "warn"
    return action


def _pii_min_occurrences(rule_id: str, cfg: dict | None = None) -> int:
    """Minimum DISTINCT occurrences a rule needs before it fires for a document.
    Resolves config `min_occurrences[rule_id]` → PII_DEFAULT_MIN_OCCURRENCES →
    1. Always ≥1."""
    if cfg is None:
        cfg = _get_gdpr_scanner_config()
    mo = (cfg.get("min_occurrences") or {}).get(rule_id)
    if mo is None:
        mo = PII_DEFAULT_MIN_OCCURRENCES.get(rule_id, 1)
    try:
        return max(1, int(mo))
    except (TypeError, ValueError):
        return 1


def _pii_email_allowed(email: str, allowlist: list[str]) -> bool:
    """True if the email matches the allowlist. Entries starting with '@' are
    treated as domain patterns (any address at that domain). Case-insensitive."""
    if not email or not allowlist:
        return False
    e = email.strip().lower()
    for pat in allowlist:
        p = pat.strip().lower()
        if not p:
            continue
        if p.startswith("@"):
            if e.endswith(p):
                return True
        elif e == p:
            return True
    return False


def is_model_local(model_id: str) -> bool:
    """Return True iff the model's provider has `is_local: true` set.

    Source of truth is the provider's `is_local` flag in config.json
    (`providers.<name>.is_local`). No URL heuristic — CLIProxyAPI runs on
    localhost but proxies to cloud models, so URL alone is unsafe for PII /
    quota routing decisions.

    Note: `resolve_provider_for_model` only returns
    `{api_key, base_url, provider_name}`, so we read the provider's
    `is_local` directly from config.json by name. 30s cached.
    """
    if not model_id:
        return False
    try:
        prov = resolve_provider_for_model(model_id)
        pname = (prov or {}).get("provider_name", "") if prov else ""
        if not pname or pname == "default":
            return False
        prov_cfg = _get_provider_config(pname)
        return bool(prov_cfg.get("is_local", False))
    except Exception:
        return False


_providers_cache: dict[str, dict] | None = None
_providers_cache_time: float = 0.0


def _get_provider_config(name: str) -> dict:
    """Return the providers.<name> entry from config.json. 30s cached.

    Lightweight helper for callers that need provider-level flags (is_local
    today; add more as needed) without going through the cred-resolution
    path (which intentionally returns only api_key + base_url + name)."""
    global _providers_cache, _providers_cache_time
    now = time.time()
    if _providers_cache is None or (now - _providers_cache_time) > 30:
        cfg_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), "config.json")
        try:
            with open(cfg_path) as f:
                _providers_cache = json.load(f).get("providers", {}) or {}
        except (OSError, json.JSONDecodeError):
            _providers_cache = {}
        _providers_cache_time = now
    return _providers_cache.get(name) or {}


def _invalidate_providers_cache():
    """Called from server.py when provider config changes."""
    global _providers_cache, _providers_cache_time
    _providers_cache = None
    _providers_cache_time = 0.0


def _invalidate_gdpr_cache():
    """Called from server.py when gdpr_scanner config changes."""
    global _gdpr_scanner_cache, _gdpr_scanner_cache_time
    _gdpr_scanner_cache = None
    _gdpr_scanner_cache_time = 0.0


class GDPRBlockedError(RuntimeError):
    """Raised by gdpr_pick_model_for_background when PII is detected, the
    server is configured in hard-block mode, and no safe local route exists.

    Callers catch this and decide what to skip (e.g. drop the background call,
    return a static summary, emit a delegate error). Not raised for the main
    chat path — that surface has its own RuntimeError branch with a different
    message aimed at the end user.
    """


class GDPRSkipError(GDPRBlockedError):
    """Raised when `gdpr_scanner.background_pii_action == 'skip'` and PII is
    found on a non-interactive (background) call to a cloud model.

    'skip' means: don't make the call, succeed empty — a deliberate no-op, NOT
    an error. Subclasses GDPRBlockedError so the ~20 existing
    `except GDPRBlockedError:` sites catch it for free and soft-return (None /
    empty / fallback) with zero per-site changes — the same subclass trick
    ClassificationBlockedError uses. Sites that map a block to an error status
    (background tasks, KG extraction) add a narrow `except GDPRSkipError`
    BEFORE their GDPRBlockedError catch to record it as 'skipped' rather than
    'error' (so it doesn't loop or trip a broken-model alarm)."""


def _identity_deanon(text):
    """No-op de-anonymise used when no anonymisation happened."""
    return text


def gdpr_pick_model_for_background(model: str, texts, purpose: str = ""):
    """Decide model + (optionally) pseudonymise inputs for a background call.

    Returns a 3-tuple: `(model, transformed_texts, deanon_fn)`.
      * `model`            — the model to actually call (possibly swapped).
      * `transformed_texts` — list[str] aligned with the input order. Either
                              the originals (no-swap / swap-only / no findings)
                              or pseudonymised copies (anonymise policy).
      * `deanon_fn(text)`  — applied by the caller to the reply text before
                              persisting/returning. Identity when no
                              pseudonymisation happened; real de-anonymiser
                              when `background_pii_action == 'anonymise'` and
                              pseudonymisation succeeded.

    Policy (`gdpr_scanner.background_pii_action`, applied when PII is found):
      * `anonymise`      — pseudonymise the texts in-place; reply is
                            de-anonymised by the caller's `deanon_fn`. Mapping
                            is session-scoped when `current_session_id` is set
                            (reuses the latest persisted map for that session
                            so tokens stay stable across calls), one-shot
                            otherwise. On pseudonymise failure the
                            `background_anonymise_fail_action` knob takes over
                            (`swap_to_local` → existing fallback path,
                            `abort` → raise GDPRBlockedError).
      * `swap_to_local`  — legacy behaviour: swap to
                            `default_local_fallback_model`, or raise/warn
                            when no usable local route exists (governed by
                            `server_block`).
      * `abort`          — always raise GDPRBlockedError on findings.

    `texts` accepts str or iterable-of-str. Unexpected errors in scanning or
    config access fall open (return model + identity deanon) — never block a
    background call on scanner bugs.

    Used by: next-prompt suggestions, chat summary, memory classifier,
    sidecar background_call (delegate tool + scheduler + agent tasks),
    user-profile daemon, KG extraction.
    """
    # Normalise texts up-front so we always return the same shape the caller
    # passed in (list, even when input was a bare string).
    if isinstance(texts, str):
        samples = [texts]
        _input_was_str = True
    else:
        try:
            samples = [t if isinstance(t, str) else "" for t in texts]
        except TypeError:
            return (model, [], _identity_deanon)
        _input_was_str = False

    # ─── Classification gate (Phase B) ──────────────────────────────────
    # Run BEFORE the GDPR scan so classified content can't be silently
    # anonymised — anonymisation strips PII but doesn't change the legal
    # classification of the document. The classification helper raises
    # ClassificationBlockedError on block; caller catches it as usual.
    # Model may also be swapped (force_local action) — subsequent GDPR
    # logic operates on the swapped model.
    try:
        model, samples_after_cls, _ = classification_pick_model_for_background(
            model, samples, purpose=purpose,
        )
        # When force_local swapped to a local model, GDPR can skip
        # anonymisation entirely — let the existing GDPR flow figure that
        # out via is_model_local() rather than short-circuiting here.
        if isinstance(samples_after_cls, list):
            samples = samples_after_cls
        elif isinstance(samples_after_cls, str):
            samples = [samples_after_cls]
    except ClassificationBlockedError:
        raise  # propagate — caller handles soft return

    try:
        cfg = _get_gdpr_scanner_config()
    except Exception:
        return (model, samples if not _input_was_str else samples[0], _identity_deanon)
    if not cfg.get("enabled", True):
        return (model, samples if not _input_was_str else samples[0], _identity_deanon)

    if not any(samples):
        return (model, samples if not _input_was_str else samples[0], _identity_deanon)

    # Full scan across all samples so anonymise has the complete finding set
    # (the legacy short-circuit-on-first-finding only worked for the model-swap
    # decision; pseudonymise needs every finding to mint a stable mapping).
    try:
        all_findings = []
        for s in samples:
            if not s:
                continue
            all_findings.extend(_pii_scan_text(s, max_findings=200, cfg=cfg))
    except Exception:
        return (model, samples if not _input_was_str else samples[0], _identity_deanon)
    if not all_findings:
        return (model, samples if not _input_was_str else samples[0], _identity_deanon)

    _agent = get_request_context().current_agent or _current_agent
    _agent_id = _agent.agent_id if _agent else "main"
    _sid = get_request_context().current_session_id or ""
    _n = len(all_findings)
    _log_audit = bool(cfg.get("server_log", True) and _audit_log)
    _worst_action = _pii_worst_action(all_findings)
    _server_block = (_worst_action == "block")
    _policy = cfg.get("background_pii_action", "anonymise")

    # Always audit the detection.
    try:
        print(f"[gdpr] session={_sid} agent={_agent_id} purpose={purpose} "
              f"findings={_n} policy={_policy} (background)", flush=True)
    except Exception:
        pass
    if _log_audit:
        try:
            _audit_log.log_action(
                agent=_agent_id,
                action_type="pii_detected",
                tool_name="gdpr_scanner",
                args_summary=f"{_n} findings",
                result_summary=f"purpose={purpose or '-'} model={model} policy={_policy}",
                result_status="warning",
                session_id=_sid or None,
                source="background",
            )
        except Exception:
            pass

    # Already on a local model — nothing to reroute, no need to anonymise.
    try:
        model_is_local = is_model_local(model)
    except Exception:
        model_is_local = False
    if model_is_local:
        return (model, samples if not _input_was_str else samples[0], _identity_deanon)

    def _try_swap_to_local(fail_reason: str = ""):
        """Attempt the model-swap. Returns (model, texts, deanon) on swap
        success. On failure (no usable local fallback) returns the ORIGINAL
        (model, texts, identity) with a `pii_warn_passthrough` audit — never
        raises. Aborting is reserved for the explicit `abort` policy options."""
        fallback = (cfg.get("default_local_fallback_model") or "").strip()
        swap_ok = False
        if fallback and fallback != model:
            try:
                fcfg = (_models_config or {}).get(fallback) or {}
                if fcfg.get("enabled") and is_model_local(fallback):
                    swap_ok = True
            except Exception:
                swap_ok = False
        if swap_ok:
            try:
                print(f"[gdpr] auto-fallback session={_sid} agent={_agent_id} "
                      f"purpose={purpose} {model} -> {fallback} "
                      f"({_n} findings{(' ' + fail_reason) if fail_reason else ''})",
                      flush=True)
            except Exception:
                pass
            if _log_audit:
                try:
                    _audit_log.log_action(
                        agent=_agent_id,
                        action_type="pii_auto_fallback",
                        tool_name="gdpr_scanner",
                        args_summary=f"{model} -> {fallback}",
                        result_summary=f"purpose={purpose or '-'} findings={_n}"
                                       f"{(' reason=' + fail_reason) if fail_reason else ''}",
                        result_status="ok",
                        session_id=_sid or None,
                        source="background",
                    )
                except Exception:
                    pass
            return (fallback, samples if not _input_was_str else samples[0], _identity_deanon)
        # No swap possible — warn-passthrough instead of raising.
        try:
            print(f"[gdpr] swap UNAVAILABLE session={_sid} agent={_agent_id} "
                  f"purpose={purpose} model={model} findings={_n} "
                  f"fallback={fallback or '-'} → passthrough", flush=True)
        except Exception:
            pass
        if _log_audit:
            try:
                _audit_log.log_action(
                    agent=_agent_id,
                    action_type="pii_warn_passthrough",
                    tool_name="gdpr_scanner",
                    args_summary=f"model={model}",
                    result_summary=f"purpose={purpose or '-'} findings={_n} "
                                   f"fallback={fallback or '-'}"
                                   f"{(' reason=' + fail_reason) if fail_reason else ''}",
                    result_status="warning",
                    session_id=_sid or None,
                    source="background",
                )
            except Exception:
                pass
        return (model, samples if not _input_was_str else samples[0], _identity_deanon)

    # --- Policy: skip (don't make the call, succeed empty) ---
    # Non-interactive only — there is no user to prompt. Raises GDPRSkipError
    # (a GDPRBlockedError subclass) so every caller's existing soft-return path
    # turns this into a quiet no-op. Unlike 'abort' it is NOT a failure: sites
    # that distinguish it record 'skipped', not 'error', and KG advances its
    # cursor so the doc isn't retried every cycle.
    if _policy == "skip":
        if _log_audit:
            try:
                _audit_log.log_action(
                    agent=_agent_id,
                    action_type="pii_skipped",
                    tool_name="gdpr_scanner",
                    args_summary=f"model={model}",
                    result_summary=f"purpose={purpose or '-'} findings={_n} policy=skip",
                    result_status="warning",
                    session_id=_sid or None,
                    source="background",
                )
            except Exception:
                pass
        raise GDPRSkipError(
            f"[GDPR skip] Background call skipped (purpose={purpose or '-'}): "
            f"{_n} personal-data finding(s); "
            f"gdpr_scanner.background_pii_action='skip'."
        )

    # --- Policy: abort (explicit admin choice — only this raises) ---
    if _policy == "abort":
        if _log_audit:
            try:
                _audit_log.log_action(
                    agent=_agent_id,
                    action_type="pii_blocked",
                    tool_name="gdpr_scanner",
                    args_summary=f"model={model}",
                    result_summary=f"purpose={purpose or '-'} findings={_n} policy=abort",
                    result_status="blocked",
                    session_id=_sid or None,
                    source="background",
                )
            except Exception:
                pass
        raise GDPRBlockedError(
            f"[GDPR block] Background call refused (purpose={purpose or '-'}): "
            f"{_n} personal-data finding(s) in payload; "
            f"gdpr_scanner.background_pii_action='abort'."
        )

    # --- Policy: swap_to_local ---
    if _policy == "swap_to_local":
        return _try_swap_to_local()

    # --- Policy: anonymise ---
    # Attempt pseudonymisation. On failure, defer to
    # background_anonymise_fail_action.
    try:
        anon_samples, deanon_fn = _anonymise_background_samples(
            samples, all_findings, session_id=_sid, agent_id=_agent_id,
            purpose=purpose, log_audit=_log_audit, cfg=cfg)
    except Exception as e:
        _fail_action = cfg.get("background_anonymise_fail_action", "swap_to_local")
        try:
            print(f"[gdpr] anonymise FAILED session={_sid} agent={_agent_id} "
                  f"purpose={purpose}: {e} → action={_fail_action}", flush=True)
        except Exception:
            pass
        if _log_audit:
            try:
                _audit_log.log_action(
                    agent=_agent_id,
                    action_type="pii_anonymise_failed",
                    tool_name="gdpr_scanner",
                    args_summary=f"findings={_n}",
                    result_summary=f"purpose={purpose or '-'} action={_fail_action} err={str(e)[:200]}",
                    result_status="error",
                    session_id=_sid or None,
                    source="background",
                )
            except Exception:
                pass
        if _fail_action == "abort":
            if _log_audit:
                try:
                    _audit_log.log_action(
                        agent=_agent_id,
                        action_type="pii_blocked",
                        tool_name="gdpr_scanner",
                        args_summary=f"model={model}",
                        result_summary=f"purpose={purpose or '-'} findings={_n} "
                                       f"reason=anonymise_failed policy=abort",
                        result_status="blocked",
                        session_id=_sid or None,
                        source="background",
                    )
                except Exception:
                    pass
            raise GDPRBlockedError(
                f"[GDPR block] Background call refused (purpose={purpose or '-'}): "
                f"pseudonymisation failed and "
                f"background_anonymise_fail_action='abort'. Underlying error: {e}"
            )
        # swap_to_local
        return _try_swap_to_local(fail_reason="anonymise_failed")

    # Anonymise succeeded. Keep the original cloud model — pseudonymised text
    # is safe to send. Caller uses deanon_fn on the reply.
    if _log_audit:
        try:
            _audit_log.log_action(
                agent=_agent_id,
                action_type="pii_anonymised",
                tool_name="gdpr_scanner",
                args_summary=f"findings={_n}",
                result_summary=f"purpose={purpose or '-'} model={model}",
                result_status="ok",
                session_id=_sid or None,
                source="background",
            )
        except Exception:
            pass
    return (model, anon_samples if not _input_was_str else anon_samples[0], deanon_fn)


def _anonymise_background_samples(samples, findings, *, session_id, agent_id,
                                  purpose, log_audit, cfg):
    """Pseudonymise a list of samples for a background LLM call.

    Returns `(pseudonymised_samples, deanon_fn)`. Mapping is session-scoped
    when `session_id` is set (latest persisted map for the session is reused
    so tokens stay stable across calls within the same session — matches the
    chat-worker behaviour); one-shot otherwise (no DB persistence — the
    de-anonymiser remains valid for the lifetime of the returned closure).

    Raises on pseudonymise / persistence failure. Caller decides the
    fallback action (swap_to_local or abort).
    """
    import pseudonymizer as _ps
    mapping = None
    reused = False
    # Try to reuse the most recent session map if we're in a real session.
    if session_id:
        try:
            from server_lib.db import ChatDB as _ChatDB  # local import — keeps
            # import-time graph free of optional deps when GDPR isn't used.
            rows = _ChatDB.list_pseudonym_maps_for_session(session_id)
            if rows:
                # rows are chronological; pick the latest. Shape is
                # (mapping_id, turn_id, created_at).
                mid = rows[-1][0]
                got = _ps.get_mapping(mid)
                if got is None:
                    loaded = _ps.load_mapping(mid)
                    if loaded is not None:
                        _ps.restore_mapping_to_registry(loaded)
                        got = loaded
                if got is not None:
                    mapping = got
                    reused = True
        except Exception:
            mapping = None
    if mapping is None:
        mapping = _ps.new_mapping()
    # Pseudonymise every sample against the same mapping so cross-sample tokens
    # stay stable (same value in two inputs → same token). `findings` arg in
    # the param signature is the GLOBAL set scanned in the caller — but
    # offsets are per-sample, so we re-scan each sample in isolation and pass
    # those findings.
    out = []
    src_label = f"background:{purpose}" if purpose else "background"
    for s in samples:
        if not s:
            out.append(s)
            continue
        try:
            per_sample = _pii_scan_text(s, max_findings=200, cfg=cfg)
        except Exception:
            per_sample = []
        if not per_sample:
            out.append(s)
            continue
        new_text = _ps.pseudonymize_text(s, per_sample, mapping=mapping, source=src_label)
        out.append(new_text)
    # Persist the mapping when it's session-scoped (one-shot mappings stay in
    # memory only — `deanon_fn` holds the reference, dropped when caller is
    # done with the reply).
    if session_id:
        try:
            _ps.save_mapping(mapping, session_id=session_id, turn_id=f"background:{purpose}")
        except Exception:
            pass
    n_tokens = len(getattr(mapping, "forward", {}) or {})
    print(f"[gdpr] anonymise OK session={session_id or '-'} agent={agent_id} "
          f"purpose={purpose} samples={len(samples)} tokens={n_tokens} "
          f"{'reused' if reused else 'new'}", flush=True)

    def _deanon(text):
        if not text or not isinstance(text, str):
            return text
        try:
            restored, _n = _ps.deanonymize_text(text, mapping=mapping)
            return restored
        except Exception:
            return text
    return out, _deanon


# ─── Document Classification (ARL 20.02.02.06) — Phase B enforcement ──────

class ClassificationBlockedError(GDPRBlockedError):
    """Raised when classified content reaches a non-local model AND the
    effective per-level action is `block` (or `force_local` with no usable
    local fallback).

    Inherits from GDPRBlockedError so every existing background caller
    that already does `except GDPRBlockedError:` (10+ sites: next-prompt,
    chat summary, memory classifier, delegate, scheduler, refine, etc.)
    transparently picks up classification blocks without per-site changes.
    Callers that need to distinguish the two can `except
    ClassificationBlockedError:` before the GDPR catch.
    """


# Default policy if classification_scanner block is absent from config.json.
# Matches the user-confirmed Phase B defaults.
_CLASSIFICATION_DEFAULTS = {
    "enabled": True,
    "server_log": True,
    "server_block": True,                # master switch for `block` action
    "default_local_fallback_model": "",  # falls back to gdpr_scanner's value if unset
    "per_level_action": {
        "public":       "ignore",
        "internal":     "warn",
        "confidential": "force_local",
        "strict":       "block",
        "unmarked":     "warn",          # unmarked is its own state per Phase A
    },
}


def _get_classification_config() -> dict:
    """Merge config.json's classification_scanner block over the defaults."""
    cfg = {}
    try:
        import sys as _sys
        _srv_mod = _sys.modules.get("__main__") or _sys.modules.get("server")
        if _srv_mod is not None:
            _sc = getattr(_srv_mod, "server_config", None) or {}
            cfg = _sc.get("classification_scanner") or {}
    except Exception:
        cfg = {}
    out = {k: v for k, v in _CLASSIFICATION_DEFAULTS.items()}
    if isinstance(cfg, dict):
        for k, v in cfg.items():
            if k == "per_level_action" and isinstance(v, dict):
                out["per_level_action"] = {**_CLASSIFICATION_DEFAULTS["per_level_action"], **v}
            else:
                out[k] = v
    # Fall back to GDPR's local fallback model when none configured.
    if not out.get("default_local_fallback_model"):
        try:
            gdpr = _get_gdpr_scanner_config()
            out["default_local_fallback_model"] = gdpr.get("default_local_fallback_model") or ""
        except Exception:
            pass
    return out


def _classification_action_level(result: dict) -> str:
    """Pick the level that the enforcement action should follow for a
    detector result.

    Two independent signals come out of `detect_classification`:
      - marker_level   = what's written in the document (or None)
      - heuristic_level = what the content analysis arrived at (PII +
                          keywords; defaults to 'public')

    Neither overrides the other. The action follows the HIGHER of the
    two so:
      - a "public"-marked PDF whose content reads confidential is still
        treated confidential (no security regression by trusting a low
        marker over high-signal content),
      - a "strict"-marked PDF whose content looks bland is still treated
        strict (no security regression by trusting bland content over a
        deliberate marker).

    Returns one of: 'public' / 'internal' / 'confidential' / 'strict' /
    'unmarked' (unmarked only when both signals are missing, which only
    happens on a completely empty / unreadable document).
    """
    from engine.classification import LEVEL_RANK as _LR
    marker_lvl = (result or {}).get("marker_level") or None
    heuristic = ((result or {}).get("content_signals") or {}).get(
        "heuristic_level") or None
    candidates = [lvl for lvl in (marker_lvl, heuristic) if lvl]
    if not candidates:
        return "unmarked"
    return max(candidates, key=lambda x: _LR.get(x, 0))


# Enforcement glue (_classification_effective_action,
# _classification_gate_tool_text, classification_pick_model_for_background)
# now lives in engine/classification.py — re-exported here so brain.X /
# engine.X callers keep resolving. The import sits below the brain-side
# helpers those functions reach back into at call time.
from engine.classification import (  # noqa: E402
    _classification_effective_action,
    _classification_gate_tool_text,
    classification_pick_model_for_background,
)


def _classification_scan_text(text: str, *, filename: str = "",
                               pdf_path: str = "") -> dict | None:
    """Run the classification detector against text.

    Returns the result dict (see engine.classification.detect_classification)
    or None if the scanner is disabled / errors. Never raises.
    """
    cfg = _get_classification_config()
    if not cfg.get("enabled", True):
        return None
    try:
        from engine.classification import detect_with_pii as _detect
        # Pass the full server_config so the detector picks up the user's
        # keyword + extra_patterns config.
        _srv_cfg = {}
        try:
            import sys as _sys
            _srv_mod = _sys.modules.get("__main__") or _sys.modules.get("server")
            if _srv_mod is not None:
                _srv_cfg = getattr(_srv_mod, "server_config", None) or {}
        except Exception:
            pass
        return _detect(text, filename=filename, pdf_path=pdf_path,
                       cfg=_srv_cfg)
    except Exception as e:
        try:
            print(f"[classification] scan failed: {e}", flush=True)
        except Exception:
            pass
        return None


# classification_pick_model_for_background extracted to
# engine/classification.py (re-exported above near _classification_action_level).


# --- Markdown rendering ---

# ANSI codes
BOLD = "\033[1m"
DIM = "\033[2m"
ITALIC = "\033[3m"
RESET = "\033[0m"
CYAN = "\033[36m"
YELLOW = "\033[33m"
GREEN = "\033[32m"
MAGENTA = "\033[35m"
BLUE = "\033[34m"
RED = "\033[31m"
BG_GRAY = "\033[48;5;236m"
FG_GRAY = "\033[38;5;245m"
FG_ORANGE = "\033[38;5;208m"
WHITE = "\033[37m"
BG_DARK = "\033[48;5;235m"

# Minimum box inner width so things don't collapse on very narrow terminals
_MIN_BOX_INNER = 20


def _term_cols() -> int:
    """Get current terminal width."""
    return shutil.get_terminal_size().columns


def _box_width() -> int:
    """Inner width for box-drawing, adapts to terminal width.
    Leaves 2 chars indent + 1 border left + 1 border right = 4 chars margin."""
    return max(_MIN_BOX_INNER, _term_cols() - 4)


def _box_top(label: str = "") -> str:
    """Draw ┌─ label ───...┐ spanning the available width."""
    w = _box_width()
    if label:
        vlen = _visible_len(label)
        # "┌─ " + label + " " + fill + "┐"  →  3 + vlen + 1 + fill + 1 = w + 2
        fill = max(0, w - 4 - vlen)
        return f"  {DIM}┌─ {RESET}{label}{DIM} {'─' * fill}┐{RESET}"
    else:
        return f"  {DIM}┌{'─' * w}┐{RESET}"


def _visible_len(text: str) -> int:
    """Get the visible (column) length of a string, ignoring ANSI escape codes.
    Handles wide Unicode characters and tabs."""
    import unicodedata
    stripped = re.sub(r"\033\[[0-9;]*[a-zA-Z]", "", text)
    stripped = re.sub(r"\033\[\?[0-9;]*[a-zA-Z]", "", stripped)
    stripped = re.sub(r"\033\([A-Z]", "", stripped)
    w = 0
    for ch in stripped:
        if ch == '\t':
            w += (8 - w % 8)
        elif unicodedata.east_asian_width(ch) in ('W', 'F'):
            w += 2
        elif unicodedata.category(ch) in ('Mn', 'Me', 'Cf'):
            pass  # zero-width combining/format chars
        else:
            w += 1
    return w


def _truncate_visible(text: str, max_cols: int) -> str:
    """Truncate a string (may contain ANSI codes) to max visible columns."""
    import unicodedata
    cols = 0
    i = 0
    while i < len(text) and cols < max_cols:
        if text[i] == '\033':
            # Skip full ANSI sequence
            j = i + 1
            while j < len(text) and text[j] not in 'mABCDHJKfhlGn':
                j += 1
            i = j + 1
        elif text[i] == '\t':
            add = 8 - cols % 8
            if cols + add > max_cols:
                break
            cols += add
            i += 1
        else:
            ch = text[i]
            cw = 2 if unicodedata.east_asian_width(ch) in ('W', 'F') else 1
            if unicodedata.category(ch) in ('Mn', 'Me', 'Cf'):
                cw = 0
            if cols + cw > max_cols:
                break
            cols += cw
            i += 1
    if i < len(text):
        # Check if remaining is only ANSI codes
        rest = text[i:]
        rest_stripped = re.sub(r"\033\[[0-9;]*[a-zA-Z]", "", rest)
        if rest_stripped.strip():
            return text[:i] + RESET
    return text


def _box_mid(content: str = "") -> str:
    """Draw │ content — truncated to fit terminal width. No wrapping."""
    # "  │  " = 5 visible chars prefix
    max_content = max(10, _term_cols() - 6)
    # Expand tabs to spaces first to avoid variable-width issues
    content = content.replace("\t", "    ")
    truncated = _truncate_visible(content, max_content)
    return f"  {DIM}│{RESET}  {truncated}"


def _box_bot() -> str:
    """Draw └───...┘ spanning the available width."""
    w = _box_width()
    return f"  {DIM}└{'─' * w}┘{RESET}"


def _render_tool_calls(text: str) -> str:
    """Pre-process tool_call XML blocks into styled representations."""

    def _replace_tool_call(m):
        block = m.group(1)
        func_match = re.search(r"<function=([^>]+)>", block)
        func_name = func_match.group(1) if func_match else "unknown"
        params = re.findall(
            r"<parameter=([^>]+)>\s*(.*?)\s*</parameter>",
            block, re.DOTALL)

        lines = []
        lines.append(_box_top(f"{FG_ORANGE}{BOLD}⚡ Tool Call{RESET}"))
        lines.append(_box_mid(f"{CYAN}{BOLD}{func_name}{RESET}()"))
        if params:
            for pname, pval in params:
                pval = pval.strip()
                lines.append(_box_mid(f"  {MAGENTA}{pname}{RESET}{DIM}:{RESET} {WHITE}{pval}{RESET}"))
        lines.append(_box_bot())
        return "\n".join(lines)

    text = re.sub(
        r"<tool_call>\s*(.*?)\s*</tool_call>",
        _replace_tool_call, text, flags=re.DOTALL)

    def _replace_standalone_tool(m):
        block = m.group(0)
        func_match = re.search(r"<function=([^>]+)>", block)
        func_name = func_match.group(1) if func_match else "unknown"
        params = re.findall(
            r"<parameter=([^>]+)>\s*(.*?)\s*</parameter>",
            block, re.DOTALL)

        lines = []
        lines.append(_box_top(f"{FG_ORANGE}{BOLD}⚡ Tool Call{RESET}"))
        lines.append(_box_mid(f"{CYAN}{BOLD}{func_name}{RESET}()"))
        if params:
            for pname, pval in params:
                pval = pval.strip()
                lines.append(_box_mid(f"  {MAGENTA}{pname}{RESET}{DIM}:{RESET} {WHITE}{pval}{RESET}"))
        lines.append(_box_bot())
        return "\n".join(lines)

    text = re.sub(
        r"<function=([^>]+)>\s*(?:<parameter=([^>]+)>\s*(.*?)\s*</parameter>\s*)*</function>",
        _replace_standalone_tool, text, flags=re.DOTALL)

    return text


def _render_tool_results(text: str) -> str:
    """Pre-process tool result XML blocks into styled representations."""

    def _replace_result(m):
        content = m.group(1).strip()
        lines = []
        lines.append(_box_top(f"{GREEN}{BOLD}✔ Tool Result{RESET}"))
        for cline in content.split("\n"):
            lines.append(_box_mid(cline))
        lines.append(_box_bot())
        return "\n".join(lines)

    text = re.sub(
        r"<tool_result>\s*(.*?)\s*</tool_result>",
        _replace_result, text, flags=re.DOTALL)

    return text


def render_markdown(text: str) -> str:
    """Render markdown text with ANSI escape codes for terminal display."""
    # Pre-process tool calls and results before line-by-line markdown
    text = _render_tool_calls(text)
    text = _render_tool_results(text)

    lines = text.split("\n")
    result = []
    in_code_block = False
    code_lang = ""

    for line in lines:
        # Skip lines already processed by tool renderers (contain box-drawing chars)
        if "┌─" in line or "└─" in line or (line.startswith("  ") and "│" in line[:6]):
            result.append(line)
            continue

        # Fenced code block toggle
        if line.strip().startswith("```"):
            if not in_code_block:
                in_code_block = True
                code_lang = line.strip()[3:].strip()
                if code_lang:
                    result.append(_box_top(f"{DIM}{code_lang}{RESET}"))
                else:
                    result.append(_box_top())
            else:
                in_code_block = False
                result.append(_box_bot())
            continue

        if in_code_block:
            result.append(f"  {DIM}│{RESET} {YELLOW}{line}{RESET}")
            continue

        # Headers
        if line.startswith("#### "):
            result.append(f"{BOLD}{CYAN}{line[5:]}{RESET}")
            continue
        if line.startswith("### "):
            result.append(f"{BOLD}{CYAN}{line[4:]}{RESET}")
            continue
        if line.startswith("## "):
            result.append(f"{BOLD}{CYAN}{line[3:]}{RESET}")
            continue
        if line.startswith("# "):
            result.append(f"{BOLD}{CYAN}{line[2:]}{RESET}")
            continue

        # Horizontal rule
        if re.match(r"^[-*_]{3,}\s*$", line):
            result.append(f"{DIM}{'─' * max(20, _term_cols() - 4)}{RESET}")
            continue

        # Bullet lists
        m = re.match(r"^(\s*)([-*])\s+(.*)$", line)
        if m:
            indent, _, content = m.groups()
            content = _inline_format(content)
            result.append(f"{indent}  {DIM}•{RESET} {content}")
            continue

        # Numbered lists
        m = re.match(r"^(\s*)(\d+)\.\s+(.*)$", line)
        if m:
            indent, num, content = m.groups()
            content = _inline_format(content)
            result.append(f"{indent}  {DIM}{num}.{RESET} {content}")
            continue

        # Regular line with inline formatting
        result.append(_inline_format(line))

    return "\n".join(result)


def _inline_format(text: str) -> str:
    """Apply inline markdown formatting (bold, italic, code)."""
    # Inline code (must be before bold/italic to avoid conflicts)
    text = re.sub(r"`([^`]+)`", rf"{YELLOW}\1{RESET}", text)
    # Bold + italic
    text = re.sub(r"\*\*\*(.+?)\*\*\*", rf"{BOLD}{ITALIC}\1{RESET}", text)
    # Bold
    text = re.sub(r"\*\*(.+?)\*\*", rf"{BOLD}\1{RESET}", text)
    # Italic
    text = re.sub(r"(?<!\*)\*(?!\*)(.+?)(?<!\*)\*(?!\*)", rf"{ITALIC}\1{RESET}", text)
    # Links [text](url) -> text (url)
    text = re.sub(r"\[([^\]]+)\]\(([^)]+)\)", rf"{BOLD}\1{RESET} {DIM}(\2){RESET}", text)
    return text


# --- API functions ---

def make_headers(api_key: str) -> dict:
    """Build request headers. All providers are OpenAI-compatible."""
    return {
        "Content-Type": "application/json",
        "Authorization": f"Bearer {api_key}",
    }


_MEMORY_CLASSIFIER_PROMPT = (
    "Classify this chat exchange into exactly one category. "
    "Reply with ONLY the category name, nothing else.\n"
    "Categories:\n"
    "- fact: contains user-specific data, measurements, names, dates, results\n"
    "- preference: user expresses a preference, like, dislike, or personal choice\n"
    "- decision: a decision was made, an action agreed upon, a plan set\n"
    "- reference: mentions a specific resource, URL, tool, project, or document\n"
    "- generic: generic advice, how-to steps, or information not specific to the user\n"
    "- refusal: assistant says it can't help, doesn't have access, or doesn't know\n"
    "- chitchat: greetings, small talk, jokes, acknowledgements with no substance"
)


def classify_chat_for_memory(user_text: str, assistant_text: str,
                             model: str, timeout: int = 15) -> str | None:
    """Classify a user+assistant exchange for memory filing. Returns the
    category label or None on error.

    Routes through `sidecar_proxy.background_call` so it picks up the same
    GDPR pre-flight + provider routing as every other non-interactive LLM
    call. The chat-sync daemon sets `current_user_id` on the thread-local
    before invoking us so any per-user gating downstream can find the caller.
    """
    try:
        # GDPR policy gate. Aborts the classify if the admin chose abort
        # policy; otherwise proceeds with possibly-swapped model and possibly
        # pseudonymised text. Reply is a one-word label so deanon is a no-op
        # but applying it costs nothing.
        try:
            model, (_u_pii, _a_pii), _deanon = gdpr_pick_model_for_background(
                model, [user_text, assistant_text], purpose="memory_classifier")
        except GDPRBlockedError:
            return None
        messages = [
            {"role": "user",
             "content": f"User: {_u_pii[:2000]}\nAssistant: {_a_pii[:2000]}"},
        ]
        from handlers import sidecar_proxy as _sidecar_proxy
        _res = _sidecar_proxy.background_call(
            messages=messages,
            model=model,
            system_prompt=_MEMORY_CLASSIFIER_PROMPT,
            cost_purpose="memory_classifier",
            max_tokens=20,
        )
        text = _deanon(_res.get("reply") or "")
        if not text:
            return None
        content = text.strip().strip('"').strip("'").strip().lower()
        # Some thinking-format models leak <think>…</think> wrappers around
        # short answers. Strip the wrapper so the label inside is comparable.
        if "<think>" in content and "</think>" in content:
            content = content.split("</think>", 1)[1].strip()
        # Take just the first token-ish word — labels are single words.
        if content:
            content = content.split()[0].strip(",.;:!?\"'`").lower()
        valid = {"fact", "preference", "decision", "reference",
                 "generic", "refusal", "chitchat"}
        return content if content in valid else None
    except Exception as e:
        print(f"[mempalace-classifier] error: {e}", file=sys.stderr, flush=True)
        return None


def get_available_models(api_key: str, base_url: str) -> list[str]:
    """Fetch available models from the API and return as a list."""
    headers = make_headers(api_key)
    request = urllib.request.Request(
        f"{base_url}/models", headers=headers, method="GET",
    )
    try:
        with urllib.request.urlopen(request) as response:
            data = json.loads(response.read().decode("utf-8"))
            models = data.get("data", [])
            return [model.get("id") for model in models if model.get("id")]
    except (urllib.error.HTTPError, urllib.error.URLError):
        return []


