CAPABILITY_VALUES = ["chat", "image", "audio", "tts", "video"]
CANONICAL_CAPABILITIES = tuple(CAPABILITY_VALUES)


def _infer_canonical_capabilities(model_id: str, cfg: dict) -> list[str]:
    """Infer the canonical capability set for a model entry.

    The five canonical buckets are routing flags (not marketing tags):
      - chat:  selectable in any general model dropdown
      - image: vision input — listable for read_document image fallback
      - audio: speech-to-text — listable for transcribe_audio
      - tts:   text-to-speech — listable for the speaker / translate TTS dropdown
      - video: video input — reserved for video-in models

    Heuristics, in order:
      - raw_formats containing 'image/*' → image
      - raw_formats containing 'video/*' → video
      - id/shortname/base contains 'tts' → tts (and not chat)
      - id/shortname/base contains 'whisper' or 'voxtral' (without 'tts') → audio (and not chat)
      - legacy 'audio' capability (pre-canonical) → audio (and not chat)
      - everything else → chat
    """
    sn = (cfg.get("shortname") or "").lower()
    base = (cfg.get("base_model_id") or "").lower()
    mid_l = (model_id or "").lower()
    blob = " ".join((mid_l, sn, base))
    raw = [str(p).lower() for p in (cfg.get("raw_formats") or [])]
    legacy = set(cfg.get("capabilities") or [])

    caps: list[str] = []
    if "tts" in blob:
        caps.append("tts")
    elif "whisper" in blob or "voxtral" in blob or "audio" in legacy:
        caps.append("audio")
    else:
        caps.append("chat")
    if any(p.startswith("image") for p in raw):
        if "image" not in caps:
            caps.append("image")
    if any(p.startswith("video") for p in raw):
        if "video" not in caps:
            caps.append("video")
    return caps


def _canonicalize_model_capabilities(force: bool = False) -> None:
    """One-shot migration: replace freeform legacy tags with the canonical
    {chat, image, audio, tts, video} set. Idempotent — each entry is migrated
    once (marker ``_caps_canonical: True``) so user removals afterwards stick.
    """
    global _models_config
    for mid, cfg in (_models_config or {}).items():
        if cfg.get("_caps_canonical") and not force:
            continue
        cfg["capabilities"] = _infer_canonical_capabilities(mid, cfg)
        cfg["_caps_canonical"] = True

_models_config: dict = {}


def _detect_thinking_format(model_id: str, provider: str = "") -> str:
    """Infer thinking_format from model id (and optional provider). Returns one of:
    "none" — model has no reasoning phase (default).
    "inline_tags" — emits <think>...</think> in content string (Qwen3, DeepSeek-R1 distills, GLM-Zero served via third parties).
    "reasoning_field" — emits separate message.reasoning_content / delta.reasoning_content (oMLX for all its models, cliproxyapi Gemini with reasoning_effort, DeepSeek-R1 direct).
    "mistral_blocks" — emits content as a list with {type: "thinking", thinking: [{type: "text", text: ...}]} blocks (Mistral API for magistral-* and mistral-small-2603+ when reasoning_effort is set).
    "openai_opaque" — reasoning tokens hidden server-side, only usage.completion_tokens_details.reasoning_tokens exposed (OpenAI o-series).

    Routing note: these choices assume DIRECT provider connections. Proxies that re-serialize via typed
    structs (e.g. Bifrost) may silently drop reasoning_content and the nested Mistral thinking array.
    Brain routes thinking-capable models direct to their provider for exactly this reason.
    """
    m = model_id.lower()
    p = (provider or "").lower()
    # Provider-aware match: cliproxyapi serves Gemini 2.5 reasoning even when
    # the stored id is bare ("gemini-2.5-flash") with no scoped prefix. The
    # id-only patterns below still cover the prefixed form for back-compat.
    if p == "cliproxyapi" and "gemini-2.5" in m:
        return "reasoning_field"
    # Model-id catch-all for chat-templates that emit a reasoning channel
    # regardless of the wire it's served on. Gemma 4 / Qwen3 / DeepSeek R1 /
    # GLM-Zero / Magistral all ship with reasoning baked into the chat
    # template — `enable_thinking` defaults to True if no kwarg is passed,
    # so the model emits its answer into the reasoning channel unless we
    # explicitly opt out. NOT gated on provider name: a user-renamed
    # provider ("Lokal", "MyMLX", whatever) serving these models on
    # OpenAI-shape wire still surfaces reasoning_content in the response.
    if (
        "qwen3" in m or "qwen-3" in m
        or "deepseek-r1" in m or "deepseek/r1" in m
        or "deepseek-v4" in m or "deepseek/deepseek-v4" in m
        or "glm-zero" in m or "glm4-zero" in m
        or "magistral" in m
        or "gemma-4" in m or "gemma4" in m
    ):
        return "reasoning_field"
    # OpenAI o-series — opaque reasoning
    for p in ("o1-", "o1/", "/o1", "o3-", "o3/", "/o3", "o4-mini"):
        if p in m:
            return "openai_opaque"
    # Mistral reasoning models — content-block array with nested thinking[]
    # (magistral-* and mistral-small 2603+ and mistral-medium 3.x+ with reasoning_effort set).
    # Checked before the generic "magistral" branch in the inline_tags section so Mistral wins.
    if (
        "magistral" in m
        or "mistral-small-2603" in m
        or "mistral-small-latest" in m  # alias commonly resolves to the newest small
        or "mistral-medium-3" in m      # mistral-medium-3.5 / mistral-medium-3-5 / mistral-medium-2604+
        or "mistral-medium-latest" in m # latest alias may point to a reasoning-capable medium
        or "mistral-medium-2604" in m
    ):
        return "mistral_blocks"
    # oMLX serves every reasoning-capable model via a unified API that exposes
    # reasoning_content as a sibling field on the message (even for gemma, when
    # enable_thinking is set). Catch the OMLX/ prefix here so we don't miss any.
    if m.startswith("omlx/") or "/omlx/" in m:
        return "reasoning_field"
    # cliproxyapi routes Gemini. 2.5-series has reasoning, returned in reasoning_content
    # when reasoning_effort is set on the request.
    if m.startswith("cliproxyapi/gemini-2.5") or "/gemini-2.5-" in m:
        return "reasoning_field"
    # DeepSeek-R1 official API uses reasoning_content field; distills via third-party often use inline tags.
    if "deepseek-r1" in m or "deepseek/r1" in m:
        return "reasoning_field" if "deepseek.com" in m or m.startswith("deepseek/") else "inline_tags"
    # Inline <think> tag emitters — Qwen3 / GLM-Zero when served by a provider that
    # does NOT strip reasoning_content. Kept as the fallback because oMLX's OMLX/qwen3
    # would have matched the reasoning_field branch above.
    if (
        "qwen3" in m or "qwen-3" in m
        or "glm-zero" in m or "glm4-zero" in m
        or "thinking" in m  # e.g. claude-*-thinking variants, custom builds
    ):
        return "inline_tags"
    return "none"


def _match_known_model(model_id: str, provider: str = "") -> dict:
    """Match a model ID against KNOWN_MODELS patterns. Returns default config."""
    m = model_id.lower()
    for prefix, defaults in KNOWN_MODELS.items():
        if m.startswith(prefix) or prefix in m:
            # Generate shortname from model ID
            shortname = model_id.split("/")[-1]  # strip provider prefix
            # Simplify common patterns
            for suffix in ["-20251101", "-20250101", "-20241022", "-20251001"]:
                shortname = shortname.replace(suffix, "")
            result = {
                "enabled": True,
                "shortname": shortname,
                "display_name": shortname,
                "icon": defaults["icon"],
                "priority": defaults["priority"],
                "capabilities": list(defaults["capabilities"]),
                "thinking_format": _detect_thinking_format(model_id, provider),
            }
            if "max_context" in defaults:
                result["max_context"] = defaults["max_context"]
            if "max_output" in defaults:
                result["max_output"] = defaults["max_output"]
            if "inference" in defaults:
                result["inference"] = dict(defaults["inference"])
            if "raw_formats" in defaults:
                result["raw_formats"] = list(defaults["raw_formats"])
            return result
    # Unknown model — enabled with low priority
    shortname = model_id.split("/")[-1]
    return {
        "enabled": True,
        "shortname": shortname,
        "display_name": shortname,
        "icon": "\U0001f916",
        "priority": 10,
        "capabilities": [],
        "raw_formats": [],
        "thinking_format": _detect_thinking_format(model_id, provider),
    }


def init_models_config(providers: dict, existing_models: dict | None = None,
                       all_providers: dict | None = None,
                       deleted_models: set | list | None = None) -> dict:
    """Auto-populate models config from provider model lists.

    Merges with existing config (preserves user edits). Returns the models dict.
    all_providers: when syncing a subset, pass full provider dict for orphan cleanup.
    deleted_models: tombstone set — model ids (and provider/scoped variants) that
        the user explicitly deleted. We never auto-rediscover these. Cleared per
        provider only by the resync_provider action.
    """
    global _models_config
    if existing_models:
        # Deep copy: per-model cfg dicts are mutated in place by the upgrade
        # paths below (e.g. forward-looking thinking_format re-detect). A
        # shallow copy would alias the value dicts back to the caller's
        # snapshot, defeating the diff-based persist branch in server.py.
        _models_config = {k: dict(v) for k, v in existing_models.items()}

    tombstones = set(deleted_models or ())

    # Discover models from all providers
    for name, p in providers.items():
        try:
            models = get_available_models(
                p.get("api_key", ""), p.get("base_url", ""))
        except Exception:
            models = []
        discovered = set(models)
        # Auto-pick profile based on endpoint: local → "speed", cloud → "balanced".
        # Explicit per-model overrides survive because this only fires for new entries.
        default_profile = "speed" if bool(p.get("is_local", False)) else "balanced"
        for model_id in models:
            scoped_key = f"{name}/{model_id}"
            # Honor user deletions: if either the bare id or the provider-scoped
            # id is tombstoned, skip discovery entirely.
            if model_id in tombstones or scoped_key in tombstones:
                continue
            if model_id not in _models_config:
                entry = _match_known_model(model_id, name)
                entry["provider"] = name
                entry["profile"] = default_profile
                _models_config[model_id] = entry
            elif _models_config[model_id].get("provider") != name:
                # Same model ID exists under a different provider — add with provider-scoped key
                if scoped_key not in _models_config:
                    entry = _match_known_model(model_id, name)
                    entry["provider"] = name
                    entry["base_model_id"] = model_id
                    entry["profile"] = default_profile
                    _models_config[scoped_key] = entry
                discovered.add(scoped_key)
            else:
                if "provider" not in _models_config[model_id]:
                    _models_config[model_id]["provider"] = name
        # Remove models from this provider that are no longer in the /models list
        if discovered:
            stale = [
                mid for mid, cfg in _models_config.items()
                if cfg.get("provider") == name
                and mid not in discovered
                and cfg.get("base_model_id", mid) not in discovered
                and not cfg.get("manual")
            ]
            for mid in stale:
                del _models_config[mid]

    # Remove orphaned models from providers that no longer exist
    all_prov_names = set((all_providers or providers).keys())
    orphaned = [
        mid for mid, cfg in _models_config.items()
        if cfg.get("provider") and cfg["provider"] not in all_prov_names
        and not cfg.get("manual")
    ]
    for mid in orphaned:
        del _models_config[mid]

    # Backfill defaults from KNOWN_MODELS for all models missing fields
    for model_id, cfg in _models_config.items():
        prov = cfg.get("provider", "") or ""
        known = _match_known_model(model_id, prov)
        if "max_context" not in cfg and "max_context" in known:
            cfg["max_context"] = known["max_context"]
        if "raw_formats" not in cfg and "raw_formats" in known:
            cfg["raw_formats"] = known["raw_formats"]
        if "thinking_format" not in cfg:
            cfg["thinking_format"] = known.get("thinking_format", "none")
        else:
            # Forward-looking re-detect: when the stored format is the
            # conservative default ('none') but the provider-aware detector
            # now produces a real format (e.g. cliproxyapi/gemini-2.5
            # gained provider-aware matching post-8.17.x), upgrade in place.
            # We never go in the other direction — that would clobber a
            # deliberate user "off" choice on a thinking-capable model.
            if cfg["thinking_format"] == "none":
                redetected = known.get("thinking_format", "none")
                if redetected != "none":
                    cfg["thinking_format"] = redetected

    _ensure_audio_models()
    _canonicalize_model_capabilities()
    return _models_config


_WHISPER_SIZES = ("tiny", "base", "small", "medium", "large-v3")


def _ensure_audio_models() -> None:
    """Idempotent migration: ensure
      - the 5 mlx-whisper sizes exist as model entries (provider=local-mlx-whisper, capability=audio)
      - any voxtral entry already in _models_config carries the 'audio' capability
    Runs on every init_models_config so existing installs gain the entries
    without manual config edits.
    """
    global _models_config
    for size in _WHISPER_SIZES:
        mid = f"whisper-{size}"
        if mid in _models_config:
            # Existing entry: never re-stamp capabilities. The user owns them.
            # Only fill in structural fields that must be present for routing.
            cfg = _models_config[mid]
            cfg.setdefault("provider", _WHISPER_PROVIDER)
            cfg.setdefault("is_local", True)
            cfg.setdefault("warmup", False)
            cfg.setdefault("manual", True)
            continue
        # First-time seed.
        _models_config[mid] = {
            "enabled": True,
            "shortname": mid,
            "display_name": f"Whisper {size}",
            "icon": "\U0001f3a4",
            "priority": 30,
            "capabilities": ["audio"],
            "raw_formats": [],
            "thinking_format": "none",
            "provider": _WHISPER_PROVIDER,
            "is_local": True,
            "warmup": False,
            "manual": True,
            "_audio_backfilled": True,
            "_caps_canonical": True,
        }
    # One-shot backfill of 'audio' capability on existing voxtral entries
    # served by the mistral-direct provider (the real Mistral API; the old
    # 'mistral-experimental' provider was removed and its refs were dangling —
    # 2026-06 cleanup). The marker per entry means the user can remove the
    # capability later without it coming back on the next startup.
    for mid, cfg in _models_config.items():
        if cfg.get("_audio_backfilled"):
            continue
        if cfg.get("provider") != "mistral-direct":
            continue
        sn = (cfg.get("shortname") or mid).lower()
        base = (cfg.get("base_model_id") or "").lower()
        if "voxtral" in sn or "voxtral" in base or "voxtral" in mid.lower():
            caps = list(cfg.get("capabilities") or [])
            if "audio" not in caps:
                caps.append("audio")
                cfg["capabilities"] = caps
            cfg["_audio_backfilled"] = True


def resolve_model(model_spec: str, purpose: str | None = None) -> str:
    """Resolve a model specifier to a canonical model ID.

    Handles:
    - "auto" + purpose → highest-priority enabled model with that capability
    - shortname (e.g. "opus") → lookup by shortname
    - canonical ID → pass through
    """
    if not model_spec:
        return ""

    if model_spec == "auto":
        return _resolve_auto_model(purpose)

    # Try shortname lookup
    for model_id, cfg in _models_config.items():
        if cfg.get("shortname") == model_spec:
            if cfg.get("enabled", True):
                return model_id
            break  # Found but disabled

    # Pass through as canonical ID
    return model_spec


def _resolve_auto_model(purpose: str | None) -> str:
    """Pick the best enabled model for a given purpose."""
    enabled = [(mid, cfg) for mid, cfg in _models_config.items() if cfg.get("enabled", True)]
    if not enabled:
        return ""

    if purpose:
        # Filter to models with the requested capability
        matching = [(mid, cfg) for mid, cfg in enabled if purpose in cfg.get("capabilities", [])]
        if matching:
            matching.sort(key=lambda x: x[1].get("priority", 0), reverse=True)
            return matching[0][0]

    # Fallback: highest priority enabled model
    enabled.sort(key=lambda x: x[1].get("priority", 0), reverse=True)
    return enabled[0][0]


def get_enabled_models() -> list[str]:
    """Return enabled model IDs sorted by priority descending."""
    enabled = [(mid, cfg) for mid, cfg in _models_config.items() if cfg.get("enabled", True)]
    enabled.sort(key=lambda x: x[1].get("priority", 0), reverse=True)
    return [mid for mid, _ in enabled]


# --- Task-based auto model selection ---

_PURPOSE_PATTERNS: dict[str, list[re.Pattern]] = {
    "coding": [
        re.compile(r"\b(write|fix|debug|refactor|implement|code|function|class|bug|error|traceback|test|unittest|lint|compile|build|deploy|dockerfile|makefile|git\b|commit|branch|merge|PR\b|pull request|regex|parse|api|endpoint|route|migration|schema|sql|query|index\.)\b", re.I),
        re.compile(r"\b(python|javascript|typescript|rust|go|java|c\+\+|html|css|json|yaml|toml|bash|shell|script)\b", re.I),
        re.compile(r"```", re.I),
    ],
    "analysis": [
        re.compile(r"\b(analy[sz]e|explain|compare|evaluate|review|assess|investigate|research|summarize|summary|report|pros?\b|cons?\b|trade-?off|benchmark|metric|statistic|data|insight|trend|pattern|cause|why does|how does|what is|understand)\b", re.I),
    ],
    "creative": [
        re.compile(r"\b(write|draft|compose|story|poem|essay|blog|article|creative|brainstorm|idea|name|slogan|tagline|marketing|copy|narrative|fiction|dialogue|character)\b", re.I),
    ],
    "agentic": [
        re.compile(r"\b(search|find|look up|fetch|download|browse|scrape|monitor|schedule|automate|run|execute|install|setup|configure|deploy|send|email|notify|delegate|background)\b", re.I),
    ],
    "fast": [
        re.compile(r"\b(quick|brief|short|one-?liner|yes or no|true or false|translate|convert|format|list|enumerate|define)\b", re.I),
    ],
}


def classify_task_purpose(message: str) -> str | None:
    """Classify a user message into a capability/purpose using keyword heuristics.

    Returns the best-matching purpose or None if no strong signal.
    Scores each purpose by number of pattern matches; requires at least 2 signal
    strength to avoid false positives on single-word matches.
    """
    if not message:
        return None

    scores: dict[str, int] = {}
    for purpose, patterns in _PURPOSE_PATTERNS.items():
        score = 0
        for pat in patterns:
            hits = len(pat.findall(message))
            score += hits
        if score > 0:
            scores[purpose] = score

    if not scores:
        return None

    best_purpose = max(scores, key=scores.get)
    # Require some minimum signal (at least 2 keyword hits) to avoid noisy classification
    if scores[best_purpose] < 2:
        return None

    return best_purpose


# The 5 purposes the tiered router (`_PURPOSE_TIER`) actually understands. The
# LLM classifier is constrained to this exact vocabulary so its output drops
# straight into `_resolve_auto_model_tiered` with no remapping.
_LLM_CLASSIFY_PURPOSES = ("coding", "analysis", "creative", "agentic", "fast")

# --- Structured task analysis (the `llm`/`hybrid` classifier internals) ---
#
# The LLM returns a JSON object describing WHAT the task involves (task_types)
# and WHICH tool families it needs (tools), so we can pick the best model AND
# tailor the tool set. Both vocabularies are CLOSED and map onto things that
# already exist downstream:
#   - task_types  -> a routing tier (via `_TASK_TYPE_TIER`)
#   - tools       -> real `TOOL_GROUPS` names (via `_TASK_TOOL_GROUPS`)
# so the model never invents a label we can't act on. Anything off-vocabulary
# is dropped during parsing (fail-safe, not fail-loud — a stray label must not
# break routing).

# task_type -> routing tier. Tiers are the same three `_resolve_auto_model_tiered`
# understands (reasoning / fast / default). The winning task_type's tier picks
# the model; we bias toward the strongest tier present (reasoning > default >
# fast) so a mixed "research + format" task still gets a capable model.
_TASK_TYPE_TIER: dict[str, str] = {
    "coding": "reasoning",
    "math": "reasoning",
    "research": "reasoning",
    "analysis": "reasoning",
    "reporting": "default",
    "creative": "default",
    "orchestration": "default",
    "agentic": "default",
    "fast": "fast",
}
_TASK_TYPES = tuple(_TASK_TYPE_TIER.keys())
# Tier strength order for picking the dominant tier across multiple task_types.
_TIER_RANK = {"reasoning": 2, "default": 1, "fast": 0}

# Classifier tool label -> set of real `TOOL_GROUPS` names to enable. Labels are
# user-facing/intuitive ("bash", "python") and fan out to the groups that carry
# the matching tool impls. Validated lazily against TOOL_GROUPS at call time so
# this stays correct if a group is renamed.
_TASK_TOOL_GROUPS: dict[str, tuple[str, ...]] = {
    "python":      ("code_exec",),
    "bash":        ("core",),          # execute_command lives in core
    "files":       ("core", "documents"),
    "web":         ("web",),
    "memory":      ("memory", "context"),
    "email":       ("email",),
    "git":         ("git", "code_graph"),
    "code_graph":  ("code_graph",),
    "delegation":  ("delegation", "background"),
    "scheduler":   ("scheduler",),
    "translation": ("translation",),
    "image_gen":   ("image_gen",),
    "audio":       ("audio",),
    "skills":      ("skills",),
}
_TASK_TOOLS = tuple(_TASK_TOOL_GROUPS.keys())

_STRUCTURED_CLASSIFY_SYSTEM = (
    "You are a task analyzer for an AI agent router. Read the user's message and "
    "return a SINGLE JSON object (no prose, no markdown fence) describing the task "
    "so a controller can pick the best model and tools.\n\n"
    "Schema (all fields required):\n"
    '{\n'
    '  "task_types": [string, ...],   // 1-3 from the TASK TYPES list, most important first\n'
    '  "tools": [string, ...],         // from the TOOLS list — EVERY tool the task plausibly needs (see WHEN rules)\n'
    '  "complexity": "low"|"medium"|"high",\n'
    '  "reasoning": string             // <=12 words, why\n'
    '}\n\n'
    "TASK TYPES (use these exact words):\n"
    "  coding        — write/fix/debug/refactor code, scripts, configs\n"
    "  math          — calculation, numeric/statistical reasoning, proofs\n"
    "  research      — gather/compare information from many sources, investigate\n"
    "  analysis      — reason about / explain / evaluate something in depth\n"
    "  reporting     — produce a document, summary, report, slides\n"
    "  creative      — prose, stories, names, marketing, brainstorming\n"
    "  orchestration — multi-step plan, coordinate sub-tasks, delegate\n"
    "  agentic       — search/fetch/automate via tools, multi-step tool use\n"
    "  fast          — quick lookup, format, translate, one-line answer\n\n"
    "TOOLS — list EVERY tool the task plausibly needs (not just one). Decide per\n"
    "tool by the WHEN rule; when unsure whether a tool helps, INCLUDE it (a tool\n"
    "left out is unavailable, a spare tool is harmless). Use these exact words:\n"
    "  memory      — WHEN the answer depends on knowledge the assistant already\n"
    "                holds: stored notes, project documents, ingested/attached\n"
    "                files, policies, standards, guidelines, internal rules, or\n"
    "                anything discussed earlier. ANY 'what does X say / what is our\n"
    "                policy on Y / look it up in the docs' question needs memory.\n"
    "                This is the DEFAULT retrieval tool — prefer it over web for\n"
    "                internal/document/policy questions.\n"
    "  files       — WHEN the task names or attaches a specific file to read,\n"
    "                write, edit, or convert (a document, spreadsheet, PDF, etc.).\n"
    "  web         — ONLY WHEN the task needs CURRENT or EXTERNAL public info not\n"
    "                in the assistant's own documents (news, live data, a public\n"
    "                website). Do NOT pick web for internal-policy/document lookups.\n"
    "  python      — WHEN the task needs computation, data crunching, or code execution.\n"
    "  bash        — WHEN the task needs shell commands / system operations.\n"
    "  git         — WHEN the task involves git / GitHub / version history.\n"
    "  code_graph  — WHEN the task asks about a codebase's structure / symbols.\n"
    "  email       — WHEN the task reads or sends email.\n"
    "  delegation  — WHEN the task should spawn / coordinate background sub-tasks.\n"
    "  scheduler   — WHEN the task schedules something to run later.\n"
    "  translation — WHEN the task translates text or documents.\n"
    "  image_gen   — WHEN the task generates images.\n"
    "  audio       — WHEN the task transcribes audio.\n"
    "  skills      — WHEN the task asks to invoke a named skill.\n\n"
    "Examples:\n"
    '  "What minimum password length does our policy require?" → tools:["memory"]\n'
    '  "Summarize the attached contract.docx" → tools:["files","memory"]\n'
    '  "What is the latest EU AI Act news?" → tools:["web"]\n'
    '  "Refactor this function to be async" → tools:["files","code_graph"]\n\n'
    "Return ONLY the JSON object."
)


def _resolve_classifier_model() -> str:
    """Pick the model used for background classification calls.

    Reuse the chat-summary model when set (the "small background model" knob,
    Settings -> Server -> Zusammenfassungen) — one setting for all tiny
    background calls. Unset/disabled -> cheapest/local (the prior default).
    """
    try:
        _sc = _server_config()
        _csm = (_sc.get("chat_summary_model") or "").strip()
        # Must be a KNOWN model (missing -> {} -> reject) AND enabled.
        _mcfg = (_models_config or {}).get(_csm)
        if _csm and _mcfg and _mcfg.get("enabled", True):
            return _csm
    except Exception:
        pass
    return _resolve_auto_model_tiered(None)  # cheapest/local


def _purpose_from_task_types(task_types: list[str]) -> str | None:
    """Derive a legacy `_PURPOSE_TIER` purpose from the structured task_types.

    Maps the dominant (strongest-tier) task_type back onto one of the 5 legacy
    purposes so the existing tiered router + auto_route reason keep working
    unchanged. Returns None if nothing usable, so the caller can fail open.
    """
    valid = [t for t in (task_types or []) if t in _TASK_TYPE_TIER]
    if not valid:
        return None
    # Pick the task_type whose tier is strongest (reasoning beats default beats
    # fast); ties keep the model's ordering (most-important-first).
    dominant = max(valid, key=lambda t: _TIER_RANK[_TASK_TYPE_TIER[t]])
    # Collapse the richer task_types onto the 5 purposes the tier map keys on.
    # New types fold into the closest legacy purpose by their tier.
    if dominant in _LLM_CLASSIFY_PURPOSES:
        return dominant
    tier = _TASK_TYPE_TIER[dominant]
    return {"reasoning": "analysis", "fast": "fast"}.get(tier, "agentic")


def _tool_groups_from_tools(tools: list[str]) -> set[str]:
    """Map classifier tool labels -> real TOOL_GROUPS names (validated)."""
    groups: set[str] = set()
    for t in (tools or []):
        for g in _TASK_TOOL_GROUPS.get(t, ()):
            if g in TOOL_GROUPS:  # ignore a renamed/removed group
                groups.add(g)
    return groups


def classify_task_structured(message: str) -> dict | None:
    """Structured LLM task analysis — the engine behind `llm`/`hybrid` modes.

    Returns a dict {purpose, task_types[], tools[], tool_groups[], complexity,
    reasoning} or None on any failure. `purpose` is derived from task_types so
    it drops straight into the existing tiered router; `tool_groups` are real
    TOOL_GROUPS names for optional per-turn tool gating.

    Fail-open: any error, timeout, or unparseable reply returns None so the
    caller (`resolve_task_purpose`) can fall back to the keyword classifier.
    The turn never blocks on classification.
    """
    if not message:
        return None
    try:
        import json as _json
        import handlers.sidecar_proxy as sidecar_proxy
        classifier_model = _resolve_classifier_model()
        if not classifier_model:
            return None
        # Force the routing JSON through a single constrained tool call so the
        # model can't emit malformed JSON. Weaker LOCAL models (verified: Qwen
        # on vllm-metal) dropped the opening brace ~20% of the time on free-text
        # JSON → fail-open to keywords; forced tool-use makes the output
        # schema-valid 15/15. The tool is never dispatched — the sidecar returns
        # its `input` as `forced_tool_input`. Schema enums track the valid
        # task_types / tools so the parser's filter stays in sync.
        _route_tool = {
            "name": "route",
            "description": "Emit the routing analysis for this task.",
            "input_schema": {
                "type": "object",
                "properties": {
                    "task_types": {
                        "type": "array",
                        "items": {"type": "string", "enum": sorted(_TASK_TYPE_TIER.keys())},
                        "minItems": 1, "maxItems": 3,
                    },
                    "tools": {
                        "type": "array",
                        "items": {"type": "string", "enum": sorted(_TASK_TOOL_GROUPS.keys())},
                    },
                    "complexity": {"type": "string", "enum": ["low", "medium", "high"]},
                    "reasoning": {"type": "string"},
                },
                "required": ["task_types", "tools", "complexity"],
            },
        }
        _res = sidecar_proxy.background_call(
            messages=[{"role": "user", "content": message[:4000]}],
            model=classifier_model,
            system_prompt=_STRUCTURED_CLASSIFY_SYSTEM,
            cost_purpose="auto_route_classify",
            max_tokens=200,
            max_rounds=1,
            timeout_s=25.0,
            forced_tool=_route_tool,
        )
        if _res.get("error"):
            return None
        # Forced-tool path: the structured input IS the result (no parsing).
        obj = _res.get("forced_tool_input")
        if not isinstance(obj, dict):
            # Fallback: a provider that ignored tool_choice returned free text —
            # recover the JSON span the old way so non-forcing models still work.
            raw = (_res.get("reply") or "").strip()
            start, end = raw.find("{"), raw.rfind("}")
            if start == -1 or end == -1 or end <= start:
                return None
            try:
                obj = _json.loads(raw[start:end + 1])
            except Exception:
                return None
        if not isinstance(obj, dict):
            return None
        task_types = [t for t in obj.get("task_types", []) if t in _TASK_TYPE_TIER]
        tools = [t for t in obj.get("tools", []) if t in _TASK_TOOL_GROUPS]
        purpose = _purpose_from_task_types(task_types)
        if not purpose:
            return None  # nothing actionable -> fail open to keywords
        complexity = obj.get("complexity")
        if complexity not in ("low", "medium", "high"):
            complexity = "medium"
        return {
            "purpose": purpose,
            "task_types": task_types,
            "tools": tools,
            "tool_groups": sorted(_tool_groups_from_tools(tools)),
            "complexity": complexity,
            "reasoning": str(obj.get("reasoning") or "")[:200],
        }
    except Exception:
        return None


def classify_task_purpose_llm(message: str) -> str | None:
    """LLM-based intent classifier — returns one of `_LLM_CLASSIFY_PURPOSES`
    or None. Now backed by the structured analyzer (`classify_task_structured`),
    keeping the legacy single-string contract for callers that only route a
    model and don't consume the richer fields.

    Fail-open: any error / timeout / unparseable reply returns None so the
    caller (`resolve_task_purpose`) can fall back to the keyword classifier.
    """
    res = classify_task_structured(message)
    return res.get("purpose") if res else None


# Tool groups never stripped by classifier-driven gating.
#
# History: this was {"core", "workflows"} — the WHOLE groups. But `core` is a junk
# drawer mixing two unrelated things: (a) the structural essentials a turn can't
# route without — `tool_search` (reach deferred tools) + `ask_user` (clarify) — and
# (b) an agentic file/shell cluster (execute_command/write_file/edit_file/
# search_files/list_directory/read_file) that is pure NOISE on a retrieval/Q&A turn.
# Forcing all 8 core + 2 workflow tools in-prompt handed mistral-small ~18 tools for
# a one-tool policy lookup — a CORRECTNESS problem (a weak model shouldn't be offered
# execute_command/write_file on a pure lookup). NOTE on eval: a single trimmed run hit
# 0.84 vs 0.80, but a 3-rep follow-up (0.76/0.85/0.77 = 0.79 ±0.04) showed that was
# within mistral-small variance — the change is eval-NEUTRAL on mean, kept on principle,
# does not regress. So the floor is now the minimal STRUCTURAL set, by tool NAME;
# everything else (incl. the file/shell cluster) is classifier-gated like any group —
# still tool_search-discoverable if a turn unexpectedly needs it, so nothing dead-ends.
_TOOL_GATING_NEVER_STRIP: set[str] = set()  # no whole-group floor anymore
_TOOL_GATING_NEVER_STRIP_TOOLS = {"tool_search", "ask_user"}


def model_maintains_warm_prefix(model: str) -> bool:
    """True iff the model keeps a warm KV prefix we must not disturb.

    Classifier-driven tool gating varies the per-turn tool list, which changes
    the KV prefix. That's free for cloud models that never warm up, but it
    invalidates the prefix for local / warmup-enabled models (the user's
    explicit constraint: gate tools only for models that do not warm up). A
    model maintains a prefix when it's local OR has warmup explicitly enabled.
    """
    if not model or model == "auto":
        return True  # unknown -> conservative: don't gate
    try:
        if is_model_local(model):
            return True
        cfg = (_models_config or {}).get(model) or {}
        return bool(cfg.get("warmup"))
    except Exception:
        return True


def model_should_optimize_tools(model: str) -> bool:
    """True iff per-turn classifier tool optimization is SAFE for this model.

    The gate that decides whether the per-turn tool list may be reshaped. Tools
    are part of the warm KV prefix (the tool schemas serialize into the prompt
    before the first message), so varying them per turn invalidates a warm
    prefix → full prefill. We therefore optimize ONLY when there is no warm
    prefix to protect:

      - Cloud model            → optimize (no reusable prefix; varying is free).
      - Local, warmup DISABLED  → optimize (it is never warmed, so nothing to
                                  lose — this is the case the old gate wrongly
                                  skipped: `model_maintains_warm_prefix` treated
                                  ALL local models as protected).
      - warmup ENABLED, mode="full" → do NOT optimize. Keyed on CONFIG, not the
                                  transient warm state: a full-mode warmup model
                                  is *meant* to be warm, and the keeper primes it
                                  with the full (static) tool set; optimizing it
                                  during a cold window would prime a TRIMMED
                                  prefix that the next (warm) turn's static set
                                  diverges from → thrash. Treat it as protected
                                  whether warm or momentarily cold.
      - warmup ENABLED, mode="minimal" → optimize. A minimal-mode prime sends
                                  NO system prompt and NO tools (just a 1-token
                                  user msg) — it keeps the weights hot but primes
                                  no tool-bearing KV prefix. There is therefore
                                  nothing for per-turn reshaping to invalidate,
                                  and the full-mode thrash argument above does not
                                  apply (no primed prefix to diverge from). This
                                  is the case that gives a warm minimal model BOTH
                                  fast weights AND a lean classifier-trimmed
                                  prompt. `warmup_mode` is resolved exactly as the
                                  keeper does (server_daemons `_warmup_keeper_loop`),
                                  so gate + keeper stay in lockstep.

    This is intentionally the near-inverse of `model_maintains_warm_prefix`,
    differing for warmup-DISABLED local models AND minimal-mode warmup models
    (protect=True there, but optimize=True here). Kept as a separate,
    tool-opt-specific predicate so the warmup-protection semantics elsewhere
    stay untouched.
    """
    if not model or model == "auto":
        return False  # unknown -> conservative: don't reshape
    try:
        cfg = (_models_config or {}).get(model) or {}
        if cfg.get("warmup"):
            # Only a FULL-mode prime builds a tool-bearing KV prefix to protect.
            # A minimal-mode prime is weights-only → safe to reshape per turn.
            mode = (cfg.get("warmup_mode") or "full").lower()
            return mode == "minimal"
        # No warmup: cloud OR a local model that never warms → safe to optimize.
        return True
    except Exception:
        return False


def agent_optimize_tools_enabled(agent_config: dict | None) -> bool:
    """Per-agent toggle for classifier-driven per-turn tool optimization.

    Reads `token_config.optimize_tools` (default True — preserves the prior
    always-on-for-non-warm behavior). When False, the classifier never reshapes
    the turn's tool set (static deferral stands) regardless of model; model
    SELECTION (auto-routing) is unaffected — the two axes are independent.
    """
    try:
        tc = (agent_config or {}).get("token_config") or {}
        return tc.get("optimize_tools", True) is not False
    except Exception:
        return True


def classifier_tool_deferral(model: str, tool_groups: list[str] | None) -> tuple[list[str], list[str]]:
    """Per-turn tool DEFERRAL adjustment from the classifier's needed groups.

    Returns `(defer_extra, undefer)` — two lists of built-in tool NAMES the
    resolver folds into its defer computation for this turn:
      - `defer_extra`: tools whose group the classifier did NOT flag as needed
        (and which aren't in the never-strip floor) → pushed OUT of the initial
        prompt. Unlike the old exclude path these stay `tool_search`-discoverable,
        so a misclassification is recoverable mid-turn.
      - `undefer`: tools whose group the classifier DID flag as needed →
        forced INTO the prompt even if they're normally deferred (the classifier
        has positive evidence the task needs them, so don't make the model hunt).

    Gated by `model_should_optimize_tools`: a warmup-ENABLED model (local or
    cloud) keeps its static KV prefix untouched (varying the tool list
    invalidates it). A warmup-DISABLED local model is never warmed, so it IS
    reshaped now (the old `model_maintains_warm_prefix` gate wrongly skipped
    it). Empty/empty when there's no signal (`tool_groups is None`) or the model
    is warmup-protected, so the caller leaves deferral as-is. NOTE: an EMPTY LIST
    (`[]`) is NOT "no signal" — it means the classifier ran and found no needed
    groups (e.g. a greeting), so everything outside the structural floor is
    deferred (the 11k-"hi" fix). Only `None` is no-signal.
    """
    if tool_groups is None:
        return [], []
    if not model_should_optimize_tools(model):
        return [], []  # preserve KV prefix — never reshape a warmup-protected model
    keep = set(tool_groups) | _TOOL_GATING_NEVER_STRIP
    defer_extra: list[str] = []
    undefer: list[str] = []
    for gname, gtools in TOOL_GROUPS.items():
        if gname in keep:
            # A needed group: pull its tools in even if normally deferred.
            undefer.extend(gtools)
        else:
            # Not needed → defer the group's tools OUT, EXCEPT the structural-floor
            # tool names (tool_search/ask_user), which must always stay in-prompt so
            # the turn can reach deferred tools + clarify. Defer everything else —
            # including the file/shell cluster that used to ride in via the `core`
            # floor and bloated the prompt.
            defer_extra.extend(t for t in gtools
                               if t not in _TOOL_GATING_NEVER_STRIP_TOOLS)
    # Floor tool names are never deferred and never need explicit undeferring
    # (they're already in-prompt); make sure nothing pushed them out.
    _floor = _TOOL_GATING_NEVER_STRIP_TOOLS
    defer_extra = [t for t in defer_extra if t not in _floor]
    return defer_extra, undefer


def classifier_gating_decision(model: str, tool_groups: list[str] | None) -> dict:
    """Human-readable summary of the classifier tool-DEFERRAL decision for the
    per-turn classification modal. Mirrors `classifier_tool_deferral` so the
    reported decision always matches what was actually applied.

    Returns {applied, reason, kept_groups, excluded_groups, needed_groups}.
    The keys are kept stable for the existing modal: `kept_groups` = groups
    pulled in-prompt (needed + floor), `excluded_groups` = groups DEFERRED out
    (still tool_search-discoverable — not removed). `applied=False` means the
    static deferral config stood (warmup-protected model, or no signal).
    """
    needed = sorted(set(tool_groups or []))
    # None = no signal (leave static). [] = classifier ran, no groups needed →
    # trim to floor (mirror classifier_tool_deferral's None-vs-empty split).
    if tool_groups is None:
        return {"applied": False, "reason": "no classification signal (keyword mode miss or fail-open)",
                "kept_groups": [], "excluded_groups": [], "needed_groups": needed}
    if not model_should_optimize_tools(model):
        why = ("local model, warmup enabled" if is_model_local(model) else "warmup enabled")
        return {"applied": False,
                "reason": f"model keeps a warm KV prefix ({why}) — deferral left static to preserve it",
                "kept_groups": sorted(TOOL_GROUPS.keys()),
                "excluded_groups": [], "needed_groups": needed}
    keep = set(tool_groups) | _TOOL_GATING_NEVER_STRIP
    kept = sorted(g for g in TOOL_GROUPS if g in keep)
    deferred = sorted(g for g in TOOL_GROUPS if g not in keep)
    floor = sorted(_TOOL_GATING_NEVER_STRIP_TOOLS)
    return {"applied": True,
            "reason": f"non-warmup model — needed groups un-deferred + minimal floor ({', '.join(floor)}) in-prompt; rest deferred (still tool_search-discoverable)",
            "kept_groups": kept, "excluded_groups": deferred, "needed_groups": needed}


# Tools whose presence in the turn's EFFECTIVE active set means the answer will
# be grounded on retrieved content (memory drawers, web, file/document reads) —
# so it must carry the citation discipline + run the validator. The trigger is
# the RESOLVED active tools (resolve_active_tools), NOT the classifier's intent:
# the classifier only REDUCES tools (deferral), so keying off its guess could
# wrongly suppress the discipline on a turn that does retrieve. What's actually
# live is the correct signal.
_RETRIEVAL_TOOLS = frozenset({
    "mempalace_query",      # memory
    "searxng_search", "exa_search",  # web search
    "web_fetch",            # web fetch
    "read_document",        # doc read
    "read_file",            # file read
})


def turn_has_retrieval_tools(active_tool_names) -> bool:
    """True iff the turn's EFFECTIVE active tool set includes a retrieval tool —
    i.e. the answer can ground on sources, so it should carry the citation
    discipline + run the validator. Takes the resolved active tool NAMES (a set/
    list from build_first_turn_prefix), not the classifier analysis."""
    return bool(set(active_tool_names or []) & _RETRIEVAL_TOOLS)


def classifier_is_llm() -> bool:
    """True when the auto-route classifier runs in LLM-driven mode ('llm' or
    'hybrid'). In that mode the DYNAMIC effective-tools citation discipline is
    active and the per-project research_mode toggle is disabled (redundant). In
    'keywords' mode (default) the dynamic trigger is OFF and the project flag is
    the only control."""
    try:
        mode = ((_server_config().get("auto_route") or {}).get("classifier_mode") or "keywords").strip()
    except Exception:
        mode = "keywords"
    return mode in ("llm", "hybrid")


def resolve_task_analysis(message: str) -> dict | None:
    """Dispatch task classification per `auto_route.classifier_mode`, returning
    the FULL structured analysis when the LLM path runs.

    Modes (config.json → auto_route.classifier_mode, default "keywords"):
      - keywords: keyword heuristics only (zero cost/latency; the prior behavior).
                  Returns {purpose, source:"keywords"} (no task_types/tools).
      - llm:      structured LLM analysis, falling back to keywords on failure.
      - hybrid:   keywords first; structured LLM only when keywords find no
                  strong signal (pays the LLM tax rarely).

    Both `llm` and `hybrid` fail-open to the keyword classifier, so a down
    sidecar or slow local model never breaks auto-routing. Always returns a
    dict with at least `purpose` (possibly None), or None if no signal at all.
    """
    mode = "keywords"
    try:
        _sc = _server_config()
        mode = ((_sc.get("auto_route") or {}).get("classifier_mode") or "keywords").strip()
    except Exception:
        pass

    def _kw():
        p = classify_task_purpose(message)
        return {"purpose": p, "source": "keywords"} if p else None

    if mode == "llm":
        rich = classify_task_structured(message)
        if rich:
            rich["source"] = "llm"
            return rich
        return _kw()
    if mode == "hybrid":
        kw = _kw()
        if kw:
            return kw
        rich = classify_task_structured(message)
        if rich:
            rich["source"] = "llm"
            return rich
        return None
    # "keywords" or any unknown value → safe default
    return _kw()


def resolve_task_purpose(message: str) -> str | None:
    """Back-compat shim: dispatch classification and return only the purpose
    string (the legacy single-value contract — fan-out, etc.)."""
    res = resolve_task_analysis(message)
    return res.get("purpose") if res else None


# Map a classified task purpose to a routing tier. The tier is resolved
# against fields every model actually has (thinking_format, is_local,
# priority) — unlike the legacy `purpose in capabilities` filter, which
# never matched because no model declares coding/analysis/etc. as a
# capability (capabilities vocabulary is chat/image/audio/tts only).
_PURPOSE_TIER: dict[str, str] = {
    "fast": "fast",          # quick/format/translate → cheapest, prefer local
    "coding": "reasoning",   # needs strong reasoning model
    "analysis": "reasoning",
    "creative": "default",
    "agentic": "default",
}


# Tier escalation order — `complexity` shifts the task-type's baseline tier
# up (high) or down (low) along this ladder. medium leaves it unchanged.
_TIER_LADDER = ["fast", "default", "reasoning"]

# Minimum measured capability% a model must clear for a task type to be a
# benchmark-eligible candidate. Below this it's treated as "not capable" and
# only used as a last-resort fallback. Capability is the hard floor; speed then
# cost rank the survivors (the user's stated order).
_BENCH_CAPABILITY_FLOOR = 50


def bench_cell_value(model: str, task_type: str) -> dict | None:
    """Return the effective benchmark cell for (model, task_type): the admin
    `override` if present, else the `measured` block, else None (never run).

    Shape: {capability: 0-100, latency_ms: int, ...}. Override is sticky — a
    later benchmark run only rewrites `measured`, so an admin edit survives.
    """
    cell = (((_models_config.get(model) or {}).get("benchmark") or {}).get(task_type) or {})
    if not cell:
        return None
    ov = cell.get("override")
    if isinstance(ov, dict) and ov.get("capability") is not None:
        return ov
    meas = cell.get("measured")
    if isinstance(meas, dict) and meas.get("capability") is not None:
        return meas
    return None


def model_family(model: str) -> str:
    """Coarse family key for fallback-walk grouping (e.g. 'mistral', 'gemma',
    'qwen', 'claude'). Derived from the base/shortname/id token blob — a
    best-effort prefix, NOT a hard taxonomy. Empty string when unguessable."""
    cfg = _models_config.get(model) or {}
    blob = " ".join(((cfg.get("base_model_id") or ""),
                     (cfg.get("shortname") or ""), (model or ""))).lower()
    for fam in ("mistral", "magistral", "devstral", "voxtral", "gemma", "qwen",
                "llama", "claude", "gpt", "deepseek", "gemini", "phi", "command"):
        if fam in blob:
            # Collapse the mistral sub-brands so they count as one family.
            return "mistral" if fam in ("magistral", "devstral", "voxtral") else fam
    return ""


def _complexity_floor(complexity: str | None) -> int:
    """Capability floor adjusted for task complexity: 'high' demands a stronger
    model (raise the bar), 'low' tolerates a weaker/cheaper one (lower it),
    medium/unknown = the base floor. Clamped to [0, 100]."""
    base = _BENCH_CAPABILITY_FLOOR
    if complexity == "high":
        base += 20
    elif complexity == "low":
        base -= 20
    return max(0, min(100, base))


# Relative width of a speed band. Two models whose tps differ by less than this
# fraction of the faster one are treated as equally fast (the difference is
# benchmark noise, not a real speed advantage) and the ranking falls through to
# cost. 0.15 = "must be ≥15 % faster to win on speed alone". Tuned so cloud
# Mistral Small (cheap) beats Medium on a capability-tied fast task instead of
# losing by 0.3 tok/s, while a genuinely 2–3× faster model still wins on speed.
_TPS_BUCKET_REL = 0.15


def _tps_bucket(tps: float) -> int:
    """Snap a throughput (tok/s) onto a coarse logarithmic band index so that
    only a >~15 % speed difference changes the band. Within a band, models tie
    on speed and the ranking falls through to cost. Higher band = faster.

    Log-spaced because speed spans orders of magnitude across the fleet (≈9 tok/s
    local up to ≈190 tok/s cloud) — a fixed linear bucket would merge fast models
    and over-split slow ones. With rel-width 0.15 each band is ~15 % wider than
    the last, so 11.2 and 11.5 land in the SAME band (tie → cost decides) while
    11.2 vs 14 (>15 %) land in different bands (faster wins)."""
    if tps <= 0:
        return 0
    return int(math.log(tps) / math.log(1.0 + _TPS_BUCKET_REL))


def _bench_rank_key(model: str, task_type: str, floor: int,
                    complexity: str | None) -> tuple:
    """Sort key for the CAPABLE-ENOUGH → cloud → fast → cheap ordering, best first.

    Capability is a FLOOR, not a maximand: a model is either capable enough
    (>= floor) or not. We deliberately do NOT rank by raw capability — that
    would always crown the single highest-scoring model (e.g. mistral-medium)
    and never let a cheaper/faster but still-capable model win. `complexity`
    only MOVES the floor (high raises it so fewer models qualify, low lowers
    it), via `_complexity_floor`.

    Among the capable set CLOUD sorts ahead of LOCAL — the same "never prefer
    cloud→local" rule `_fallback_walk` enforces, applied here at the PRIMARY
    pick (a free/fast local model must not outrank a capable cloud model on a
    near-tied, and least-trustworthy, benchmark). Within one locality class the
    order is the user's stated priority: speed (THROUGHPUT tok/s, negated so
    highest tps wins), then cost, then static priority."""
    cell = bench_cell_value(model, task_type) or {}
    cap = cell.get("capability")
    cap = cap if isinstance(cap, (int, float)) else 0
    has_cap = cap >= floor
    local = 1 if is_model_local(model) else 0  # cloud (0) before local (1)
    tps = cell.get("tps")
    tps = tps if isinstance(tps, (int, float)) and tps > 0 else 0.0
    cost = _model_total_cost(model)
    prio = -(_models_config.get(model, {}).get("priority") or 0)
    # Speed is BUCKETED before it ranks: a raw tps compare let a noise-sized
    # delta (e.g. 11.5 vs 11.2 tok/s — within run-to-run variance, n=2) decide
    # the pick and PREEMPT the much larger cost axis, so a 20×-pricier model won
    # a "fast" task by 0.3 tok/s. `_tps_bucket` snaps tps to a coarse band so
    # only a MEANINGFULLY faster model wins on speed; models within one band tie
    # here and fall through to cost (then static priority). Order is the user's
    # stated policy: capable-enough → cloud → fast(bucketed) → cheap → priority.
    return (0 if has_cap else 1, local, -_tps_bucket(tps), cost, prio)


def _pick_by_benchmark(candidates: list[str], task_type: str | None,
                       complexity: str | None = None) -> str | None:
    """Among candidates with a benchmark for this task type, return the best by
    capable→fast→cheap (complexity-adjusted floor). None when no candidate has
    been benchmarked for the task (caller then falls back to the tier heuristic)."""
    if not task_type:
        return None
    scored = [m for m in candidates if bench_cell_value(m, task_type) is not None]
    if not scored:
        return None
    floor = _complexity_floor(complexity)
    scored.sort(key=lambda m: _bench_rank_key(m, task_type, floor, complexity))
    return scored[0]


def _fallback_walk(picked: str, candidates: list[str], task_type: str | None) -> str:
    """When `picked` is not in the allowed candidate pool, walk to the nearest
    replacement per the user's rule: prefer SAME FAMILY (closest capability),
    then SAME LOCALITY (cloud→cloud / local→local), and NEVER cross cloud→local.
    Falls back to the configured default_model, then the first candidate."""
    if picked in candidates:
        return picked
    want_local = is_model_local(picked)
    want_fam = model_family(picked)
    picked_cap = (bench_cell_value(picked, task_type) or {}).get("capability") if task_type else None

    def _cap(m):
        return (bench_cell_value(m, task_type) or {}).get("capability") if task_type else None

    # Locality-safe pool: never go cloud→local. If the lost pick was cloud,
    # only cloud replacements qualify; if it was local, only local.
    locality_ok = [m for m in candidates if is_model_local(m) == want_local]
    pool = locality_ok or candidates  # if locality empties the pool, relax (still no cloud->local below)
    # Never cloud→local: if picked was cloud, drop any local from the pool.
    if not want_local:
        pool = [m for m in pool if not is_model_local(m)] or pool

    # 1) Same family, nearest capability to the lost pick.
    fam_pool = [m for m in pool if want_fam and model_family(m) == want_fam]
    target_cap = picked_cap if picked_cap is not None else 100

    def _nearest(ms):
        return min(ms, key=lambda m: (abs((_cap(m) if _cap(m) is not None else 0) - target_cap),
                                      _model_total_cost(m)))
    if fam_pool:
        return _nearest(fam_pool)
    # 2) Same locality (already enforced in `pool`), nearest capability.
    if pool:
        return _nearest(pool)
    # 3) Configured default, else first candidate.
    try:
        dm = (_server_config().get("default_model") or "")
        if dm in candidates:
            return dm
    except Exception:
        pass
    return candidates[0] if candidates else picked


def _model_total_cost(mid: str) -> float:
    """Per-1M input+output cost for ranking 'cheapest' (unpriced -> +inf so a
    model with no rates never wins a cheapest-pick by accident)."""
    cfg = _models_config.get(mid, {}) or {}
    ci, co = cfg.get("cost_input"), cfg.get("cost_output")
    if ci is None and co is None:
        return float("inf")
    return float(ci or 0) + float(co or 0)


def _pick_cheapest_cloud(candidates: list[str]) -> str:
    """The 'simpler' pick: cheapest enabled CLOUD model, local only as last
    resort (honors the 'stick to cloud' policy). Falls back to the first
    candidate if neither cloud nor local resolves cleanly."""
    cloud = [m for m in candidates if not is_model_local(m)]
    if cloud:
        return min(cloud, key=lambda m: (_model_total_cost(m),
                                         -(_models_config.get(m, {}).get("priority") or 0)))
    local = [m for m in candidates if is_model_local(m)]
    if local:
        return min(local, key=lambda m: (_model_total_cost(m),
                                         -(_models_config.get(m, {}).get("priority") or 0)))
    return candidates[0]


def _shift_tier(tier: str, complexity: str | None) -> str:
    """Bump the baseline tier up (high) or down (low) the ladder per complexity.
    medium / unknown leaves it unchanged."""
    if complexity not in ("low", "high"):
        return tier
    try:
        i = _TIER_LADDER.index(tier)
    except ValueError:
        return tier
    if complexity == "high":
        i = min(i + 1, len(_TIER_LADDER) - 1)
    else:  # low
        i = max(i - 1, 0)
    return _TIER_LADDER[i]


def _resolve_auto_model_tiered(purpose: str | None,
                               *, attachment_mimes: list[str] | None = None,
                               allowed_models: set[str] | None = None,
                               complexity: str | None = None,
                               task_types: list[str] | None = None,
                               pool: str | None = None) -> str:
    """Pick the best enabled model for a task.

    Precedence (highest first):
      1. Attachments — restrict to models whose `raw_formats` match, but ONLY
         for raw image/* uploads (the sole MIME the chat router sends raw;
         everything else is converted to markdown and readable by any text
         model, so it doesn't constrain the pool). Falls back to the full set
         when no enabled model matches.
      2. Benchmark ranking — when a candidate has measured data for the task
         type, rank capable→fast→cheap (capability floor nudged by complexity).
      3. Tier — the purpose's baseline tier (`_PURPOSE_TIER`), then SHIFTED by
         `complexity` along `_TIER_LADDER` (high→up, low→down, medium→same):
           - "reasoning" → first model with thinking_format != "none"
           - "default"   → highest-priority model (the cloud `default_model`)
           - "fast"      → cheapest CLOUD model, local last (`_pick_cheapest_cloud`)
      4. Always returns a concrete model id (top-priority fallback) — never "".

    `allowed_models`, when set, restricts the candidate pool to models the
    caller may use (ACL). Empty intersection falls back to the full enabled
    set so an unrestricted/admin caller is never starved.

    `pool` ("cloud" | "local" | None) constrains the candidate set to cloud-only
    or local-only models — this is the sole difference between the composer's
    "Smart (Cloud)" and "Smart (Lokal)" auto modes (the classification + tiering
    are identical; only the pool changes). Empty intersection falls back to the
    full set (same never-starve rule as the ACL filter), so a box with no local
    model still routes rather than failing.
    """
    enabled = get_enabled_models()  # priority-desc
    if allowed_models:
        scoped = [m for m in enabled if m in allowed_models]
        if scoped:
            enabled = scoped
    if pool in ("cloud", "local"):
        want_local = (pool == "local")
        scoped = [m for m in enabled if is_model_local(m) == want_local]
        if scoped:
            enabled = scoped
    if not enabled:
        return ""

    candidates = enabled
    # Only attachments that are sent to the model RAW constrain the pool by
    # capability. Everything Brain converts to markdown first (PDF/docx/xlsx/…
    # → read_document) is readable by any text model, so it must NOT narrow the
    # candidates. The raw path is image/* only: the chat attachment router
    # (handlers/chat.py) sends a multimodal block solely when
    # `mime.startswith("image/")` (its `api_blocked` predicate) — every other
    # MIME, even one a model lists in `raw_formats`, is routed to disk and
    # converted. Mirror that predicate here so router and dispatcher agree.
    # (Audio/video go through the separate translation/transcription path, not
    # this MIME router, so they don't appear here either.)
    mimes = [m for m in (attachment_mimes or []) if m and m.startswith("image/")]
    if mimes:
        vision = [mid for mid in enabled
                  if any(_mime_matches(m, get_model_raw_formats(mid)) for m in mimes)]
        if vision:
            candidates = vision  # raw-image capability wins

    # Benchmark ranking (the measured path): if any candidate has been
    # benchmarked for the task, rank capable→fast→cheap and take the best. The
    # capability floor folds in the tier intent (a reasoning task simply scores
    # higher on capable models), so we rank over the WHOLE candidate pool, not
    # a tier-filtered slice. Complexity nudges the floor: a 'high'-complexity
    # task demands a stronger model, 'low' tolerates a weaker/cheaper one.
    bench_task = (task_types or [None])[0] if task_types else None
    if bench_task is None and purpose:
        # keyword mode has no task_types — fall back to the legacy heuristic
        # below (no benchmark lookup without a concrete task type).
        bench_task = None
    if bench_task:
        picked = _pick_by_benchmark(candidates, bench_task, complexity)
        if picked:
            # `picked` is already in `candidates`; the fallback walk is a no-op
            # here but documents the locality/family rule for when the pool
            # later excludes it (ACL/disable between benchmark and use).
            return _fallback_walk(picked, candidates, bench_task)

    # No benchmark data for this task → tier heuristic (the pre-benchmark
    # behavior): purpose's baseline tier, shifted by complexity.
    tier = _shift_tier(_PURPOSE_TIER.get(purpose or "", "default"), complexity)

    if tier == "reasoning":
        for mid in candidates:
            if _models_config.get(mid, {}).get("thinking_format", "none") != "none":
                return mid
    elif tier == "fast":
        return _pick_cheapest_cloud(candidates)

    # default tier, or no tier-specific match found
    return candidates[0]


def resolve_auto_model_for_task(agent_config: dict, message: str,
                                attachment_mimes: list[str] | None = None,
                                allowed_models: set[str] | None = None,
                                pool: str | None = None
                                ) -> tuple[str, str | None, dict | None]:
    """For agents with model="auto", analyze the task and pick the best model.

    Returns (resolved_model_id, detected_purpose, analysis). `analysis` is the
    full structured dict (task_types/tools/tool_groups/complexity/reasoning)
    when the LLM classifier ran, else None — callers that want richer routing
    (e.g. per-turn tool gating) read it; legacy callers ignore it.
    If agent has a fixed model_purpose, uses that instead of classifying.
    `attachment_mimes` (when the turn carries files) constrains the pick to a
    model that can natively handle those MIME types.
    `allowed_models` (when set) restricts the pick to the caller's ACL set.
    `pool` ("cloud" | "local" | None) constrains the pick to cloud- or local-only
    models — the "Smart (Cloud)" vs "Smart (Lokal)" composer modes.
    """
    raw_model = agent_config.get("model", "")
    if raw_model != "auto":
        return resolve_model(raw_model, agent_config.get("model_purpose")), agent_config.get("model_purpose"), None

    fixed_purpose = agent_config.get("model_purpose")
    if fixed_purpose:
        return (_resolve_auto_model_tiered(fixed_purpose, attachment_mimes=attachment_mimes,
                                           allowed_models=allowed_models, pool=pool), fixed_purpose, None)

    # Classify task from message (keyword / LLM / hybrid per config).
    analysis = resolve_task_analysis(message)
    detected = analysis.get("purpose") if analysis else None
    # complexity + task_types only exist on the structured (LLM) path; keyword
    # mode passes None/[] → tier logic is unchanged there.
    resolved = _resolve_auto_model_tiered(
        detected, attachment_mimes=attachment_mimes, allowed_models=allowed_models,
        complexity=(analysis or {}).get("complexity"),
        task_types=(analysis or {}).get("task_types"), pool=pool)
    # Only hand back analysis with actionable richer fields (LLM source).
    rich = analysis if (analysis and analysis.get("source") == "llm") else None
    return resolved, detected, rich


def get_model_info(model: str) -> dict:
    """Return config entry for a model, or empty dict if not configured."""
    return _models_config.get(model, {})


def get_api_model_id(model: str) -> str:
    """Return the actual model ID to send to the API.

    For provider-scoped models (e.g. 'mistral/devstral-small-latest'),
    returns the base model ID ('devstral-small-latest').
    """
    cfg = _models_config.get(model, {})
    return cfg.get("base_model_id", model)


def get_model_max_context(model: str) -> int:
    """Return the model's context window size, or DEFAULT_MAX_CONTEXT_TOKENS."""
    return _models_config.get(model, {}).get("max_context", DEFAULT_MAX_CONTEXT_TOKENS)


# Default max output tokens per model family
_MAX_OUTPUT_DEFAULTS = {
    "opus": 32768,
    "sonnet": 16384,
    "haiku": 8192,
    "minimax": 32768,
    "m2.7": 32768,
    "m2.5": 32768,
}


def get_model_raw_formats(model: str) -> list[str]:
    """Return list of MIME patterns the model handles natively as multimodal.
    Checks models_config first, then falls back to KNOWN_MODELS family defaults."""
    cfg = _models_config.get(model, {})
    if "raw_formats" in cfg:
        return cfg["raw_formats"]
    # Fall back to KNOWN_MODELS family defaults
    ml = model.lower()
    for prefix, defaults in KNOWN_MODELS.items():
        if ml.startswith(prefix) or prefix in ml:
            return list(defaults.get("raw_formats", []))
    return []


def _mime_matches(mime_type: str, patterns: list[str]) -> bool:
    """Check if a MIME type matches any pattern (supports wildcard like 'image/*')."""
    for pat in patterns:
        if pat == mime_type:
            return True
        if pat.endswith("/*") and mime_type.startswith(pat[:-1]):
            return True
    return False


def get_model_max_output(model: str) -> int:
    """Return the model's max output tokens. Checks models_config first, then family defaults."""
    cfg = _models_config.get(model, {})
    if cfg.get("max_output"):
        return int(cfg["max_output"])
    ml = model.lower()
    for family, limit in _MAX_OUTPUT_DEFAULTS.items():
        if family in ml:
            return limit
    # Non-Anthropic models: use a generous default
    return 16384


def get_inference_params(model: str, purpose: str | None = None) -> dict:
    """Resolve inference parameters for a model, optionally overlaying a purpose preset.

    Returns only explicitly set keys (empty dict = use API defaults).
    """
    cfg = _models_config.get(model, {})
    base = dict(cfg.get("inference", {}))
    if purpose:
        preset = cfg.get("presets", {}).get(purpose, {})
        base.update(preset)
    return base


# Keys valid for all providers
_INFERENCE_STANDARD_KEYS = {"temperature", "top_p", "top_k", "max_tokens"}
# Keys only for OpenAI-compatible / oMLX
_INFERENCE_OPENAI_KEYS = {"frequency_penalty", "presence_penalty"}
# oMLX extension keys
_INFERENCE_OMLX_KEYS = {"min_p", "repetition_penalty"}


def _provider_supports_chat_template_kwargs(provider_name: str) -> bool:
    """Whether the upstream gateway accepts the oMLX/vLLM `chat_template_kwargs`
    extension (used to force `enable_thinking` on reasoning-capable chat
    templates like gemma-4 / qwen3).

    Source of truth is the per-provider `supports_chat_template_kwargs`
    boolean in config.json. The legacy provider id `omlx` is grandfathered to
    True so installs that haven't been migrated keep working.
    """
    if not provider_name:
        return False
    if provider_name.lower() == "omlx":
        return True
    try:
        cfg_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), "config.json")
        with open(cfg_path) as f:
            prov = json.load(f).get("providers", {}).get(provider_name, {})
        return bool(prov.get("supports_chat_template_kwargs", False))
    except Exception:
        return False


def _apply_inference_to_payload(payload: dict, params: dict, provider: str = "", scoped_model: str = "") -> None:
    """Apply resolved inference params to an OpenAI-compatible payload."""
    # Note: don't early-return when params is empty. We may still need to set
    # chat_template_kwargs.enable_thinking=false on oMLX thinking-capable models,
    # since their chat templates default thinking to ON when the kwarg is absent.
    params = params or {}

    # `chat_template_kwargs` is an oMLX/vLLM-style extension. The provider
    # opts in via `supports_chat_template_kwargs: true` in config.json so we
    # don't rely on provider name matching.
    is_omlx = _provider_supports_chat_template_kwargs(provider)

    for key in _INFERENCE_STANDARD_KEYS:
        if key in params:
            payload[key] = params[key]

    for key in _INFERENCE_OPENAI_KEYS:
        if key in params:
            payload[key] = params[key]

    for key in _INFERENCE_OMLX_KEYS:
        if key in params and is_omlx:
            payload[key] = params[key]

    # reasoning_effort is passed through verbatim for providers that support it
    if "reasoning_effort" in params:
        payload["reasoning_effort"] = params["reasoning_effort"]

    # Thinking routing: translate the UI's thinking_level string (low/medium/high)
    # into whatever the model's provider expects, based on the per-model thinking_format.
    _thinking_level = params.get("thinking_level")
    if _thinking_level and _thinking_level != "none":
        _scoped_id = scoped_model or payload.get("model", "")
        _fmt = _models_config.get(_scoped_id, {}).get("thinking_format", "none")
        if _fmt == "mistral_blocks":
            # Mistral accepts only "none" and "high" on reasoning_effort; any non-none
            # UI level maps to "high".
            payload["reasoning_effort"] = "high"
        elif _fmt in ("reasoning_field", "openai_opaque"):
            # OpenAI / Gemini via cliproxy / DeepSeek all accept low|medium|high.
            payload["reasoning_effort"] = _thinking_level

    # Legacy/oMLX chat template kwarg (kept for models that use it instead of reasoning_effort).
    # Qwen3 chat templates default enable_thinking=True when the kwarg is absent —
    # so we must send it EXPLICITLY in both directions, not only when turning on.
    # Otherwise the off toggle in the UI is silently ignored.
    if is_omlx:
        _scoped_id = scoped_model or payload.get("model", "")
        _fmt = _models_config.get(_scoped_id, {}).get("thinking_format", "none")
        if _fmt != "none":
            want_thinking = bool(params.get("thinking")) or (
                params.get("thinking_level") not in (None, "", "none")
            )
            payload.setdefault("chat_template_kwargs", {})["enable_thinking"] = want_thinking


def list_models(api_key: str, base_url: str) -> None:
    """List available models from the API."""
    models = get_available_models(api_key, base_url)
    if models:
        print("Available models:")
        for model_id in models:
            print(f"  {model_id}")
    else:
        print("No models available")


def _unescape(text: str) -> str:
    """Unescape literal backslash sequences that some APIs send."""
    return text.replace("\\n", "\n").replace("\\t", "\t").replace('\\"', '"')


def _collect_openai(response) -> str:
    """Parse OpenAI SSE stream silently. Returns full text."""
    collected = []
    for line in response:
        line = line.decode("utf-8").strip()
        if not line.startswith("data: "):
            continue
        payload = line[6:]
        if payload == "[DONE]":
            break
        try:
            event = json.loads(payload)
            choices = event.get("choices", [])
            if choices:
                delta = choices[0].get("delta", {})
                content = delta.get("content")
                if content:
                    collected.append(_unescape(content))
        except json.JSONDecodeError:
            pass
    return "".join(collected)


def _stream_openai(response) -> str:
    """Parse OpenAI SSE stream with live output. Returns full text."""
    collected = []
    for line in response:
        line = line.decode("utf-8").strip()
        if not line.startswith("data: "):
            continue
        payload = line[6:]
        if payload == "[DONE]":
            break
        try:
            event = json.loads(payload)
            choices = event.get("choices", [])
            if choices:
                delta = choices[0].get("delta", {})
                content = delta.get("content")
                if content:
                    content = _unescape(content)
                    print(content, end="", flush=True)
                    collected.append(content)
        except json.JSONDecodeError:
            pass
    return "".join(collected)


